		//IL_0227: Unknown result type (might be due to invalid IL or missing references)
		//IL_01c5: Unknown result type (might be due to invalid IL or missing references)
		//IL_01c6: Unknown result type (might be due to invalid IL or missing references)
		clampedPos = endPos;
		Stack<Node> stack = tmpStack;
		List<Node> list = tmpClosed;
		stack.Clear();
		list.Clear();
		float num = float.PositiveInfinity;
		Node result = null;
		Vector3 val = (startPos + endPos) / 2f;
		float num2 = Mathfx.MagnitudeXZ(startPos, endPos) / 2f;
		Vector3 val2 = startPos;
		stack.Push(startNode);
		list.Add(startNode);
		if (!(AstarData.GetGraph(startNode) is INavmesh navmesh))
		{
			return startNode;
		}
		while (stack.Count > 0)
		{
			Node node = stack.Pop();
			MeshNode meshNode = node as MeshNode;
			if (NavMeshGraph.ContainsPoint(meshNode, endPos, navmesh.vertices))
			{
				result = node;
				val2 = endPos;
				break;
			}
			int num3 = 0;
			int i = 2;
			while (num3 < 3)
			{
				int vertexIndex = meshNode.GetVertexIndex(i);
				int vertexIndex2 = meshNode.GetVertexIndex(num3);
				bool flag = true;
				MeshNode meshNode2 = null;
				for (int j = 0; j < node.connections.Length; j++)
				{
					meshNode2 = node.connections[j] as MeshNode;
					if (meshNode2 == null)
					{
						continue;
					}
					int num4 = 0;
					int i2 = 2;
					while (num4 < 3)
					{
						int vertexIndex3 = meshNode2.GetVertexIndex(i2);
						int vertexIndex4 = meshNode2.GetVertexIndex(num4);
						if ((vertexIndex3 == vertexIndex && vertexIndex4 == vertexIndex2) || (vertexIndex3 == vertexIndex2 && vertexIndex4 == vertexIndex))
						{
							flag = false;
							break;
						}
						i2 = num4++;
					}
					if (!flag)
					{
						break;
					}
				}
				if (flag)
				{
					Vector3 val3 = Mathfx.NearestPointStrictXZ((Vector3)navmesh.vertices[vertexIndex], (Vector3)navmesh.vertices[vertexIndex2], endPos);
					float num5 = Mathfx.MagnitudeXZ(val3, endPos);
					if (num5 < num)
					{
						val2 = val3;
						num = num5;
						result = node;
					}
				}
				else if (!list.Contains(meshNode2))
				{
					list.Add(meshNode2);
					Vector3 val3 = Mathfx.NearestPointStrictXZ((Vector3)navmesh.vertices[vertexIndex], (Vector3)navmesh.vertices[vertexIndex2], val);
					float num5 = Mathfx.MagnitudeXZ(val3, val);
					if (num5 <= num2)
					{
						stack.Push(meshNode2);
					}
				}
				i = num3++;
			}
		}
		clampedPos = val2;
		return result;
	}
}
[AddComponentMenu("Pathfinding/Seeker")]
public class Seeker : MonoBehaviour
{
	public enum ModifierPass
	{
		PreProcess,
		PostProcessOriginal,
		PostProcess
	}

	public bool drawGizmos = true;

	public bool detailedGizmos;

	[HideInInspector]
	public bool saveGetNearestHints = true;

	public StartEndModifier startEndModifier = new StartEndModifier();

	[HideInInspector]
	public TagMask traversableTags = new TagMask(-1, -1);

	[HideInInspector]
	public int[] tagPenalties = new int[32];

	public OnPathDelegate pathCallback;

	public OnPathDelegate preProcessPath;

	public OnPathDelegate postProcessOriginalPath;

	public OnPathDelegate postProcessPath;

	[NonSerialized]
	public List<Vector3> lastCompletedVectorPath;

	[NonSerialized]
	public List<Node> lastCompletedNodePath;

	[NonSerialized]
	protected Pathfinding.Path path;

	protected Pathfinding.Path prevPath;

	private Node startHint;

	private Node endHint;

	private OnPathDelegate onPathDelegate;

	private OnPathDelegate onPartialPathDelegate;

	private OnPathDelegate tmpPathCallback;

	protected uint lastPathID;

	private List<IPathModifier> modifiers = new List<IPathModifier>();

	public Pathfinding.Path GetCurrentPath()
	{
		return path;
	}

	public void Awake()
	{
		onPathDelegate = OnPathComplete;
		onPartialPathDelegate = OnPartialPathComplete;
		startEndModifier.Awake(this);
	}

	public void OnDestroy()
	{
		startEndModifier.OnDestroy(this);
	}

	public void RegisterModifier(IPathModifier mod)
	{
		if (modifiers == null)
		{
			modifiers = new List<IPathModifier>(1);
		}
		modifiers.Add(mod);
	}

	public void DeregisterModifier(IPathModifier mod)
	{
		if (modifiers != null)
		{
			modifiers.Remove(mod);
		}
	}

	public void PostProcess(Pathfinding.Path p)
	{
		RunModifiers(ModifierPass.PostProcess, p);
	}

	public void RunModifiers(ModifierPass pass, Pathfinding.Path p)
	{
		bool flag = true;
		while (flag)
		{
			flag = false;
			for (int i = 0; i < modifiers.Count - 1; i++)
			{
				if (modifiers[i].Priority < modifiers[i + 1].Priority)
				{
					IPathModifier value = modifiers[i];
					modifiers[i] = modifiers[i + 1];
					modifiers[i + 1] = value;
					flag = true;
				}
			}
		}
		switch (pass)
		{
		case ModifierPass.PreProcess:
			if (preProcessPath != null)
			{
				preProcessPath(p);
			}
			break;
		case ModifierPass.PostProcessOriginal:
			if (postProcessOriginalPath != null)
			{
				postProcessOriginalPath(p);
			}
			break;
		case ModifierPass.PostProcess:
			if (postProcessPath != null)
			{
				postProcessPath(p);
			}
			break;
		}
		if (modifiers.Count == 0)
		{
			return;
		}
		ModifierData modifierData = ModifierData.All;
		IPathModifier pathModifier = modifiers[0];
		for (int j = 0; j < modifiers.Count; j++)
		{
			MonoModifier monoModifier = modifiers[j] as MonoModifier;
			if ((Object)(object)monoModifier != (Object)null && !((Behaviour)monoModifier).enabled)
			{
				continue;
			}
			switch (pass)
			{
			case ModifierPass.PreProcess:
				modifiers[j].PreProcess(p);
				break;
			case ModifierPass.PostProcessOriginal:
				modifiers[j].ApplyOriginal(p);
				break;
			case ModifierPass.PostProcess:
			{
				ModifierData modifierData2 = ModifierConverter.Convert(p, modifierData, modifiers[j].input);
				if (modifierData2 != ModifierData.None)
				{
					modifiers[j].Apply(p, modifierData2);
					modifierData = modifiers[j].output;
				}
				else
				{
					Debug.Log((object)("Error converting " + ((j <= 0) ? "original" : pathModifier.GetType().Name) + "'s output to " + modifiers[j].GetType().Name + "'s input.\nTry rearranging the modifier priorities on the Seeker."));
					modifierData = ModifierData.None;
				}
				pathModifier = modifiers[j];
				break;
			}
			}
			if (modifierData == ModifierData.None)
			{
				break;
			}
		}
	}

	public bool IsDone()
	{
		return path == null || path.GetState() >= PathState.Returned;
	}

	public void OnPathComplete(Pathfinding.Path p)
	{
		OnPathComplete(p, runModifiers: true, sendCallbacks: true);
	}

	public void OnPathComplete(Pathfinding.Path p, bool runModifiers, bool sendCallbacks)
	{
		if ((p != null && p != path && sendCallbacks) || (Object)(object)this == (Object)null || p == null || p != path)
		{
			return;
		}
		if (!path.error && runModifiers)
		{
			RunModifiers(ModifierPass.PostProcessOriginal, path);
			RunModifiers(ModifierPass.PostProcess, path);
		}
		if (sendCallbacks)
		{
			p.Claim(this);
			lastCompletedNodePath = p.path;
			lastCompletedVectorPath = p.vectorPath;
			if (tmpPathCallback != null)
			{
				tmpPathCallback(p);
			}
			if (pathCallback != null)
			{
				pathCallback(p);
			}
			if (prevPath != null)
			{
				prevPath.ReleaseSilent(this);
			}
			prevPath = p;
		}
	}

	public void OnPartialPathComplete(Pathfinding.Path p)
	{
		OnPathComplete(p, runModifiers: true, sendCallbacks: false);
	}

	public void OnMultiPathComplete(Pathfinding.Path p)
	{
		OnPathComplete(p, runModifiers: false, sendCallbacks: true);
	}

	public Pathfinding.Path GetNewPath(Vector3 start, Vector3 end)
	{
		//IL_0000: Unknown result type (might be due to invalid IL or missing references)
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		return ABPath.Construct(start, end);
	}

	public Pathfinding.Path StartPath(Vector3 start, Vector3 end)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		//IL_0002: Unknown result type (might be due to invalid IL or missing references)
		return StartPath(start, end, null, -1);
	}

	public Pathfinding.Path StartPath(Vector3 start, Vector3 end, OnPathDelegate callback)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		//IL_0002: Unknown result type (might be due to invalid IL or missing references)
		return StartPath(start, end, callback, -1);
	}

	public Pathfinding.Path StartPath(Vector3 start, Vector3 end, OnPathDelegate callback, int graphMask)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		//IL_0002: Unknown result type (might be due to invalid IL or missing references)
		Pathfinding.Path newPath = GetNewPath(start, end);
		return StartPath(newPath, callback, graphMask);
	}

	public Pathfinding.Path StartPath(Pathfinding.Path p, OnPathDelegate callback = null, int graphMask = -1)
	{
		p.enabledTags = traversableTags.tagsChange;
		p.tagPenalties = tagPenalties;
		if ((object)p.GetType() == typeof(MultiTargetPath))
		{
			return StartMultiTargetPath(p as MultiTargetPath, callback);
		}
		if (path != null && path.GetState() <= PathState.Processing && lastPathID == path.pathID)
		{
			path.LogError("Canceled path because a new one was requested\nGameObject: " + ((Object)((Component)this).gameObject).name);
		}
		path = p;
		Pathfinding.Path obj = path;
		obj.callback = (OnPathDelegate)Delegate.Combine(obj.callback, onPathDelegate);
		path.nnConstraint.graphMask = graphMask;
		tmpPathCallback = callback;
		lastPathID = path.pathID;
		RunModifiers(ModifierPass.PreProcess, path);
		AstarPath.StartPath(path);
		return path;
	}

	public MultiTargetPath StartMultiTargetPath(Vector3 start, Vector3[] endPoints, bool pathsForAll, OnPathDelegate callback = null, int graphMask = -1)
	{
		//IL_0000: Unknown result type (might be due to invalid IL or missing references)
		MultiTargetPath multiTargetPath = MultiTargetPath.Construct(start, endPoints, null);
		multiTargetPath.pathsForAll = pathsForAll;
		return StartMultiTargetPath(multiTargetPath, callback, graphMask);
	}

	public MultiTargetPath StartMultiTargetPath(Vector3[] startPoints, Vector3 end, bool pathsForAll, OnPathDelegate callback = null, int graphMask = -1)
	{
		//IL_0001: Unknown result type (might be due to invalid IL or missing references)
		MultiTargetPath multiTargetPath = MultiTargetPath.Construct(startPoints, end, null);
		multiTargetPath.pathsForAll = pathsForAll;
		return StartMultiTargetPath(multiTargetPath, callback, graphMask);
	}

	public MultiTargetPath StartMultiTargetPath(MultiTargetPath p, OnPathDelegate callback = null, int graphMask = -1)
	{
		if (path != null && path.GetState() <= PathState.Processing && lastPathID == path.pathID)
		{
			path.LogError("Canceled path because a new one was requested");
		}
		OnPathDelegate[] array = new OnPathDelegate[p.targetPoints.Length];
		for (int i = 0; i < array.Length; i++)
		{
			array[i] = onPartialPathDelegate;
		}
		p.callbacks = array;
		p.callback = (OnPathDelegate)Delegate.Combine(p.callback, new OnPathDelegate(OnMultiPathComplete));
		p.nnConstraint.graphMask = graphMask;
		path = p;
		tmpPathCallback = callback;
		lastPathID = path.pathID;
		RunModifiers(ModifierPass.PreProcess, path);
		AstarPath.StartPath(path);
		return p;
	}

	public IEnumerator DelayPathStart(Pathfinding.Path p)
	{
		yield return 0;
		RunModifiers(ModifierPass.PreProcess, p);
		AstarPath.StartPath(p);
	}

	public void OnDrawGizmos()
	{
		//IL_00b0: Unknown result type (might be due to invalid IL or missing references)
		//IL_0036: Unknown result type (might be due to invalid IL or missing references)
		//IL_00d3: Unknown result type (might be due to invalid IL or missing references)
		//IL_00e1: Unknown result type (might be due to invalid IL or missing references)
		//IL_0063: Unknown result type (might be due to invalid IL or missing references)
		//IL_007b: Unknown result type (might be due to invalid IL or missing references)
		if (lastCompletedNodePath == null || !drawGizmos)
		{
			return;
		}
		if (detailedGizmos)
		{
			Gizmos.color = new Color(0.7f, 0.5f, 0.1f, 0.5f);
			if (lastCompletedNodePath != null)
			{
				for (int i = 0; i < lastCompletedNodePath.Count - 1; i++)
				{
					Gizmos.DrawLine((Vector3)lastCompletedNodePath[i].position, (Vector3)lastCompletedNodePath[i + 1].position);
				}
			}
		}
		Gizmos.color = new Color(0f, 1f, 0f, 1f);
		if (lastCompletedVectorPath != null)
		{
			for (int j = 0; j < lastCompletedVectorPath.Count - 1; j++)
			{
				Gizmos.DrawLine(lastCompletedVectorPath[j], lastCompletedVectorPath[j + 1]);
			}
		}
	}
}
namespace Pathfinding
{
	[Serializable]
	public class AstarData
	{
		[NonSerialized]
		public NavMeshGraph navmesh;

		[NonSerialized]
		public GridGraph gridGraph;

		[NonSerialized]
		public PointGraph pointGraph;

		[NonSerialized]
		public NodeRun[][] nodeRuns;

		public Type[] graphTypes;

		[NonSerialized]
		public NavGraph[] graphs = new NavGraph[0];

		[NonSerialized]
		public UserConnection[] userConnections = new UserConnection[0];

		public bool hasBeenReverted;

		[SerializeField]
		private byte[] data;

		public uint dataChecksum;

		public byte[] data_backup;

		public byte[] data_cachedStartup;

		public byte[] revertData;

		public bool cacheStartup;

		public bool compress;

		public AstarPath active => AstarPath.active;

		public byte[] GetData()
		{
			return data;
		}

		public void SetData(byte[] data, uint checksum)
		{
			this.data = data;
			dataChecksum = checksum;
		}

		public void Awake()
		{
			userConnections = new UserConnection[0];
			graphs = new NavGraph[0];
			if (cacheStartup && data_cachedStartup != null)
			{
				LoadFromCache();
			}
			else
			{
				DeserializeGraphs();
			}
		}

		[Obsolete]
		public void CollectNodes(int numTemporary)
		{
		}

		public void AssignNodeIndices()
		{
			int num = 0;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i].nodes == null)
				{
					continue;
				}
				Node[] nodes = graphs[i].nodes;
				int num2 = 0;
				while (num2 < nodes.Length)
				{
					if (nodes[num2] != null)
					{
						nodes[num2].SetNodeIndex(num);
					}
					num2++;
					num++;
				}
			}
		}

		public void CreateNodeRuns(int numParallel)
		{
			if (graphs == null)
			{
				throw new Exception("Cannot create NodeRuns when no graphs exist. (Scan and or Load graphs first)");
			}
			int num = 0;
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i].nodes != null)
				{
					num += graphs[i].nodes.Length;
				}
			}
			AssignNodeIndices();
			if (nodeRuns == null || nodeRuns.Length != numParallel)
			{
				nodeRuns = new NodeRun[numParallel][];
			}
			for (int j = 0; j < nodeRuns.Length; j++)
			{
				if (nodeRuns[j] == null || nodeRuns[j].Length != num)
				{
					nodeRuns[j] = new NodeRun[num];
				}
				else
				{
					Debug.Log((object)"Saved some allocations");
				}
				int num2 = 0;
				for (int k = 0; k < graphs.Length; k++)
				{
					Node[] nodes = graphs[k].nodes;
					if (nodes == null)
					{
						continue;
					}
					int num3 = 0;
					while (num3 < nodes.Length)
					{
						if (nodes[num3] != null)
						{
							if (nodeRuns[j][num2] == null)
							{
								nodeRuns[j][num2] = new NodeRun();
							}
							else
							{
								nodeRuns[j][num2].Reset();
							}
							nodeRuns[j][num2].Link(nodes[num3], num2);
						}
						num3++;
						num2++;
					}
				}
			}
			active.UpdatePathThreadInfoNodes();
		}

		public void UpdateShortcuts()
		{
			navmesh = (NavMeshGraph)FindGraphOfType(typeof(NavMeshGraph));
			gridGraph = (GridGraph)FindGraphOfType(typeof(GridGraph));
			pointGraph = (PointGraph)FindGraphOfType(typeof(PointGraph));
		}

		public void LoadFromCache()
		{
			if (data_cachedStartup != null && data_cachedStartup.Length > 0)
			{
				DeserializeGraphs(data_cachedStartup);
				GraphModifier.TriggerEvent(GraphModifier.EventType.PostCacheLoad);
			}
			else
			{
				Debug.LogError((object)"Can't load from cache since the cache is empty");
			}
		}

		public void SaveCacheData(SerializeSettings settings)
		{
			data_cachedStartup = SerializeGraphs(settings);
			cacheStartup = true;
		}

		public byte[] SerializeGraphs()
		{
			return SerializeGraphs(SerializeSettings.Settings);
		}

		public byte[] SerializeGraphs(SerializeSettings settings)
		{
			uint checksum;
			return SerializeGraphs(settings, out checksum);
		}

		public byte[] SerializeGraphs(SerializeSettings settings, out uint checksum)
		{
			Pathfinding.Serialization.AstarSerializer astarSerializer = new Pathfinding.Serialization.AstarSerializer(this, settings);
			astarSerializer.OpenSerialize();
			SerializeGraphsPart(astarSerializer);
			byte[] result = astarSerializer.CloseSerialize();
			checksum = astarSerializer.GetChecksum();
			return result;
		}

		public void SerializeGraphsPart(Pathfinding.Serialization.AstarSerializer sr)
		{
			sr.SerializeGraphs(graphs);
			sr.SerializeUserConnections(userConnections);
			sr.SerializeNodes();
			sr.SerializeExtraInfo();
		}

		public void DeserializeGraphs()
		{
			if (data != null)
			{
				DeserializeGraphs(data);
			}
		}

		public void DeserializeGraphs(byte[] bytes)
		{
			try
			{
				if (bytes != null)
				{
					Pathfinding.Serialization.AstarSerializer astarSerializer = new Pathfinding.Serialization.AstarSerializer(this);
					if (astarSerializer.OpenDeserialize(bytes))
					{
						DeserializeGraphsPart(astarSerializer);
						astarSerializer.CloseDeserialize();
					}
					else
					{
						Debug.Log((object)"Invalid data file (cannot read zip). Trying to load with old deserializer (pre 3.1)...");
						AstarSerializer serializer = new AstarSerializer(active);
						DeserializeGraphs_oldInternal(serializer);
					}
					active.DataUpdate();
					return;
				}
				throw new ArgumentNullException("Bytes should not be null when passed to DeserializeGraphs");
			}
			catch (Exception ex)
			{
				Debug.LogWarning((object)("Caught exception while deserializing data.\n" + ex));
				data_backup = bytes;
			}
		}

		public void DeserializeGraphsAdditive(byte[] bytes)
		{
			try
			{
				if (bytes != null)
				{
					Pathfinding.Serialization.AstarSerializer astarSerializer = new Pathfinding.Serialization.AstarSerializer(this);
					if (astarSerializer.OpenDeserialize(bytes))
					{
						DeserializeGraphsPartAdditive(astarSerializer);
						astarSerializer.CloseDeserialize();
					}
					else
					{
						Debug.Log((object)"Invalid data file (cannot read zip).");
					}
					active.DataUpdate();
					return;
				}
				throw new ArgumentNullException("Bytes should not be null when passed to DeserializeGraphs");
			}
			catch (Exception ex)
			{
				Debug.LogWarning((object)("Caught exception while deserializing data.\n" + ex));
			}
		}

		public void DeserializeGraphsPart(Pathfinding.Serialization.AstarSerializer sr)
		{
			graphs = sr.DeserializeGraphs();
			userConnections = sr.DeserializeUserConnections();
			sr.DeserializeNodes();
			sr.DeserializeExtraInfo();
			sr.PostDeserialization();
		}

		public void DeserializeGraphsPartAdditive(Pathfinding.Serialization.AstarSerializer sr)
		{
			if (graphs == null)
			{
				graphs = new NavGraph[0];
			}
			if (userConnections == null)
			{
				userConnections = new UserConnection[0];
			}
			List<NavGraph> list = new List<NavGraph>(graphs);
			list.AddRange(sr.DeserializeGraphs());
			graphs = list.ToArray();
			List<UserConnection> list2 = new List<UserConnection>(userConnections);
			list2.AddRange(sr.DeserializeUserConnections());
			userConnections = list2.ToArray();
			sr.DeserializeNodes();
			sr.DeserializeExtraInfo();
			sr.PostDeserialization();
			for (int i = 0; i < graphs.Length; i++)
			{
				for (int j = i + 1; j < graphs.Length; j++)
				{
					if (graphs[i].guid == graphs[j].guid)
					{
						Debug.LogWarning((object)"Guid Conflict when importing graphs additively. Imported graph will get a new Guid.\nThis message is (relatively) harmless.");
						graphs[i].guid = Pathfinding.Util.Guid.NewGuid();
						break;
					}
				}
			}
		}

		[Obsolete("This function is obsolete. Use DeserializeGraphs () instead")]
		public void DeserializeGraphs(AstarSerializer serializer)
		{
			DeserializeGraphs_oldInternal(serializer);
		}

		public void DeserializeGraphs_oldInternal(AstarSerializer serializer)
		{
			DeserializeGraphs_oldInternal(serializer, data);
		}

		[Obsolete("This function is obsolete. Use DeserializeGraphs (bytes) instead")]
		public void DeserializeGraphs(AstarSerializer serializer, byte[] bytes)
		{
			DeserializeGraphs_oldInternal(serializer, bytes);
		}

		public void DeserializeGraphs_oldInternal(AstarSerializer serializer, byte[] bytes)
		{
			DateTime utcNow = DateTime.UtcNow;
			if (bytes == null || bytes.Length == 0)
			{
				Debug.Log((object)"No previous data, assigning default");
				graphs = new NavGraph[0];
				return;
			}
			Debug.Log((object)"Deserializing...");
			serializer = serializer.OpenDeserialize(bytes);
			DeserializeGraphsPart(serializer);
			serializer.Close();
			DateTime utcNow2 = DateTime.UtcNow;
