		public void DeserializeGraphsPart(AstarSerializer serializer)
		{
			if (serializer.error != AstarSerializer.SerializerError.Nothing)
			{
				data_backup = (serializer.readerStream.BaseStream as MemoryStream).ToArray();
				Debug.Log((object)string.Concat("Error encountered : ", serializer.error, "\nWriting data to AstarData.data_backup"));
				graphs = new NavGraph[0];
				return;
			}
			try
			{
				int num = serializer.readerStream.ReadInt32();
				int num2 = serializer.readerStream.ReadInt32();
				if (num != num2)
				{
					Debug.LogError((object)("Data is corrupt (" + num + " != " + num2 + ")"));
					graphs = new NavGraph[0];
					return;
				}
				NavGraph[] array = new NavGraph[num];
				for (int i = 0; i < array.Length; i++)
				{
					if (!serializer.MoveToAnchor("Graph" + i))
					{
						Debug.LogError((object)("Couldn't find graph " + i + " in the data"));
						Debug.Log((object)("Logging... " + serializer.anchors.Count));
						foreach (KeyValuePair<string, int> anchor in serializer.anchors)
						{
							Debug.Log((object)("KeyValuePair " + anchor.Key));
						}
						array[i] = null;
						continue;
					}
					string text = serializer.readerStream.ReadString();
					text = text.Replace("ListGraph", "PointGraph");
					Pathfinding.Util.Guid guid = new Pathfinding.Util.Guid(serializer.readerStream.ReadString());
					NavGraph navGraph = GuidToGraph(guid);
					if (navGraph != null)
					{
						array[i] = navGraph;
					}
					else
					{
						array[i] = CreateGraph(text);
					}
					NavGraph navGraph2 = array[i];
					if (navGraph2 == null)
					{
						Debug.LogError((object)("One of the graphs saved was of an unknown type, the graph was of type '" + text + "'"));
						data_backup = data;
						graphs = new NavGraph[0];
						return;
					}
					array[i].guid = guid;
					serializer.sPrefix = i.ToString();
					serializer.DeSerializeSettings(navGraph2, active);
				}
				serializer.SetUpGraphRefs(array);
				for (int j = 0; j < array.Length; j++)
				{
					NavGraph graph = array[j];
					if (serializer.MoveToAnchor("GraphNodes_Graph" + j))
					{
						serializer.mask = serializer.readerStream.ReadInt32();
						serializer.sPrefix = j + "N";
						serializer.DeserializeNodes(graph, array, j, active);
						serializer.sPrefix = string.Empty;
					}
				}
				userConnections = serializer.DeserializeUserConnections();
				List<NavGraph> list = new List<NavGraph>(array);
				for (int k = 0; k < array.Length; k++)
				{
					if (array[k] == null)
					{
						list.Remove(array[k]);
					}
				}
				graphs = list.ToArray();
			}
			catch (Exception ex)
			{
				data_backup = (serializer.readerStream.BaseStream as MemoryStream).ToArray();
				Debug.LogWarning((object)("Deserializing Error Encountered - Writing data to AstarData.data_backup:\n" + ex.ToString()));
				graphs = new NavGraph[0];
			}
		}

		public void FindGraphTypes()
		{
			Assembly assembly = Assembly.GetAssembly(typeof(AstarPath));
			Type[] types = assembly.GetTypes();
			List<Type> list = new List<Type>();
			Type[] array = types;
			foreach (Type type in array)
			{
				Type baseType = type.BaseType;
				while ((object)baseType != null)
				{
					if ((object)baseType == typeof(NavGraph))
					{
						list.Add(type);
						break;
					}
					baseType = baseType.BaseType;
				}
			}
			graphTypes = list.ToArray();
		}

		public Type GetGraphType(string type)
		{
			for (int i = 0; i < graphTypes.Length; i++)
			{
				if (graphTypes[i].Name == type)
				{
					return graphTypes[i];
				}
			}
			return null;
		}

		public NavGraph CreateGraph(string type)
		{
			Debug.Log((object)("Creating Graph of type '" + type + "'"));
			for (int i = 0; i < graphTypes.Length; i++)
			{
				if (graphTypes[i].Name == type)
				{
					return CreateGraph(graphTypes[i]);
				}
			}
			Debug.LogError((object)("Graph type (" + type + ") wasn't found"));
			return null;
		}

		public NavGraph CreateGraph(Type type)
		{
			NavGraph navGraph = Activator.CreateInstance(type) as NavGraph;
			navGraph.active = active;
			return navGraph;
		}

		public NavGraph AddGraph(string type)
		{
			NavGraph navGraph = null;
			for (int i = 0; i < graphTypes.Length; i++)
			{
				if (graphTypes[i].Name == type)
				{
					navGraph = CreateGraph(graphTypes[i]);
				}
			}
			if (navGraph == null)
			{
				Debug.LogError((object)("No NavGraph of type '" + type + "' could be found"));
				return null;
			}
			AddGraph(navGraph);
			return navGraph;
		}

		public NavGraph AddGraph(Type type)
		{
			NavGraph navGraph = null;
			for (int i = 0; i < graphTypes.Length; i++)
			{
				if ((object)graphTypes[i] == type)
				{
					navGraph = CreateGraph(graphTypes[i]);
				}
			}
			if (navGraph == null)
			{
				Debug.LogError((object)string.Concat("No NavGraph of type '", type, "' could be found, ", graphTypes.Length, " graph types are avaliable"));
				return null;
			}
			AddGraph(navGraph);
			return navGraph;
		}

		public void AddGraph(NavGraph graph)
		{
			List<NavGraph> list = new List<NavGraph>(graphs);
			list.Add(graph);
			graphs = list.ToArray();
		}

		public void RemoveGraph(NavGraph graph)
		{
			List<NavGraph> list = new List<NavGraph>(graphs);
			list.Remove(graph);
			graphs = list.ToArray();
			graph.SafeOnDestroy();
		}

		public static NavGraph GetGraph(Node node)
		{
			if (node == null)
			{
				return null;
			}
			AstarPath astarPath = AstarPath.active;
			if ((Object)(object)astarPath == (Object)null)
			{
				return null;
			}
			AstarData astarData = astarPath.astarData;
			if (astarData == null)
			{
				return null;
			}
			if (astarData.graphs == null)
			{
				return null;
			}
			int graphIndex = node.graphIndex;
			if (graphIndex < 0 || graphIndex >= astarData.graphs.Length)
			{
				return null;
			}
			return astarData.graphs[graphIndex];
		}

		public Node GetNode(int graphIndex, int nodeIndex)
		{
			return GetNode(graphIndex, nodeIndex, graphs);
		}

		public Node GetNode(int graphIndex, int nodeIndex, NavGraph[] graphs)
		{
			if (graphs == null)
			{
				return null;
			}
			if (graphIndex < 0 || graphIndex >= graphs.Length)
			{
				Debug.LogError((object)("Graph index is out of range" + graphIndex + " [0-" + (graphs.Length - 1) + "]"));
				return null;
			}
			NavGraph navGraph = graphs[graphIndex];
			if (navGraph.nodes == null)
			{
				return null;
			}
			if (nodeIndex < 0 || nodeIndex >= navGraph.nodes.Length)
			{
				Debug.LogError((object)("Node index is out of range : " + nodeIndex + " [0-" + (navGraph.nodes.Length - 1) + "] (graph " + graphIndex + ")"));
				return null;
			}
			return navGraph.nodes[nodeIndex];
		}

		public NavGraph FindGraphOfType(Type type)
		{
			for (int i = 0; i < graphs.Length; i++)
			{
				if ((object)graphs[i].GetType() == type)
				{
					return graphs[i];
				}
			}
			return null;
		}

		public IEnumerable FindGraphsOfType(Type type)
		{
			if (graphs == null)
			{
				yield break;
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				if ((object)graphs[i].GetType() == type)
				{
					yield return graphs[i];
				}
			}
		}

		public IEnumerable GetUpdateableGraphs()
		{
			if (graphs == null)
			{
				yield break;
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i] is IUpdatableGraph)
