		public int GetGraphIndex(NavGraph graph)
		{
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graph == graphs[i])
				{
					return i;
				}
			}
			Debug.LogError((object)"Graph doesn't exist");
			return -1;
		}

		public int GuidToIndex(Pathfinding.Util.Guid guid)
		{
			if (graphs == null)
			{
				return -1;
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i] == null)
				{
					Debug.LogWarning((object)("Graph " + i + " is null - This should not happen"));
				}
				else if (graphs[i].guid == guid)
				{
					return i;
				}
			}
			return -1;
		}

		public NavGraph GuidToGraph(Pathfinding.Util.Guid guid)
		{
			if (graphs == null)
			{
				return null;
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i] == null)
				{
					Debug.LogWarning((object)("Graph " + i + " is null - This should not happen"));
				}
				else if (graphs[i].guid == guid)
				{
					return graphs[i];
				}
			}
			return null;
		}
