					flag = true;
				}
				foreach (IUpdatableGraph updateableGraph in astarData.GetUpdateableGraphs())
				{
					NavGraph graph = updateableGraph as NavGraph;
					if (graphUpdateObject.nnConstraint == null || graphUpdateObject.nnConstraint.SuitableGraph(active.astarData.GetGraphIndex(graph), graph))
					{
						updateableGraph.UpdateArea(graphUpdateObject);
					}
				}
			}
		}
		isUpdatingGraphs = false;
		if (flag && !isScanning)
		{
			FloodFill();
		}
		if (OnGraphsUpdated != null && !isScanning)
		{
			OnGraphsUpdated(this);
		}
		GraphModifier.TriggerEvent(GraphModifier.EventType.PostUpdate);
	}

	public void FlushThreadSafeCallbacks()
	{
		if (OnThreadSafeCallback == null)
		{
			return;
		}
		bool flag = true;
		if (IsUsingMultithreading)
		{
			for (int i = 0; i < threadInfos.Length; i++)
			{
				bool flag2 = false;
				while (!flag2 && !threadSafeUpdateState)
				{
					flag2 = Monitor.TryEnter(threadInfos[i].Lock, 10);
				}
				if (threadSafeUpdateState)
				{
					if (i != 0 || flag2)
					{
						throw new Exception("Wait wut! This should not happen! " + i + " " + flag2);
					}
					flag = false;
					break;
				}
			}
			threadSafeUpdateState = true;
		}
		else
		{
			while (!threadSafeUpdateState && threadEnumerator.MoveNext())
			{
			}
		}
		TryCallThreadSafeCallbacks();
		doSetQueueState = true;
		pathQueueFlag.Set();
		if (IsUsingMultithreading && flag)
		{
			for (int j = 0; j < threadInfos.Length; j++)
			{
				Monitor.Exit(threadInfos[j].Lock);
			}
		}
	}

