	public static int CalculateThreadCount(ThreadCount count)
	{
		if (count == ThreadCount.Automatic)
		{
			int num = SystemInfo.processorCount;
			int systemMemorySize = SystemInfo.systemMemorySize;
			if (num <= 1)
			{
				return 0;
			}
			if (systemMemorySize <= 512)
			{
				return 0;
			}
			if (systemMemorySize <= 1024)
			{
				num = Math.Min(num, 2);
			}
			return Math.Min(num, 6);
		}
		return (int)count;
	}

	public void Awake()
	{
		active = this;
		if (Object.FindObjectsOfType(typeof(AstarPath)).Length > 1)
		{
			Debug.LogError((object)"You should NOT have more than one AstarPath component in the scene at any time.\nThis can cause serious errors since the AstarPath component builds around a singleton pattern.");
		}
		((MonoBehaviour)this).useGUILayout = false;
		if (OnAwakeSettings != null)
		{
			OnAwakeSettings();
		}
		int num = CalculateThreadCount(threadCount);
		threads = new Thread[num];
		threadInfos = new PathThreadInfo[Math.Max(num, 1)];
		for (int i = 0; i < threadInfos.Length; i++)
		{
			ref PathThreadInfo reference = ref threadInfos[i];
			reference = new PathThreadInfo(i, this, new NodeRunData());
		}
		for (int j = 0; j < threads.Length; j++)
		{
			threads[j] = new Thread(CalculatePathsThreaded);
			threads[j].IsBackground = true;
		}
		Initialize();
		((MonoBehaviour)this).StartCoroutine(ReturnsPathsHandler());
		if (scanOnStartup && (!astarData.cacheStartup || astarData.data_cachedStartup == null))
		{
			Scan();
		}
		UpdatePathThreadInfoNodes();
		if (threads.Length > 0)
		{
			Thread thread = new Thread(LockThread);
			thread.Start(this);
		}
		for (int k = 0; k < threads.Length; k++)
		{
			if (logPathResults == PathLog.Heavy)
			{
				Debug.Log((object)("Starting pathfinding thread " + k));
			}
			threads[k].Start(threadInfos[k]);
		}
		if (threads.Length == 0)
		{
			((MonoBehaviour)this).StartCoroutine(CalculatePathsHandler(threadInfos[0]));
		}
	}

	public void DataUpdate()
	{
		if ((Object)(object)active != (Object)(object)this)
		{
			throw new Exception("Singleton pattern broken. Make sure you only have one AstarPath object in the scene");
		}
		if (astarData == null)
		{
			throw new NullReferenceException("AstarData is null... Astar not set up correctly?");
		}
		if (astarData.graphs == null)
		{
			astarData.graphs = new NavGraph[0];
		}
		astarData.AssignNodeIndices();
		if (Application.isPlaying)
		{
			astarData.CreateNodeRuns(threadInfos.Length);
		}
	}

	public void UpdatePathThreadInfoNodes()
	{
		for (int i = 0; i < threadInfos.Length; i++)
		{
			PathThreadInfo pathThreadInfo = threadInfos[i];
			if (pathThreadInfo.threadIndex != i)
			{
				throw new Exception("threadInfos[" + i + "] did not have a matching index member. Expected " + i + " found " + pathThreadInfo.threadIndex);
			}
			NodeRunData runData = pathThreadInfo.runData;
			if (runData == null)
			{
				throw new NullReferenceException("A thread info.node run data was null");
			}
			runData.nodes = astarData.nodeRuns[i];
		}
	}

