	public void OnDestroy()
	{
		if (logPathResults == PathLog.Heavy)
		{
			Debug.Log((object)"+++ AstarPath Component Destroyed - Cleaning Up Pathfinding Data +++");
		}
		TrickAbortThreads();
		if (threads != null)
		{
			for (int i = 0; i < threads.Length; i++)
			{
				if (!threads[i].Join(50))
				{
					Debug.LogError((object)("Could not terminate pathfinding thread[" + i + "] in 50ms, trying Thread.Abort"));
					threads[i].Abort();
				}
			}
		}
		if (logPathResults == PathLog.Heavy)
		{
			Debug.Log((object)"Destroying Graphs");
		}
		if (astarData.graphs != null)
		{
			for (int j = 0; j < astarData.graphs.Length; j++)
			{
				astarData.graphs[j].OnDestroy();
			}
		}
		astarData.graphs = null;
		if (logPathResults == PathLog.Heavy)
		{
			Debug.Log((object)"Returning Paths");
		}
		ReturnPaths(timeSlice: false);
		pathReturnStack.PopAll();
		if (logPathResults == PathLog.Heavy)
		{
			Debug.Log((object)"Cleaning up variables");
		}
		floodStack = null;
		graphUpdateQueue = null;
		OnDrawGizmosCallback = null;
		OnAwakeSettings = null;
		OnGraphPreScan = null;
		OnGraphPostScan = null;
		OnPathPreSearch = null;
		OnPathPostSearch = null;
		OnPreScan = null;
		OnPostScan = null;
		OnLatePostScan = null;
		On65KOverflow = null;
		OnGraphsUpdated = null;
		OnSafeCallback = null;
		OnThreadSafeCallback = null;
		pathQueue.Clear();
		threads = null;
		threadInfos = null;
		numActiveThreads = 0;
		ResetQueueStates();
		PathsCompleted = 0;
		active = null;
	}

	public void FloodFill(Node seed)
	{
		FloodFill(seed, lastUniqueAreaIndex + 1);
		lastUniqueAreaIndex++;
	}

	public void FloodFill(Node seed, int area)
	{
		if (area > 255)
		{
			Debug.LogError((object)"Too high area index - The maximum area index is 255");
			return;
		}
		if (area < 0)
		{
			Debug.LogError((object)"Too low area index - The minimum area index is 0");
			return;
		}
		if (floodStack == null)
		{
			floodStack = new Stack<Node>(1024);
		}
		Stack<Node> stack = floodStack;
		stack.Clear();
		stack.Push(seed);
		seed.area = area;
		while (stack.Count > 0)
		{
			stack.Pop().FloodFill(stack, area);
		}
	}

	public void FloodFill()
	{
		if (astarData.graphs == null)
		{
			return;
		}
		int num = 0;
		lastUniqueAreaIndex = 0;
		if (floodStack == null)
		{
			floodStack = new Stack<Node>(1024);
		}
		Stack<Node> stack = floodStack;
		for (int i = 0; i < graphs.Length; i++)
		{
			NavGraph navGraph = graphs[i];
			if (navGraph.nodes == null)
			{
				continue;
			}
			for (int j = 0; j < navGraph.nodes.Length; j++)
			{
				if (navGraph.nodes[j] != null)
				{
					navGraph.nodes[j].area = 0;
				}
			}
		}
		int num2 = 0;
		for (int k = 0; k < graphs.Length; k++)
		{
			NavGraph navGraph2 = graphs[k];
			if (navGraph2.nodes == null)
			{
				Debug.LogWarning((object)("Graph " + k + " has not defined any nodes"));
				continue;
			}
			for (int l = 0; l < navGraph2.nodes.Length; l++)
			{
				if (navGraph2.nodes[l] == null || !navGraph2.nodes[l].walkable || navGraph2.nodes[l].area != 0)
				{
					continue;
				}
				num++;
				if (num > 255)
				{
					Debug.LogError((object)"Too many areas - The maximum number of areas is 256");
					num--;
					break;
				}
				stack.Clear();
				stack.Push(navGraph2.nodes[l]);
				int num3 = 1;
				navGraph2.nodes[l].area = num;
				while (stack.Count > 0)
				{
					num3++;
					stack.Pop().FloodFill(stack, num);
				}
				if (num3 < minAreaSize)
				{
					stack.Clear();
					stack.Push(navGraph2.nodes[l]);
					navGraph2.nodes[l].area = 254;
					while (stack.Count > 0)
					{
						stack.Pop().FloodFill(stack, 254);
					}
					num2++;
					num--;
				}
			}
		}
		lastUniqueAreaIndex = num;
		if (num2 > 0)
		{
			AstarLog(num2 + " small areas were detected (fewer than " + minAreaSize + " nodes),these might have the same IDs as other areas, but it shouldn't affect pathfinding in any significant way (you might get All Nodes Searched as a reason for path failure).\nWhich areas are defined as 'small' is controlled by the 'Min Area Size' variable, it can be changed in the A* inspector-->Settings-->Min Area Size\nThe small areas will use the area id 254");
		}
	}

	public void Scan()
	{
		IEnumerator<Progress> enumerator = ScanLoop().GetEnumerator();
		while (enumerator.MoveNext())
		{
		}
	}

	public IEnumerable<Progress> ScanLoop()
	{
		if (graphs == null)
		{
			yield break;
		}
		isScanning = true;
		yield return new Progress(0.02f, "Updating graph shortcuts");
		astarData.UpdateShortcuts();
		yield return new Progress(0.05f, "Pre processing graphs");
		if (OnPreScan != null)
		{
			OnPreScan(this);
		}
		GraphModifier.TriggerEvent(GraphModifier.EventType.PreScan);
		DateTime startTime = DateTime.UtcNow;
		for (int i = 0; i < graphs.Length; i++)
		{
			NavGraph graph = graphs[i];
			if (OnGraphPreScan != null)
			{
				yield return new Progress(Mathfx.MapTo(0.05f, 0.7f, ((float)i + 0.5f) / (float)(graphs.Length + 1)), "Scanning graph " + (i + 1) + " of " + graphs.Length + " - Pre processing");
				OnGraphPreScan(graph);
			}
			yield return new Progress(Mathfx.MapTo(0.05f, 0.7f, ((float)i + 1f) / (float)(graphs.Length + 1)), "Scanning graph " + (i + 1) + " of " + graphs.Length);
			graph.Scan();
			yield return new Progress(Mathfx.MapTo(0.05f, 0.7f, ((float)i + 1.1f) / (float)(graphs.Length + 1)), "Scanning graph " + (i + 1) + " of " + graphs.Length + " - Assigning graph indices");
			if (graph.nodes != null)
			{
				for (int j = 0; j < graph.nodes.Length; j++)
				{
					if (graph.nodes[j] != null)
					{
						graph.nodes[j].graphIndex = i;
					}
				}
			}
			if (OnGraphPostScan != null)
			{
				yield return new Progress(Mathfx.MapTo(0.05f, 0.7f, ((float)i + 1.5f) / (float)(graphs.Length + 1)), "Scanning graph " + (i + 1) + " of " + graphs.Length + " - Post processing");
				OnGraphPostScan(graph);
			}
		}
		yield return new Progress(0.8f, "Post processing graphs");
		if (OnPostScan != null)
		{
			OnPostScan(this);
		}
		GraphModifier.TriggerEvent(GraphModifier.EventType.PostScan);
		isScanning = false;
		yield return new Progress(0.85f, "Applying links");
		ApplyLinks();
		yield return new Progress(0.9f, "Computing areas");
		FloodFill();
		yield return new Progress(0.92f, "Updating misc. data");
		DataUpdate();
		yield return new Progress(0.95f, "Late post processing");
		if (OnLatePostScan != null)
		{
			OnLatePostScan(this);
		}
		GraphModifier.TriggerEvent(GraphModifier.EventType.LatePostScan);
		lastScanTime = (float)(DateTime.UtcNow - startTime).TotalSeconds;
		GC.Collect();
		AstarLog("Scanning - Process took " + (lastScanTime * 1000f).ToString("0") + " ms to complete ");
	}

	public void NodeCountChanged()
	{
		if (Application.isPlaying)
		{
			astarData.CreateNodeRuns(Math.Max(threads.Length, 1));
		}
	}

	public void ApplyLinks()
	{
		//IL_00de: Unknown result type (might be due to invalid IL or missing references)
		//IL_0022: Unknown result type (might be due to invalid IL or missing references)
		//IL_0038: Unknown result type (might be due to invalid IL or missing references)
		for (int i = 0; i < astarData.userConnections.Length; i++)
		{
			UserConnection userConnection = astarData.userConnections[i];
			if (userConnection.type == ConnectionType.Connection)
			{
				Node node = GetNearest(userConnection.p1).node;
				Node node2 = GetNearest(userConnection.p2).node;
				if (node == null || node2 == null)
				{
					continue;
				}
				int cost = ((!userConnection.doOverrideCost) ? (node.position - node2.position).costMagnitude : userConnection.overrideCost);
				if (userConnection.enable)
				{
					node.AddConnection(node2, cost);
					if (!userConnection.oneWay)
					{
						node2.AddConnection(node, cost);
					}
				}
				else
				{
					node.RemoveConnection(node2);
					if (!userConnection.oneWay)
					{
						node2.RemoveConnection(node);
					}
				}
				continue;
			}
			Node node3 = GetNearest(userConnection.p1).node;
			if (node3 == null)
			{
				continue;
			}
			if (userConnection.doOverrideWalkability)
			{
				node3.walkable = userConnection.enable;
				if (!node3.walkable)
				{
					node3.UpdateNeighbourConnections();
					node3.UpdateConnections();
				}
			}
			if (userConnection.doOverridePenalty)
			{
				node3.penalty = userConnection.overridePenalty;
			}
		}
		NodeLink[] array = Object.FindObjectsOfType(typeof(NodeLink)) as NodeLink[];
		for (int j = 0; j < array.Length; j++)
		{
			array[j].Apply();
		}
	}

	public static void WaitForPath(Pathfinding.Path p)
	{
		if ((Object)(object)active == (Object)null)
		{
			throw new Exception("Pathfinding is not correctly initialized in this scene (yet?). AstarPath.active is null.\nDo not call this function in Awake");
		}
		if (p == null)
		{
			throw new ArgumentNullException("Path must not be null");
		}
		if (!active.acceptNewPaths)
		{
			return;
		}
		if (p.GetState() == PathState.Created)
		{
			throw new Exception("The specified path has not been started yet.");
		}
		waitForPathDepth++;
		if (waitForPathDepth == 5)
		{
			Debug.LogError((object)"You are calling the WaitForPath function recursively (maybe from a path callback). Please don't do this.");
		}
		if (p.GetState() < PathState.ReturnQueue)
		{
			if (IsUsingMultithreading)
			{
				while (p.GetState() < PathState.ReturnQueue)
				{
					if (ActiveThreadsCount == 0)
					{
						waitForPathDepth--;
						throw new Exception("Pathfinding Threads seems to have crashed. No threads are running.");
					}
					Thread.Sleep(1);
					TryCallThreadSafeCallbacks();
				}
			}
			else
			{
				while (p.GetState() < PathState.ReturnQueue)
				{
					if (pathQueue.Count == 0 && p.GetState() != PathState.Processing)
					{
						waitForPathDepth--;
						throw new Exception(string.Concat("Critical error. Path Queue is empty but the path state is '", p.GetState(), "'"));
					}
					threadEnumerator.MoveNext();
					TryCallThreadSafeCallbacks();
				}
			}
		}
		active.ReturnPaths(timeSlice: false);
		waitForPathDepth--;
	}

	public static void RegisterSafeUpdate(OnVoidDelegate callback, bool threadSafe)
	{
		if (callback == null || !Application.isPlaying)
		{
			return;
		}
		if (threadSafeUpdateState)
		{
			callback();
			return;
		}
		if (IsUsingMultithreading)
		{
			int num = 0;
			for (int i = 0; i < threadInfos.Length && Monitor.TryEnter(threadInfos[i].Lock); i++)
			{
				num = i;
			}
			if (num == threadInfos.Length - 1)
			{
				threadSafeUpdateState = true;
				callback();
				threadSafeUpdateState = false;
			}
			for (int j = 0; j <= num; j++)
			{
				Monitor.Exit(threadInfos[j].Lock);
			}
			if (num == threadInfos.Length - 1)
			{
				return;
			}
			doSetQueueState = false;
			pathQueueFlag.Reset();
			lock (safeUpdateLock)
			{
				if (threadSafe)
				{
					OnThreadSafeCallback = (OnVoidDelegate)Delegate.Combine(OnThreadSafeCallback, callback);
				}
				else
				{
					OnSafeCallback = (OnVoidDelegate)Delegate.Combine(OnSafeCallback, callback);
				}
				safeUpdateFlag.Set();
				return;
			}
		}
		if (threadSafeUpdateState)
		{
			callback();
			return;
		}
		lock (safeUpdateLock)
		{
			if (threadSafe)
			{
				OnThreadSafeCallback = (OnVoidDelegate)Delegate.Combine(OnThreadSafeCallback, callback);
			}
			else
			{
				OnSafeCallback = (OnVoidDelegate)Delegate.Combine(OnSafeCallback, callback);
			}
		}
	}

	public static void StartPath(Pathfinding.Path p)
	{
		if ((Object)(object)active == (Object)null)
		{
			Debug.LogError((object)"There is no AstarPath object in the scene");
			return;
		}
		if (p.GetState() != PathState.Created)
		{
			throw new Exception(string.Concat("The path has an invalid state. Expected ", PathState.Created, " found ", p.GetState(), "\nMake sure you are not requesting the same path twice"));
		}
		if (!active.acceptNewPaths)
		{
			p.Error();
			p.LogError("No new paths are accepted");
			return;
		}
		if (active.graphs == null || active.graphs.Length == 0)
		{
			Debug.LogError((object)"There are no graphs in the scene");
			p.Error();
			p.LogError("There are no graphs in the scene");
			Debug.LogError((object)p.errorLog);
			return;
		}
		p.Claim(active);
		lock (pathQueue)
		{
			p.AdvanceState(PathState.PathQueue);
			pathQueue.Enqueue(p);
			if (doSetQueueState)
			{
				pathQueueFlag.Set();
			}
		}
	}

	public void OnApplicationQuit()
	{
		if (threads != null)
		{
			for (int i = 0; i < threads.Length; i++)
			{
				threads[i].Abort();
			}
		}
	}

	public IEnumerator ReturnsPathsHandler()
	{
		while (true)
		{
			ReturnPaths(timeSlice: true);
			yield return 0;
		}
	}

	public void ReturnPaths(bool timeSlice)
	{
		Pathfinding.Path next = pathReturnStack.PopAll();
		if (pathReturnPop == null)
		{
			pathReturnPop = next;
		}
		else
		{
			Pathfinding.Path next2 = pathReturnPop;
			while (next2.next != null)
			{
				next2 = next2.next;
			}
			next2.next = next;
		}
		long num = ((!timeSlice) ? 0 : (DateTime.UtcNow.Ticks + 5000));
		int num2 = 0;
		while (pathReturnPop != null)
		{
			Pathfinding.Path path = pathReturnPop;
			pathReturnPop = pathReturnPop.next;
			path.next = null;
			path.ReturnPath();
			path.AdvanceState(PathState.Returned);
			path.ReleaseSilent(this);
			num2++;
			if (num2 > 5 && timeSlice)
			{
				num2 = 0;
				if (DateTime.UtcNow.Ticks >= num)
				{
					break;
				}
			}
		}
	}

	private static void LockThread(object _astar)
	{
		AstarPath astarPath = (AstarPath)_astar;
		while (astarPath.acceptNewPaths)
		{
			safeUpdateFlag.WaitOne();
			PathThreadInfo[] array = threadInfos;
			if (array == null)
			{
				Debug.LogError((object)"Path Thread Infos are null");
				break;
			}
			for (int i = 0; i < array.Length; i++)
			{
				Monitor.Enter(array[i].Lock);
			}
			lock (safeUpdateLock)
			{
				safeUpdateFlag.Reset();
				OnVoidDelegate onSafeCallback = OnSafeCallback;
				OnSafeCallback = null;
				onSafeCallback?.Invoke();
				if (OnThreadSafeCallback != null)
				{
					threadSafeUpdateFlag.Reset();
				}
				else
				{
					threadSafeUpdateFlag.Set();
				}
			}
			threadSafeUpdateState = true;
			threadSafeUpdateFlag.WaitOne();
			doSetQueueState = true;
			pathQueueFlag.Set();
			for (int j = 0; j < array.Length; j++)
			{
				Monitor.Exit(array[j].Lock);
			}
		}
	}

	private static void CalculatePathsThreaded(object _threadInfo)
	{
		Interlocked.Increment(ref numActiveThreads);
		PathThreadInfo pathThreadInfo;
		try
		{
