	public abstract class GraphModifier : MonoBehaviour
	{
		public enum EventType
		{
			PostScan,
			PreScan,
			LatePostScan,
			PreUpdate,
			PostUpdate,
			PostCacheLoad
		}

		private static List<GraphModifier> activeModifiers = new List<GraphModifier>();

		private static int lastLateScanEvent = -9999;

		private static int lastPostCacheEvent = -9999;

		private static List<GraphModifier> GetActiveModifiers()
		{
			if (Application.isPlaying)
			{
				return activeModifiers;
			}
			return new List<GraphModifier>(Object.FindObjectsOfType(typeof(GraphModifier)) as GraphModifier[]);
		}

		public static void TriggerEvent(EventType type)
		{
			List<GraphModifier> list = GetActiveModifiers();
			switch (type)
			{
			case EventType.PreScan:
			{
				for (int l = 0; l < list.Count; l++)
				{
					list[l].OnPreScan();
				}
				break;
			}
			case EventType.PostScan:
			{
				for (int n = 0; n < list.Count; n++)
				{
					list[n].OnPostScan();
				}
				break;
			}
			case EventType.LatePostScan:
			{
				lastLateScanEvent = Time.frameCount;
				for (int j = 0; j < list.Count; j++)
				{
					list[j].OnLatePostScan();
				}
				break;
			}
			case EventType.PreUpdate:
			{
				for (int m = 0; m < list.Count; m++)
				{
					list[m].OnGraphsPreUpdate();
				}
				break;
			}
			case EventType.PostUpdate:
			{
				for (int k = 0; k < list.Count; k++)
				{
					list[k].OnGraphsPostUpdate();
				}
				break;
			}
			case EventType.PostCacheLoad:
			{
				lastPostCacheEvent = Time.frameCount;
				for (int i = 0; i < list.Count; i++)
				{
					list[i].OnPostCacheLoad();
				}
				break;
			}
			}
		}

		public virtual void OnEnable()
		{
			activeModifiers.Add(this);
			if (lastLateScanEvent == Time.frameCount)
			{
				OnLatePostScan();
			}
			if (lastPostCacheEvent == Time.frameCount)
			{
				OnPostCacheLoad();
			}
		}

		public virtual void OnDisable()
		{
			activeModifiers.Remove(this);
		}

		public virtual void OnPostScan()
		{
		}

		public virtual void OnPreScan()
		{
		}

		public virtual void OnLatePostScan()
		{
		}

		public virtual void OnPostCacheLoad()
		{
		}

		public virtual void OnGraphsPreUpdate()
		{
		}

		public virtual void OnGraphsPostUpdate()
		{
		}
	}
	public struct Int3
	{
