namespace Pathfinding.Util
{
	public static class ListPool<T>
	{
		private static List<List<T>> pool;

		static ListPool()
		{
			pool = new List<List<T>>();
		}

		public static List<T> Claim()
		{
			if (pool.Count > 0)
			{
				List<T> result = pool[pool.Count - 1];
				pool.RemoveAt(pool.Count - 1);
				return result;
			}
			return new List<T>();
		}

		public static List<T> Claim(int capacity)
		{
			if (pool.Count > 0)
			{
				List<T> list = pool[pool.Count - 1];
				pool.RemoveAt(pool.Count - 1);
				if (list.Capacity < capacity)
				{
					list.Capacity = capacity;
				}
				return list;
			}
			return new List<T>(capacity);
		}

		public static void Warmup(int count, int size)
		{
			List<T>[] array = new List<T>[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = Claim(size);
			}
			for (int j = 0; j < count; j++)
			{
				Release(array[j]);
			}
		}

		public static void Release(List<T> list)
		{
			for (int i = 0; i < pool.Count; i++)
			{
				if (pool[i] == list)
				{
					throw new InvalidOperationException("The List is released even though it is in the pool");
				}
			}
			list.Clear();
			pool.Add(list);
		}

		public static void Clear()
		{
			pool.Clear();
		}

		public static int GetSize()
		{
			return pool.Count;
		}
	}
}
namespace Pathfinding
{
	public static class PathPool<T> where T : Path, new()
	{
		private static Stack<T> pool;

		private static int totalCreated;

		static PathPool()
		{
			pool = new Stack<T>();
		}

		public static void Recycle(T path)
		{
			lock (pool)
			{
				if ((object)path.GetType() != typeof(T))
				{
					throw new ArgumentException("Cannot recycle path of type '" + path.GetType().Name + "' in a pool for path type '" + typeof(T).Name + "'.\nMost likely the path type does not have support for recycling. Please do not call Recycle () on that path");
				}
				path.recycled = true;
				path.OnEnterPool();
				pool.Push(path);
			}
		}

		public static void Warmup(int count, int length)
		{
			ListPool<Node>.Warmup(count, length);
			ListPool<Vector3>.Warmup(count, length);
			Path[] array = new Path[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = GetPath();
				array[i].Claim(array);
			}
			for (int j = 0; j < count; j++)
			{
				array[j].Release(array);
			}
		}

		public static int GetTotalCreated()
		{
			return totalCreated;
		}

		public static int GetSize()
		{
			return pool.Count;
		}

		public static T GetPath()
		{
			lock (pool)
			{
				T val;
				if (pool.Count > 0)
				{
					val = pool.Pop();
				}
				else
				{
					val = new T();
					totalCreated++;
				}
				val.recycled = false;
				val.Reset();
				return val;
			}
		}
	}
}
namespace Pathfinding.Util
{
	public static class StackPool<T>
	{
		private static List<Stack<T>> pool;

		static StackPool()
		{
			pool = new List<Stack<T>>();
		}

		public static Stack<T> Claim()
		{
			if (pool.Count > 0)
			{
				Stack<T> result = pool[pool.Count - 1];
				pool.RemoveAt(pool.Count - 1);
				return result;
			}
			return new Stack<T>();
		}

		public static void Warmup(int count)
		{
			Stack<T>[] array = new Stack<T>[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = Claim();
			}
			for (int j = 0; j < count; j++)
			{
				Release(array[j]);
			}
		}

		public static void Release(Stack<T> stack)
		{
			for (int i = 0; i < pool.Count; i++)
			{
				if (pool[i] == stack)
				{
					Debug.LogError((object)"The Stack is released even though it is inside the pool");
				}
			}
			stack.Clear();
			pool.Add(stack);
		}

		public static void Clear()
		{
			pool.Clear();
		}

		public static int GetSize()
		{
			return pool.Count;
		}
	}
}
namespace Pathfinding
{
	public class NodeRunData
	{
		public Path path;

		public ushort pathID;

		public NodeRun[] nodes;

		public BinaryHeapM open = new BinaryHeapM(512);

		private StringBuilder stringBuilder = new StringBuilder();

		public StringBuilder DebugStringBuilder => stringBuilder;

		public void Initialize(Path p)
		{
			path = p;
			pathID = p.pathID;
			open.Clear();
		}

		public void ClearPathIDs()
		{
			for (int i = 0; i < nodes.Length; i++)
			{
				if (nodes[i] != null)
				{
					nodes[i].pathID = 0;
				}
			}
		}
	}
	public class NodeRun
	{
		public uint g;

		public uint h;

		public ushort pathID;

		public uint cost;

		public NodeRun parent;

		public Node node { get; set; }

		public uint f => g + h;

		public void Reset()
		{
			g = 0u;
			h = 0u;
			node = null;
			pathID = 0;
			cost = 0u;
			parent = null;
		}

		public void Link(Node node, int index)
		{
			this.node = node;
			if (index != node.GetNodeIndex())
			{
				throw new Exception("Node indices out of sync when creating NodeRun data (node index != specified index)");
			}
		}
	}
	public class Node
	{
		private const int WalkableBitNumber = 23;

		private const int WalkableBit = 8388608;

		private const int AreaBitNumber = 24;

		private const int AreaBitsSize = 255;

		private const int NotAreaBits = 16777215;

		private const int GraphIndexBitNumber = 18;

		private const int GraphIndexBitsSize = 31;

		private const int NotGraphIndexBits = -8126465;

		private int nodeIndex;

		public Int3 position;

		private uint _penalty;

		public Node[] connections;

		public int[] connectionCosts;

		public int flags;

		public uint penalty
		{
			get
			{
				return _penalty;
			}
			set
			{
				if (value > 1048575)
				{
					Debug.LogWarning((object)("Very high penalty applied. Are you sure negative values haven't underflowed?\nPenalty values this high could with long paths cause overflows and in some cases infinity loops because of that.\nPenalty value applied: " + value));
				}
				_penalty = value;
			}
		}

		public int tags
		{
			get
			{
				return (flags >> 9) & 0x1F;
			}
			set
			{
				flags = (flags & -15873) | (value << 9);
			}
		}

		public bool Bit8
		{
			get
			{
				return (flags & 0x100) != 0;
			}
			set
			{
				flags = (flags & -257) | (value ? 256 : 0);
			}
		}

		public bool Bit15
		{
			get
			{
				return ((flags >> 15) & 1) != 0;
			}
			set
			{
				flags = (flags & -32769) | ((value ? 1 : 0) << 15);
			}
		}

		public bool Bit16
		{
			get
			{
				return ((flags >> 16) & 1) != 0;
			}
			set
			{
				flags = (flags & -65537) | ((value ? 1 : 0) << 16);
			}
		}

		public bool walkable
		{
			get
			{
				return (flags & 0x800000) == 8388608;
			}
			set
			{
				flags = (flags & -8388609) | (value ? 8388608 : 0);
			}
		}

		public int area
		{
			get
			{
				return (flags >> 24) & 0xFF;
			}
			set
			{
				flags = (flags & 0xFFFFFF) | (value << 24);
			}
		}

		public int graphIndex
		{
			get
			{
				return (flags >> 18) & 0x1F;
			}
			set
			{
				flags = (flags & -8126465) | ((value & 0x1F) << 18);
			}
		}

		public int GetNodeIndex()
		{
			return nodeIndex;
		}

		public NodeRun GetNodeRun(NodeRunData data)
		{
			return data.nodes[nodeIndex];
		}

		public void SetNodeIndex(int index)
		{
			nodeIndex = index;
		}

		public void UpdateH(Int3 targetPosition, Heuristic heuristic, float scale, NodeRun nodeR)
		{
			switch (heuristic)
			{
			case Heuristic.None:
				nodeR.h = 0u;
				return;
			case Heuristic.Euclidean:
				nodeR.h = (uint)Mathfx.RoundToInt((position - targetPosition).magnitude * scale);
				return;
			case Heuristic.Manhattan:
				nodeR.h = (uint)Mathfx.RoundToInt((float)(Abs(position.x - targetPosition.x) + Abs(position.y - targetPosition.y) + Abs(position.z - targetPosition.z)) * scale);
				return;
			}
			int num = Abs(position.x - targetPosition.x);
			int num2 = Abs(position.z - targetPosition.z);
			if (num > num2)
			{
				nodeR.h = (uint)(14 * num2 + 10 * (num - num2)) / 10u;
			}
			else
			{
				nodeR.h = (uint)(14 * num + 10 * (num2 - num)) / 10u;
			}
			nodeR.h = (uint)Mathfx.RoundToInt((float)nodeR.h * scale);
		}

		public static int Abs(int x)
		{
			return (x >= 0) ? x : (-x);
		}

		public void UpdateG(NodeRun nodeR, NodeRunData nodeRunData)
		{
			nodeR.g = nodeR.parent.g + nodeR.cost + penalty + nodeRunData.path.GetTagPenalty(tags);
		}

		protected void BaseUpdateAllG(NodeRun nodeR, NodeRunData nodeRunData)
		{
			UpdateG(nodeR, nodeRunData);
			nodeRunData.open.Add(nodeR);
			if (connections == null)
			{
				return;
			}
			for (int i = 0; i < connections.Length; i++)
			{
				NodeRun nodeRun = connections[i].GetNodeRun(nodeRunData);
				if (nodeRun.parent == nodeR && nodeRun.pathID == nodeRunData.pathID)
				{
					connections[i].UpdateAllG(nodeRun, nodeRunData);
				}
			}
		}

		public virtual void UpdateAllG(NodeRun nodeR, NodeRunData nodeRunData)
		{
			BaseUpdateAllG(nodeR, nodeRunData);
		}

		public virtual int[] InitialOpen(BinaryHeapM open, Int3 targetPosition, Int3 position, Path path, bool doOpen)
		{
			return BaseInitialOpen(open, targetPosition, position, path, doOpen);
		}

		public int[] BaseInitialOpen(BinaryHeapM open, Int3 targetPosition, Int3 position, Path path, bool doOpen)
		{
			if (connectionCosts == null)
			{
				return null;
			}
			int[] result = connectionCosts;
			connectionCosts = new int[connectionCosts.Length];
			for (int i = 0; i < connectionCosts.Length; i++)
			{
				connectionCosts[i] = (connections[i].position - position).costMagnitude;
			}
			if (!doOpen)
			{
				for (int j = 0; j < connectionCosts.Length; j++)
				{
					Node node = connections[j];
					if (node.connections == null)
					{
						continue;
					}
					for (int k = 0; k < node.connections.Length; k++)
					{
						if (node.connections[k] == this)
						{
							node.connectionCosts[k] = connectionCosts[j];
							break;
						}
					}
				}
			}
			if (doOpen)
			{
				connectionCosts = result;
			}
			return result;
		}

		public virtual void ResetCosts(int[] costs)
		{
			BaseResetCosts(costs);
		}

		public void BaseResetCosts(int[] costs)
		{
			connectionCosts = costs;
			if (connectionCosts == null)
			{
				return;
			}
			for (int i = 0; i < connectionCosts.Length; i++)
			{
				Node node = connections[i];
				if (node.connections == null)
				{
					continue;
				}
				for (int j = 0; j < node.connections.Length; j++)
				{
					if (node.connections[j] == this)
					{
						node.connectionCosts[j] = connectionCosts[i];
						break;
					}
				}
			}
		}

		public virtual void Open(NodeRunData nodeRunData, NodeRun nodeR, Int3 targetPosition, Path path)
		{
			BaseOpen(nodeRunData, nodeR, targetPosition, path);
		}

		public void BaseOpen(NodeRunData nodeRunData, NodeRun nodeR, Int3 targetPosition, Path path)
		{
			if (connections == null)
			{
				return;
			}
			for (int i = 0; i < connections.Length; i++)
			{
				Node node = connections[i];
				if (!path.CanTraverse(node))
				{
					continue;
				}
				NodeRun nodeRun = node.GetNodeRun(nodeRunData);
				if (nodeRun.pathID != nodeRunData.pathID)
				{
					nodeRun.parent = nodeR;
					nodeRun.pathID = nodeRunData.pathID;
					nodeRun.cost = (uint)connectionCosts[i];
					node.UpdateH(targetPosition, path.heuristic, path.heuristicScale, nodeRun);
					node.UpdateG(nodeRun, nodeRunData);
					nodeRunData.open.Add(nodeRun);
					continue;
				}
				uint num = (uint)connectionCosts[i];
				if (nodeR.g + num + node.penalty + path.GetTagPenalty(node.tags) < nodeRun.g)
				{
					nodeRun.cost = num;
					nodeRun.parent = nodeR;
					node.UpdateAllG(nodeRun, nodeRunData);
					nodeRunData.open.Add(nodeRun);
				}
				else if (nodeRun.g + num + penalty + path.GetTagPenalty(tags) < nodeR.g && node.ContainsConnection(this))
				{
					nodeR.parent = nodeRun;
					nodeR.cost = num;
					UpdateAllG(nodeR, nodeRunData);
					nodeRunData.open.Add(nodeR);
				}
			}
		}

		public virtual void GetConnections(NodeDelegate callback)
		{
			GetConnectionsBase(callback);
		}

		public void GetConnectionsBase(NodeDelegate callback)
		{
			if (connections == null)
			{
				return;
			}
			for (int i = 0; i < connections.Length; i++)
			{
				if (connections[i].walkable)
				{
					callback(connections[i]);
				}
			}
		}

		public virtual void FloodFill(Stack<Node> stack, int area)
		{
			BaseFloodFill(stack, area);
		}

		public void BaseFloodFill(Stack<Node> stack, int area)
		{
			if (connections == null)
			{
				return;
			}
			for (int i = 0; i < connections.Length; i++)
			{
				if (connections[i].walkable && connections[i].area != area)
				{
					stack.Push(connections[i]);
					connections[i].area = area;
				}
			}
		}

		public virtual void UpdateConnections()
		{
			if (connections == null)
			{
				return;
			}
			List<Node> list = null;
			List<int> list2 = null;
			for (int i = 0; i < connections.Length; i++)
			{
				if (!connections[i].walkable)
				{
					if (list == null)
					{
						list = new List<Node>(connections.Length - 1);
						list2 = new List<int>(connections.Length - 1);
						for (int j = 0; j < i; j++)
						{
							list.Add(connections[j]);
							list2.Add(connectionCosts[j]);
						}
					}
				}
				else if (list != null)
				{
					list.Add(connections[i]);
					list2.Add(connectionCosts[i]);
				}
			}
		}

		public virtual void UpdateNeighbourConnections()
		{
			if (connections != null)
			{
				for (int i = 0; i < connections.Length; i++)
				{
					connections[i].UpdateConnections();
				}
			}
		}

		public virtual bool ContainsConnection(Node node)
		{
			if (connections != null)
			{
				for (int i = 0; i < connections.Length; i++)
				{
					if (connections[i] == node)
					{
						return true;
					}
				}
			}
			return false;
		}

		public void AddConnection(Node node, int cost)
		{
			if (connections == null)
			{
				connections = new Node[0];
				connectionCosts = new int[0];
			}
			else
			{
				for (int i = 0; i < connections.Length; i++)
				{
					if (connections[i] == node)
					{
						connectionCosts[i] = cost;
						return;
					}
				}
			}
			Node[] array = connections;
			int[] array2 = connectionCosts;
			connections = new Node[connections.Length + 1];
			connectionCosts = new int[connections.Length];
			for (int j = 0; j < array.Length; j++)
			{
				connections[j] = array[j];
				connectionCosts[j] = array2[j];
			}
			connections[array.Length] = node;
			connectionCosts[array.Length] = cost;
		}

		public virtual bool RemoveConnection(Node node)
		{
			if (connections == null)
			{
				return false;
			}
			for (int i = 0; i < connections.Length; i++)
			{
				if (connections[i] == node)
				{
					connections[i] = connections[connections.Length - 1];
					connectionCosts[i] = connectionCosts[connectionCosts.Length - 1];
					Node[] array = new Node[connections.Length - 1];
					int[] array2 = new int[connections.Length - 1];
					for (int j = 0; j < connections.Length - 1; j++)
					{
						array[j] = connections[j];
						array2[j] = connectionCosts[j];
					}
					connections = array;
					connectionCosts = array2;
					return true;
				}
			}
			return false;
		}

		public void RecalculateConnectionCosts(bool neighbours)
		{
			for (int i = 0; i < connections.Length; i++)
			{
				connectionCosts[i] = (int)Math.Round((position - connections[i].position).magnitude);
			}
			if (neighbours)
			{
				for (int j = 0; j < connections.Length; j++)
				{
					connections[j].RecalculateConnectionCosts(neighbours: false);
				}
			}
		}
	}
}
