				if (num16 >= -1E-45f && num17 >= -1E-45f)
				{
					list.Add(obstacleVertex4);
					continue;
				}
				if (num16 <= float.Epsilon && num17 <= float.Epsilon)
				{
					list2.Add(obstacleVertex4);
					continue;
				}
				float num18 = Polygon.IntersectionFactor(obstacleVertex4.position, next4.position, obstacleVertex3.position, next3.position);
				Vector3 position = obstacleVertex4.position + (next4.position - obstacleVertex4.position) * num18;
				ObstacleVertex obstacleVertex5 = new ObstacleVertex();
				obstacleVertex5.position = position;
				obstacleVertex4.next = obstacleVertex5;
				obstacleVertex5.prev = obstacleVertex4;
				obstacleVertex5.next = next4;
				next4.prev = obstacleVertex5;
				obstacleVertex5.dir = obstacleVertex4.dir;
				obstacleVertex5.split = true;
				obstacleVertex5.convex = true;
				if (num16 > 0f)
				{
					list.Add(obstacleVertex4);
					list2.Add(obstacleVertex5);
				}
				else
				{
					list2.Add(obstacleVertex4);
					list.Add(obstacleVertex5);
				}
			}
			ListPool<ObstacleVertex>.Release(obstacles);
			oTN.obstacle = obstacleVertex3;
			oTN.left = BuildObstacleTreeRecursive(list);
			oTN.right = BuildObstacleTreeRecursive(list2);
			return oTN;
		}

		public void GetAgentNeighbours(Agent agent, float rangeSq)
		{
			QueryAgentTreeRecursive(agent, ref rangeSq, 0);
		}

		public void GetObstacleNeighbours(Agent agent, float rangeSq)
		{
			QueryObstacleTreeRecursive(agent, rangeSq, obstacleRoot);
		}

		private float Sqr(float v)
		{
			return v * v;
		}

		private void QueryAgentTreeRecursive(Agent agent, ref float rangeSq, int node)
		{
			if (agentTree[node].end - agentTree[node].start <= 10)
			{
				for (int i = agentTree[node].start; i < agentTree[node].end; i++)
				{
					rangeSq = agent.InsertAgentNeighbour(agents[i], rangeSq);
				}
				return;
			}
			float num = Sqr(Math.Max(0f, agentTree[agentTree[node].left].xmin - agent.position.x)) + Sqr(Math.Max(0f, agent.position.x - agentTree[agentTree[node].left].xmax)) + Sqr(Math.Max(0f, agentTree[agentTree[node].left].ymin - agent.position.z)) + Sqr(Math.Max(0f, agent.position.z - agentTree[agentTree[node].left].ymax));
			float num2 = Sqr(Math.Max(0f, agentTree[agentTree[node].right].xmin - agent.position.x)) + Sqr(Math.Max(0f, agent.position.x - agentTree[agentTree[node].right].xmax)) + Sqr(Math.Max(0f, agentTree[agentTree[node].right].ymin - agent.position.z)) + Sqr(Math.Max(0f, agent.position.z - agentTree[agentTree[node].right].ymax));
			if (num < num2)
			{
				if (num < rangeSq)
				{
					QueryAgentTreeRecursive(agent, ref rangeSq, agentTree[node].left);
					if (num2 < rangeSq)
					{
						QueryAgentTreeRecursive(agent, ref rangeSq, agentTree[node].right);
					}
				}
			}
			else if (num2 < rangeSq)
			{
				QueryAgentTreeRecursive(agent, ref rangeSq, agentTree[node].right);
				if (num < rangeSq)
				{
					QueryAgentTreeRecursive(agent, ref rangeSq, agentTree[node].left);
				}
			}
		}

		private void QueryObstacleTreeRecursive(Agent agent, float rangeSq, ObstacleTreeNode node)
		{
			//IL_0016: Unknown result type (might be due to invalid IL or missing references)
			//IL_001c: Unknown result type (might be due to invalid IL or missing references)
			//IL_0022: Unknown result type (might be due to invalid IL or missing references)
			//IL_0052: Unknown result type (might be due to invalid IL or missing references)
			//IL_0058: Unknown result type (might be due to invalid IL or missing references)
			//IL_005d: Unknown result type (might be due to invalid IL or missing references)
			//IL_0062: Unknown result type (might be due to invalid IL or missing references)
			if (node == null)
			{
				return;
			}
			ObstacleVertex obstacle = node.obstacle;
			ObstacleVertex next = obstacle.next;
			float num = Polygon.TriangleArea(obstacle.position, next.position, agent.position);
			QueryObstacleTreeRecursive(agent, rangeSq, (!(num >= 0f)) ? node.right : node.left);
			Vector3 val = obstacle.position - next.position;
			val.y = 0f;
			float num2 = Sqr(num) / ((Vector3)(ref val)).sqrMagnitude;
			if (num2 < rangeSq)
			{
				if (num < 0f)
				{
					agent.InsertObstacleNeighbour(node.obstacle, rangeSq);
				}
				QueryObstacleTreeRecursive(agent, rangeSq, (!(num >= 0f)) ? node.left : node.right);
			}
		}

		private static ObstacleTreeNode GetOTN()
		{
			if (OTNPool.Count > 0)
			{
				return OTNPool.Pop();
			}
			return new ObstacleTreeNode();
		}

		private static void RecycleOTN(ObstacleTreeNode node)
		{
			if (node != null)
			{
				OTNPool.Push(node);
				node.obstacle = null;
				RecycleOTN(node.left);
				RecycleOTN(node.right);
			}
		}
	}
