		public void Sort(int[] a, byte[] b)
		{
			bool flag = true;
			while (flag)
			{
				flag = false;
				for (int i = 0; i < a.Length - 1; i++)
				{
					if (a[i] > a[i + 1])
					{
						int num = a[i];
						a[i] = a[i + 1];
						a[i + 1] = num;
						byte b2 = b[i];
						b[i] = b[i + 1];
						b[i + 1] = b2;
						flag = true;
					}
				}
			}
		}

		public void SaveToFile(string path, byte[] data)
		{
			FileStream fileStream = File.Create(path);
			fileStream.Write(data, 0, data.Length);
			fileStream.Close();
		}

		public byte[] LoadFromFile(string path)
		{
			if (!File.Exists(path))
			{
				error = SerializerError.DoesNotExist;
				Debug.LogError((object)("File does not exist : " + path));
				return new byte[0];
			}
			FileStream fileStream = File.Open(path, FileMode.Open);
			byte[] array = new byte[fileStream.Length];
			fileStream.Read(array, 0, array.Length);
			fileStream.Close();
			return array;
		}

		public static void TestLoadFile(string path)
		{
			FileStream fileStream = File.Open(path, FileMode.Open);
			fileStream.Close();
		}
