	public class AstarSerializer
	{
		private const string jsonExt = ".json";

		private const string binaryExt = ".binary";

		private AstarData data;

		public JsonWriterSettings writerSettings;

		public JsonReaderSettings readerSettings;

		private ZipFile zip;

		private MemoryStream str;

		private GraphMeta meta;

		private SerializeSettings settings;

		private NavGraph[] graphs;

		private uint checksum = uint.MaxValue;

		private UTF8Encoding encoding = new UTF8Encoding();

		private static StringBuilder _stringBuilder = new StringBuilder();

		public AstarSerializer(AstarData data)
		{
			this.data = data;
			settings = SerializeSettings.Settings;
		}

		public AstarSerializer(AstarData data, SerializeSettings settings)
		{
			this.data = data;
			this.settings = settings;
		}

		private static StringBuilder GetStringBuilder()
		{
			_stringBuilder.Length = 0;
			return _stringBuilder;
		}

		public void AddChecksum(byte[] bytes)
		{
			checksum = Checksum.GetChecksum(bytes, checksum);
		}

		public uint GetChecksum()
		{
			return checksum;
		}

		public void OpenSerialize()
		{
			//IL_0001: Unknown result type (might be due to invalid IL or missing references)
			//IL_000b: Expected O, but got Unknown
			//IL_0028: Unknown result type (might be due to invalid IL or missing references)
			//IL_0032: Expected O, but got Unknown
			zip = new ZipFile();
			zip.AlternateEncoding = Encoding.UTF8;
			zip.AlternateEncodingUsage = (ZipOption)2;
			writerSettings = new JsonWriterSettings();
			writerSettings.AddTypeConverter((JsonConverter)(object)new VectorConverter());
			writerSettings.AddTypeConverter((JsonConverter)(object)new BoundsConverter());
			writerSettings.AddTypeConverter((JsonConverter)(object)new LayerMaskConverter());
			writerSettings.AddTypeConverter((JsonConverter)(object)new MatrixConverter());
			writerSettings.AddTypeConverter((JsonConverter)(object)new GuidConverter());
			writerSettings.AddTypeConverter((JsonConverter)(object)new UnityObjectConverter());
			writerSettings.PrettyPrint = settings.prettyPrint;
			meta = new GraphMeta();
		}

		public byte[] CloseSerialize()
		{
			byte[] array = SerializeMeta();
			AddChecksum(array);
			zip.AddEntry("meta.json", array);
			MemoryStream memoryStream = new MemoryStream();
			zip.Save((Stream)memoryStream);
			memoryStream.Close();
			array = memoryStream.ToArray();
			zip.Dispose();
			zip = null;
			return array;
		}

		public void SerializeGraphs(NavGraph[] _graphs)
		{
			if (graphs != null)
			{
				throw new InvalidOperationException("Cannot serialize graphs multiple times.");
			}
			graphs = _graphs;
			if (zip == null)
			{
				throw new NullReferenceException("You must not call CloseSerialize before a call to this function");
			}
			if (graphs == null)
			{
				graphs = new NavGraph[0];
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				byte[] array = Serialize(graphs[i]);
				AddChecksum(array);
				zip.AddEntry("graph" + i + ".json", array);
			}
		}

		public void SerializeUserConnections(UserConnection[] conns)
		{
			//IL_001b: Unknown result type (might be due to invalid IL or missing references)
			//IL_0021: Expected O, but got Unknown
			if (conns == null)
			{
				conns = new UserConnection[0];
			}
			StringBuilder stringBuilder = GetStringBuilder();
			JsonWriter val = new JsonWriter(stringBuilder, writerSettings);
			val.Write((object)conns);
			byte[] bytes = encoding.GetBytes(stringBuilder.ToString());
			stringBuilder = null;
			if (bytes.Length > 2)
			{
				AddChecksum(bytes);
				zip.AddEntry("connections.json", bytes);
			}
		}

		private byte[] SerializeMeta()
		{
			//IL_0133: Unknown result type (might be due to invalid IL or missing references)
			//IL_0139: Expected O, but got Unknown
			meta.version = AstarPath.Version;
			meta.graphs = data.graphs.Length;
			meta.guids = new string[data.graphs.Length];
			meta.typeNames = new string[data.graphs.Length];
			meta.nodeCounts = new int[data.graphs.Length];
			for (int i = 0; i < data.graphs.Length; i++)
			{
				meta.guids[i] = data.graphs[i].guid.ToString();
				meta.typeNames[i] = data.graphs[i].GetType().FullName;
				meta.nodeCounts[i] = ((data.graphs[i].nodes != null) ? data.graphs[i].nodes.Length : 0);
			}
			StringBuilder stringBuilder = GetStringBuilder();
			JsonWriter val = new JsonWriter(stringBuilder, writerSettings);
			val.Write((object)meta);
			return encoding.GetBytes(stringBuilder.ToString());
		}

		public byte[] Serialize(NavGraph graph)
		{
			//IL_000d: Unknown result type (might be due to invalid IL or missing references)
			//IL_0013: Expected O, but got Unknown
			StringBuilder stringBuilder = GetStringBuilder();
			JsonWriter val = new JsonWriter(stringBuilder, writerSettings);
			val.Write((object)graph);
			return encoding.GetBytes(stringBuilder.ToString());
		}

		public void SerializeNodes()
		{
			if (settings.nodes)
			{
				if (graphs == null)
				{
					throw new InvalidOperationException("Cannot serialize nodes with no serialized graphs (call SerializeGraphs first)");
				}
				for (int i = 0; i < graphs.Length; i++)
				{
					byte[] array = SerializeNodes(i);
					AddChecksum(array);
					zip.AddEntry("graph" + i + "_nodes.binary", array);
				}
				for (int j = 0; j < graphs.Length; j++)
				{
					byte[] array2 = SerializeNodeConnections(j);
					AddChecksum(array2);
					zip.AddEntry("graph" + j + "_conns.binary", array2);
				}
			}
		}

		private byte[] SerializeNodes(int index)
		{
			NavGraph navGraph = graphs[index];
			MemoryStream memoryStream = new MemoryStream();
			BinaryWriter binaryWriter = new BinaryWriter(memoryStream);
			Node[] array = navGraph.nodes;
			if (array == null)
			{
				array = new Node[0];
			}
			binaryWriter.Write(1);
			foreach (Node node in array)
			{
				if (node == null)
				{
					binaryWriter.Write(0);
					binaryWriter.Write(0);
					binaryWriter.Write(0);
				}
				else
				{
					binaryWriter.Write(node.position.x);
					binaryWriter.Write(node.position.y);
					binaryWriter.Write(node.position.z);
				}
			}
			binaryWriter.Write(2);
			for (int j = 0; j < array.Length; j++)
			{
				if (array[j] == null)
				{
					binaryWriter.Write(0);
				}
				else
				{
					binaryWriter.Write(array[j].penalty);
				}
			}
			binaryWriter.Write(3);
			for (int k = 0; k < array.Length; k++)
			{
				if (array[k] == null)
				{
					binaryWriter.Write(0);
				}
				else
				{
					binaryWriter.Write(array[k].flags);
				}
			}
			binaryWriter.Close();
			return memoryStream.ToArray();
		}

		public void SerializeExtraInfo()
		{
			if (!settings.nodes)
			{
				return;
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				byte[] array = graphs[i].SerializeExtraInfo();
				if (array != null)
				{
					AddChecksum(array);
					zip.AddEntry("graph" + i + "_extra.binary", array);
				}
			}
		}

		private byte[] SerializeNodeConnections(int index)
		{
			NavGraph navGraph = graphs[index];
			MemoryStream memoryStream = new MemoryStream();
			BinaryWriter binaryWriter = new BinaryWriter(memoryStream);
			if (navGraph.nodes == null)
			{
				return new byte[0];
			}
			Node[] nodes = navGraph.nodes;
			for (int i = 0; i < nodes.Length; i++)
			{
				Node node = nodes[i];
				if (node.connections == null)
				{
					binaryWriter.Write((ushort)0);
					continue;
				}
				if (node.connections.Length != node.connectionCosts.Length)
				{
					throw new IndexOutOfRangeException("Node.connections.Length != Node.connectionCosts.Length. In node " + i + " in graph " + index);
				}
				binaryWriter.Write((ushort)node.connections.Length);
				for (int j = 0; j < node.connections.Length; j++)
				{
					binaryWriter.Write(node.connections[j].GetNodeIndex());
					binaryWriter.Write(node.connectionCosts[j]);
				}
			}
			binaryWriter.Close();
			return memoryStream.ToArray();
		}

		public bool OpenDeserialize(byte[] bytes)
		{
			//IL_0001: Unknown result type (might be due to invalid IL or missing references)
			//IL_000b: Expected O, but got Unknown
			//IL_00aa: Expected O, but got Unknown
			readerSettings = new JsonReaderSettings();
			readerSettings.AddTypeConverter((JsonConverter)(object)new VectorConverter());
			readerSettings.AddTypeConverter((JsonConverter)(object)new BoundsConverter());
			readerSettings.AddTypeConverter((JsonConverter)(object)new LayerMaskConverter());
			readerSettings.AddTypeConverter((JsonConverter)(object)new MatrixConverter());
			readerSettings.AddTypeConverter((JsonConverter)(object)new GuidConverter());
			readerSettings.AddTypeConverter((JsonConverter)(object)new UnityObjectConverter());
			str = new MemoryStream();
			str.Write(bytes, 0, bytes.Length);
			str.Position = 0L;
			try
			{
				zip = ZipFile.Read((Stream)str);
			}
			catch (ZipException ex)
			{
				ZipException ex2 = ex;
				Debug.LogWarning((object)("Caught exception when loading from zip\n" + ex2));
				str.Close();
				return false;
			}
			meta = DeserializeMeta(zip["meta.json"]);
			if (meta.version > AstarPath.Version)
			{
				Debug.LogWarning((object)string.Concat("Trying to load data from a newer version of the A* Pathfinding Project\nCurrent version: ", AstarPath.Version, " Data version: ", meta.version));
			}
			else if (meta.version < AstarPath.Version)
			{
