					int num2 = reader.ReadInt32();
					node.connections[j] = GetNodeWithIndex(index2);
					node.connectionCosts[j] = num2;
				}
			}
		}

		public Node GetNodeWithIndex(int index)
		{
			if (graphs == null)
			{
				throw new InvalidOperationException("Cannot find node with index because graphs have not been serialized/deserialized yet");
			}
			for (int i = 0; i < graphs.Length; i++)
			{
				if (graphs[i].nodes.Length > index)
				{
					return graphs[i].nodes[index];
				}
				index -= graphs[i].nodes.Length;
			}
			Debug.LogError((object)("Could not find node with index " + index));
			return null;
		}

		private string GetString(ZipEntry entry)
		{
			MemoryStream memoryStream = new MemoryStream();
			entry.Extract((Stream)memoryStream);
			memoryStream.Position = 0L;
			StreamReader streamReader = new StreamReader(memoryStream);
			string result = streamReader.ReadToEnd();
			memoryStream.Position = 0L;
			streamReader.Close();
			return result;
		}

