	public struct IntRect
	{
		public int xmin;

		public int ymin;

		public int xmax;

		public int ymax;

		public IntRect(int xmin, int ymin, int xmax, int ymax)
		{
			this.xmin = xmin;
			this.xmax = xmax;
			this.ymin = ymin;
			this.ymax = ymax;
		}

		public bool Contains(int x, int y)
		{
			return x >= xmin && y >= ymin && x <= xmax && y <= ymax;
		}

		public bool IsValid()
		{
			return xmin <= xmax && ymin <= ymax;
		}

