				{
				}
				return;
			}
			for (int i = 0; i < nodes.Length; i++)
			{
				Node node = nodes[i];
				if (node.connections == null)
				{
					continue;
				}
				Gizmos.color = NodeColor(node, AstarPath.active.debugPathData);
				if (AstarPath.active.showSearchTree && !InSearchTree(node, AstarPath.active.debugPath))
				{
					break;
				}
