									break;
								}
							}
							if (flag)
							{
								gridNode.walkable = false;
							}
						}
					}
					for (int m = zmin; m < zmax; m++)
					{
						for (int n = xmin; n < xmax; n++)
						{
							GridNode node = nodes[m * width + n] as GridNode;
							CalculateConnections(nodes, n, m, node);
						}
