				}
				return;
			}
			if (erodeIterations + erosionFirstTag > 31)
			{
				Debug.LogError((object)("Too few tags available for " + erodeIterations + " erode iterations and starting with tag " + erosionFirstTag + " (erodeIterations+erosionFirstTag > 31)"));
