			Node[] nodes = layerGridGraph.nodes;
			int index = GetIndex();
			for (int i = 0; i < 4; i++)
			{
				int connectionValue = GetConnectionValue(i);
				if (connectionValue == 255)
				{
					continue;
				}
				Node node = nodes[index + neighbourOffsets[i] + layerGridGraph.width * layerGridGraph.depth * connectionValue];
