		public static void RemoveGridGraph(LayerGridGraph graph)
		{
			if (gridGraphs == null)
			{
				return;
			}
			for (int i = 0; i < gridGraphs.Length; i++)
			{
				if (gridGraphs[i] != graph)
				{
					continue;
				}
				if (gridGraphs.Length == 1)
				{
					gridGraphs = null;
					break;
				}
				for (int j = i + 1; j < gridGraphs.Length; j++)
				{
					LayerGridGraph layerGridGraph = gridGraphs[j];
					if (layerGridGraph.nodes != null)
					{
						for (int k = 0; k < layerGridGraph.nodes.Length; k++)
						{
							((LevelGridNode)layerGridGraph.nodes[k]).SetGridIndex(j - 1);
						}
					}
				}
				LayerGridGraph[] array = new LayerGridGraph[gridGraphs.Length - 1];
				for (int l = 0; l < i; l++)
				{
					array[l] = gridGraphs[l];
				}
				for (int m = i + 1; m < gridGraphs.Length; m++)
				{
					array[m - 1] = gridGraphs[m];
				}
				break;
			}
		}

