			List<int> list2 = new List<int>();
			list.AddRange(node.connections);
			list2.AddRange(node.connectionCosts);
			Node node2 = navGraph.nodes[num];
			list.Add(node2);
			list2.Add((node.position - node2.position).costMagnitude);
