			for (int i = 0; i < nodes.Length; i++)
			{
				if (!(nodes[i] is MeshNode meshNode))
				{
					Debug.LogError((object)"Serialization Error : Couldn't cast the node to the appropriate type - NavMeshGenerator");
					return;
				}
				meshNode.v1 = binaryReader.ReadInt32();
				meshNode.v2 = binaryReader.ReadInt32();
				meshNode.v3 = binaryReader.ReadInt32();
			}
			int num = binaryReader.ReadInt32();
			graph.vertices = new Int3[num];
			for (int j = 0; j < num; j++)
			{
				int x = binaryReader.ReadInt32();
				int y = binaryReader.ReadInt32();
				int z = binaryReader.ReadInt32();
				ref Int3 reference = ref graph.vertices[j];
				reference = new Int3(x, y, z);
			}
