		}
		for (int num22 = num - voxelArea.width; num22 >= 0; num22 -= voxelArea.width)
		{
			for (int num23 = voxelArea.width - 1; num23 >= 0; num23--)
			{
				CompactVoxelCell compactVoxelCell3 = voxelArea.compactCells[num23 + num22];
				int num24 = (int)compactVoxelCell3.index;
				for (int num25 = (int)(compactVoxelCell3.index + compactVoxelCell3.count); num24 < num25; num24++)
				{
					CompactVoxelSpan compactVoxelSpan5 = voxelArea.compactSpans[num24];
					if (compactVoxelSpan5.GetConnection(2) != NotConnected)
					{
