		{
			if (hasEndPoint && startNode == endNode)
			{
				NodeRun nodeRun = endNode.GetNodeRun(runData);
				nodeRun.parent = null;
				nodeRun.h = 0u;
				nodeRun.g = 0u;
				Trace(nodeRun);
				base.CompleteState = PathCompleteState.Complete;
				return;
			}
			NodeRun nodeRun2 = startNode.GetNodeRun(runData);
			nodeRun2.pathID = pathID;
			nodeRun2.parent = null;
			nodeRun2.cost = 0u;
			nodeRun2.g = startNode.penalty;
			startNode.UpdateH(hTarget, heuristic, heuristicScale, nodeRun2);
			startNode.Open(runData, nodeRun2, hTarget, this);
			searchedNodes++;
			partialBestTarget = nodeRun2;
			if (runData.open.numberOfItems <= 1)
			{
				if (!calculatePartial)
				{
					Error();
					LogError("No open points, the start node didn't open any nodes");
