		public override void Initialize()
		{
			for (int i = 0; i < targetNodes.Length; i++)
			{
				if (startNode == targetNodes[i])
				{
					FoundTarget(startNode.GetNodeRun(runData), i);
				}
				else
				{
					targetNodes[i].Bit8 = true;
				}
			}
			AstarPath.OnPathPostSearch = (OnPathDelegate)Delegate.Combine(AstarPath.OnPathPostSearch, new OnPathDelegate(ResetBit8));
			if (targetNodeCount <= 0)
			{
				base.CompleteState = PathCompleteState.Complete;
				return;
			}
			NodeRun nodeRun = startNode.GetNodeRun(runData);
			nodeRun.pathID = pathID;
			nodeRun.parent = null;
			nodeRun.cost = 0u;
			nodeRun.g = startNode.penalty;
			startNode.UpdateH(hTarget, heuristic, heuristicScale, nodeRun);
			startNode.Open(runData, nodeRun, hTarget, this);
			searchedNodes++;
			if (runData.open.numberOfItems <= 1)
			{
				LogError("No open points, the start node didn't open any nodes");
			}
			else
			{
				currentR = runData.open.Remove();
			}
		}

		public void ResetBit8(Path p)
		{
			AstarPath.OnPathPostSearch = (OnPathDelegate)Delegate.Remove(AstarPath.OnPathPostSearch, new OnPathDelegate(ResetBit8));
			if (p != this)
			{
				Debug.LogError((object)"This should have been cleared after it was called on 'this' path. Was it not called? Or did the delegate reset not work?");
			}
			for (int i = 0; i < targetNodes.Length; i++)
			{
				targetNodes[i].Bit8 = false;
			}
		}

