namespace Pathfinding.Threading
{
	public class Parallel
	{
		public delegate void ForLoopBody(int i);

		private Parallel Instance;

		private AutoResetEvent[] jobAvailable;

		private ManualResetEvent[] threadIdle;

		private Thread[] threads;

		private static object sync = new object();

		private int currentIndex;

		private int stopIndex;

		private int step = 1;

		private ForLoopBody loopBody;

		public static int threadsCount = Environment.ProcessorCount;

		public static int iterationStepLength = 10;

		private void Initialize()
		{
			threadsCount = Environment.ProcessorCount;
			if (threadsCount > 1)
			{
				jobAvailable = new AutoResetEvent[threadsCount];
				threadIdle = new ManualResetEvent[threadsCount];
				threads = new Thread[threadsCount];
				for (int i = 0; i < threadsCount; i++)
				{
					jobAvailable[i] = new AutoResetEvent(initialState: false);
					threadIdle[i] = new ManualResetEvent(initialState: true);
					threads[i] = new Thread(WorkerThread);
					threads[i].IsBackground = false;
					threads[i].Start(i);
				}
			}
		}

		public void Close()
		{
			loopBody = null;
			for (int i = 0; i < threadsCount; i++)
			{
				jobAvailable[i].Set();
			}
		}

		public static void For(int start, int stop, ForLoopBody loopBody)
		{
			For(start, stop, 1, loopBody);
		}

		public static void For(int start, int stop, int stepLength, ForLoopBody loopBody)
		{
			For(start, stop, stepLength, loopBody, close: true);
		}

		public static void For(int start, int stop, int stepLength, ForLoopBody loopBody, bool close)
		{
			Parallel parallel = new Parallel();
			parallel.Initialize();
			parallel.ForLoop(start, stop, stepLength, loopBody, close);
		}

		public void ForLoop(int start, int stop, int stepLength, ForLoopBody loopBody, bool close)
		{
			lock (sync)
			{
				stepLength = ((stepLength < 1) ? 1 : stepLength);
				currentIndex = start;
				stopIndex = stop;
				this.loopBody = loopBody;
				step = stepLength;
				if (threadsCount <= 1)
				{
					for (int i = start; i < stop; i += stepLength)
					{
						loopBody(i);
					}
					return;
				}
				for (int j = 0; j < threadsCount; j++)
				{
					threadIdle[j].Reset();
					jobAvailable[j].Set();
				}
				for (int k = 0; k < threadsCount; k++)
				{
					threadIdle[k].WaitOne();
				}
				if (close)
				{
					Close();
				}
			}
		}

		private void WorkerThread(object index)
		{
			int num = (int)index;
			int num2 = 0;
			while (true)
			{
				jobAvailable[num].WaitOne();
				if (loopBody == null)
				{
					break;
				}
				bool flag;
				do
				{
					num2 = Interlocked.Add(ref currentIndex, iterationStepLength * step);
					int num3 = num2 - iterationStepLength * step;
					flag = false;
					if (num2 >= stopIndex)
					{
						flag = true;
						num2 = stopIndex;
					}
					for (int i = num3; i < num2; i += step)
					{
						loopBody(i);
					}
				}
				while (!flag);
				threadIdle[num].Set();
			}
		}
	}
}
public class AstarProfiler
{
	public struct ProfilePoint
	{
		public DateTime lastRecorded;

		public TimeSpan totalTime;

		public int totalCalls;
	}

	private static Dictionary<string, ProfilePoint> profiles = new Dictionary<string, ProfilePoint>();

	private static DateTime startTime = DateTime.UtcNow;

	public static ProfilePoint[] fastProfiles;

	public static string[] fastProfileNames;

	private AstarProfiler()
	{
	}

	[Conditional("ProfileAstar")]
	public static void InitializeFastProfile(string[] profileNames)
	{
		fastProfileNames = profileNames;
		fastProfiles = new ProfilePoint[profileNames.Length];
	}

	[Conditional("ProfileAstar")]
	public static void StartFastProfile(int tag)
	{
		fastProfiles[tag].lastRecorded = DateTime.UtcNow;
	}

	[Conditional("ProfileAstar")]
	public static void EndFastProfile(int tag)
	{
		DateTime utcNow = DateTime.UtcNow;
		ProfilePoint profilePoint = fastProfiles[tag];
		profilePoint.totalTime += utcNow - profilePoint.lastRecorded;
		profilePoint.totalCalls++;
		fastProfiles[tag] = profilePoint;
	}

	[Conditional("UNITY_PRO_PROFILER")]
	public static void EndProfile()
	{
	}

	[Conditional("ProfileAstar")]
	public static void StartProfile(string tag)
	{
		profiles.TryGetValue(tag, out var value);
		value.lastRecorded = DateTime.UtcNow;
		profiles[tag] = value;
	}

	[Conditional("ProfileAstar")]
	public static void EndProfile(string tag)
	{
		if (!profiles.ContainsKey(tag))
		{
			Debug.LogError((object)("Can only end profiling for a tag which has already been started (tag was " + tag + ")"));
			return;
		}
		DateTime utcNow = DateTime.UtcNow;
		ProfilePoint value = profiles[tag];
		value.totalTime += utcNow - value.lastRecorded;
		value.totalCalls++;
		profiles[tag] = value;
	}

	[Conditional("ProfileAstar")]
	public static void Reset()
	{
		profiles.Clear();
		startTime = DateTime.UtcNow;
		if (fastProfiles != null)
		{
			for (int i = 0; i < fastProfiles.Length; i++)
			{
				fastProfiles[i] = default(ProfilePoint);
			}
		}
	}

	[Conditional("ProfileAstar")]
	public static void PrintFastResults()
	{
		TimeSpan timeSpan = DateTime.UtcNow - startTime;
		StringBuilder stringBuilder = new StringBuilder();
		stringBuilder.Append("============================\n\t\t\t\tProfile results:\n============================\n");
		stringBuilder.Append("Name\t\t|\tTotal Time\t|\tTotal Calls\t|\tAvg/Call\t");
		for (int i = 0; i < fastProfiles.Length; i++)
		{
			string text = fastProfileNames[i];
			ProfilePoint profilePoint = fastProfiles[i];
			double totalMilliseconds = profilePoint.totalTime.TotalMilliseconds;
			int totalCalls = profilePoint.totalCalls;
			if (totalCalls >= 1)
			{
				stringBuilder.Append("\n").Append(text.PadLeft(10)).Append("|   ");
				stringBuilder.Append(totalMilliseconds.ToString("0.0").PadLeft(10)).Append("|   ");
				stringBuilder.Append(totalCalls.ToString().PadLeft(10)).Append("|   ");
				stringBuilder.Append((totalMilliseconds / (double)totalCalls).ToString("0.000").PadLeft(10));
			}
		}
		stringBuilder.Append("\n\n============================\n\t\tTotal runtime: ");
		stringBuilder.Append(timeSpan.TotalSeconds.ToString("F3"));
		stringBuilder.Append(" seconds\n============================");
		Debug.Log((object)stringBuilder.ToString());
	}

	[Conditional("ProfileAstar")]
	public static void PrintResults()
	{
		TimeSpan timeSpan = DateTime.UtcNow - startTime;
		StringBuilder stringBuilder = new StringBuilder();
		stringBuilder.Append("============================\n\t\t\t\tProfile results:\n============================\n");
		int num = 5;
		foreach (KeyValuePair<string, ProfilePoint> profile in profiles)
		{
			num = Math.Max(profile.Key.Length, num);
		}
		stringBuilder.Append(" Name ".PadRight(num)).Append("|").Append(" Total Time\t".PadRight(20))
			.Append("|")
			.Append(" Total Calls ".PadRight(20))
			.Append("|")
			.Append(" Avg/Call ".PadRight(20));
		foreach (KeyValuePair<string, ProfilePoint> profile2 in profiles)
		{
			double totalMilliseconds = profile2.Value.totalTime.TotalMilliseconds;
			int totalCalls = profile2.Value.totalCalls;
			if (totalCalls >= 1)
			{
				string key = profile2.Key;
				stringBuilder.Append("\n").Append(key.PadRight(num)).Append("| ");
				stringBuilder.Append(totalMilliseconds.ToString("0.0").PadRight(20)).Append("| ");
				stringBuilder.Append(totalCalls.ToString().PadRight(20)).Append("| ");
				stringBuilder.Append((totalMilliseconds / (double)totalCalls).ToString("0.000").PadRight(20));
			}
		}
		stringBuilder.Append("\n\n============================\n\t\tTotal runtime: ");
		stringBuilder.Append(timeSpan.TotalSeconds.ToString("F3"));
		stringBuilder.Append(" seconds\n============================");
		Debug.Log((object)stringBuilder.ToString());
	}
