namespace Pathfinding
{
	public static class GraphUpdateUtilities
	{
		[Obsolete("This function has been moved to Pathfinding.Util.PathUtilities. Please use the version in that class")]
		public static bool IsPathPossible(Node n1, Node n2)
		{
			return n1.walkable && n2.walkable && n1.area == n2.area;
		}

		[Obsolete("This function has been moved to Pathfinding.Util.PathUtilities. Please use the version in that class")]
		public static bool IsPathPossible(List<Node> nodes)
		{
			int area = nodes[0].area;
			for (int i = 0; i < nodes.Count; i++)
			{
				if (!nodes[i].walkable || nodes[i].area != area)
				{
					return false;
				}
			}
			return true;
		}

		public static bool UpdateGraphsNoBlock(GraphUpdateObject guo, Node node1, Node node2, bool alwaysRevert = false)
		{
			List<Node> list = ListPool<Node>.Claim();
			list.Add(node1);
			list.Add(node2);
			bool result = UpdateGraphsNoBlock(guo, list, alwaysRevert);
			ListPool<Node>.Release(list);
			return result;
		}

		public static bool UpdateGraphsNoBlock(GraphUpdateObject guo, List<Node> nodes, bool alwaysRevert = false)
		{
			for (int i = 0; i < nodes.Count; i++)
			{
				if (!nodes[i].walkable)
				{
					return false;
				}
			}
			guo.trackChangedNodes = true;
			bool worked = true;
			AstarPath.RegisterSafeUpdate(delegate
			{
				AstarPath.active.UpdateGraphs(guo);
				AstarPath.active.QueueGraphUpdates();
				AstarPath.ForceCallThreadSafeCallbacks();
				worked = worked && PathUtilities.IsPathPossible(nodes);
				if (!worked || alwaysRevert)
				{
					guo.RevertFromBackup();
					AstarPath.active.FloodFill();
				}
			}, threadSafe: true);
			AstarPath.active.FlushThreadSafeCallbacks();
			guo.trackChangedNodes = false;
			return worked;
		}
	}
}
namespace Pathfinding.Util
{
	public class LockFreeStack
	{
		public Path head;

		public void Push(Path p)
		{
			Path path;
			do
			{
				p.next = head;
				path = Interlocked.CompareExchange(ref head, p, p.next);
			}
			while (path != p.next);
		}

		public Path PopAll()
		{
			return Interlocked.Exchange(ref head, null);
		}
	}
}
namespace Pathfinding
{
	public static class PathUtilities
	{
		public static bool IsPathPossible(Node n1, Node n2)
		{
			return n1.walkable && n2.walkable && n1.area == n2.area;
		}

		public static bool IsPathPossible(List<Node> nodes)
		{
			int area = nodes[0].area;
			for (int i = 0; i < nodes.Count; i++)
			{
				if (!nodes[i].walkable || nodes[i].area != area)
				{
					return false;
				}
			}
			return true;
		}

		public static List<Node> GetReachableNodes(Node seed, int tagMask = -1)
		{
			Stack<Node> stack = StackPool<Node>.Claim();
			List<Node> list = ListPool<Node>.Claim();
			HashSet<Node> map = new HashSet<Node>();
			NodeDelegate nodeDelegate = ((tagMask != -1) ? ((NodeDelegate)delegate(Node node)
			{
				if (node.walkable && ((tagMask >> node.tags) & 1) != 0 && map.Add(node))
				{
					list.Add(node);
					stack.Push(node);
				}
			}) : ((NodeDelegate)delegate(Node node)
			{
				if (node.walkable && map.Add(node))
				{
					list.Add(node);
					stack.Push(node);
				}
			}));
			nodeDelegate(seed);
			while (stack.Count > 0)
			{
				stack.Pop().GetConnections(nodeDelegate);
			}
			StackPool<Node>.Release(stack);
			return list;
		}
	}
}
public class SizeProfiler
{
	public struct ProfileSizePoint
	{
		public long lastBegin;

		public long totalSize;

		public bool open;
	}

	private static Dictionary<string, ProfileSizePoint> profiles = new Dictionary<string, ProfileSizePoint>();

	private static string lastOpen = string.Empty;

	private static bool hasClosed = false;

	public static void Initialize()
	{
		profiles.Clear();
	}

	[Conditional("ASTAR_SizeProfile")]
	public static void Begin(string s, BinaryWriter stream)
	{
	}

	[Conditional("ASTAR_SizeProfile")]
	public static void Begin(string s, BinaryWriter stream, bool autoClosing)
	{
	}

	[Conditional("ASTAR_SizeProfile")]
	public static void Begin(string s, Stream stream, bool autoClosing)
	{
		if (hasClosed || profiles.ContainsKey(lastOpen))
		{
		}
		ProfileSizePoint value = default(ProfileSizePoint);
		if (!profiles.ContainsKey(s))
		{
			profiles[s] = default(ProfileSizePoint);
		}
		else
		{
			value = profiles[s];
		}
		if (value.open)
		{
			Debug.LogWarning((object)("Opening an already open entry (" + s + ")"));
		}
		value.lastBegin = stream.Position;
		value.open = true;
		if (autoClosing)
		{
			hasClosed = false;
			lastOpen = s;
		}
		profiles[s] = value;
	}

	[Conditional("ASTAR_SizeProfile")]
	public static void End(string s, BinaryWriter stream)
	{
	}

	[Conditional("ASTAR_SizeProfile")]
	public static void End(string s, Stream stream)
	{
		if (!profiles.ContainsKey(s))
		{
			Debug.LogError((object)("Can't end profile before one has started (" + s + ")"));
			return;
		}
		ProfileSizePoint value = profiles[s];
		if (!value.open)
		{
			Debug.LogWarning((object)("Cannot close an already closed entry (" + s + ")"));
			return;
		}
		hasClosed = true;
		value.totalSize += stream.Position - value.lastBegin;
		value.open = false;
		profiles[s] = value;
	}

	[Conditional("ASTAR_SizeProfile")]
	public static void Log()
	{
		StringBuilder stringBuilder = new StringBuilder();
		stringBuilder.Append("============================\n\t\t\t\tSize Profile results:\n============================\n");
		foreach (KeyValuePair<string, ProfileSizePoint> profile in profiles)
		{
			stringBuilder.Append(profile.Key);
			stringBuilder.Append("\tused\t");
			stringBuilder.Append(Mathfx.FormatBytes((int)profile.Value.totalSize));
			stringBuilder.Append("\n");
		}
		Debug.Log((object)stringBuilder.ToString());
	}
}
