			result = Random.Range(shootPowerRange[1][0], shootPowerRange[1][1]);
			break;
		case "Enemy3(Clone)":
			result = Random.Range(shootPowerRange[2][0], shootPowerRange[2][1]);
			break;
		case "Enemy4(Clone)":
			result = Random.Range(shootPowerRange[3][0], shootPowerRange[3][1]);
			break;
		case "Friend(Clone)":
			result = Random.Range(shootPowerRange[4][0], shootPowerRange[4][1]);
			break;
		}
		return result;
	}

	private void OnTriggerEnter(Collider other)
	{
		int randomDamage = getRandomDamage();
		if (((Component)other).gameObject.tag == "Player")
		{
			PlayerLogic.mInstance.PlayerDamage(randomDamage);
			Object.Destroy((Object)(object)((Component)this).gameObject);
		}
		else if (((Component)other).gameObject.tag == "EnemyTag")
		{
			if (Game.mInstance.gameMode == Game.Mode.Team && theParent == "FriendTag")
			{
				((Component)other).gameObject.GetComponent<enemyLogic>().ReceiveDamage(randomDamage);
				((Component)other).gameObject.GetComponent<enemyLogic>().setAnotherTarget(theParentGameObject);
				Object.Destroy((Object)(object)((Component)this).gameObject);
			}
		}
		else if (((Component)other).gameObject.tag == "FriendTag")
		{
			if (theParent == "EnemyTag")
			{
				((Component)other).gameObject.GetComponent<enemyLogic>().ReceiveDamage(randomDamage);
				((Component)other).gameObject.GetComponent<enemyLogic>().setAnotherTarget(theParentGameObject);
				Object.Destroy((Object)(object)((Component)this).gameObject);
			}
		}
		else
		{
			if (!(((Component)other).gameObject.tag == "City") && !(((Component)other).gameObject.tag == "City2"))
			{
				return;
			}
			if ((Object)(object)theParentGameObject != (Object)null)
			{
				theParentGameObject.GetComponent<enemyLogic>().AddShootWallNum(1);
				if (theParentGameObject.GetComponent<enemyLogic>().GetShootWallNum() == 15)
				{
					theParentGameObject.GetComponent<enemyLogic>().setAnotherTarget(theParentGameObject);
					theParentGameObject.GetComponent<enemyLogic>().ResetShootWallNum();
				}
			}
			Object.Destroy((Object)(object)((Component)this).gameObject);
		}
	}
}
