			break;
		case UIMenuDirector.SceneModTag.SceneModTag_2:
			gameMode = Mode.Team;
			break;
		case UIMenuDirector.SceneModTag.SceneModTag_4:
			gameMode = Mode.LocalOnline;
			break;
		case UIMenuDirector.SceneModTag.SceneModTag_5:
			gameMode = Mode.SinglePlayer;
			break;
		case UIMenuDirector.SceneModTag.SceneModTag_6:
