	private void RPGLanucherEffect(int i)
	{
		qiang_5_1 = GameObject.Find("qiang_5_1");
		qiang_5_1.renderer.enabled = false;
		if (i > 1)
		{
			((MonoBehaviour)this).StartCoroutine(waitForDisplayGunLanucher(2));
