	private void GrenadeEffect(int i)
	{
		qiang_6 = GameObject.Find("qiang_6");
		qiang_6.renderer.enabled = false;
		if (i > 1)
		{
			((MonoBehaviour)this).StartCoroutine(waitForDisplayGrenade(0.5f));
		}
	}

	private IEnumerator waitForDisplayGunLanucher(int seconds)
	{
		yield return (object)new WaitForSeconds((float)seconds);
		qiang_5_1.renderer.enabled = true;
	}

	private IEnumerator waitForDisplayGrenade(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		qiang_6.renderer.enabled = true;
	}
