	public void countdown()
	{
		DateTime now = DateTime.Now;
		TimeSpan ts = new TimeSpan(lastDateTime.Ticks);
		TimeSpan timeSpan = new TimeSpan(now.Ticks).Subtract(ts).Duration();
		if (timeSpan.Seconds >= 5)
		{
			go.GetComponent<UILabel>().text = string.Empty;
		}
		else if (timeSpan.Seconds == 0)
		{
			go.GetComponent<UILabel>().text = "5";
		}
		else if (timeSpan.Seconds == 1)
		{
			go.GetComponent<UILabel>().text = "4";
		}
		else if (timeSpan.Seconds == 2)
		{
			go.GetComponent<UILabel>().text = "3";
		}
		else if (timeSpan.Seconds == 3)
		{
			go.GetComponent<UILabel>().text = "2";
		}
		else if (timeSpan.Seconds == 4)
		{
			go.GetComponent<UILabel>().text = "1";
		}
	}

