	{
		audioBulletHit.Play();
	}

	private IEnumerator waitForGeneratePlayer(int seconds)
	{
		mStatus = PlayerStatus.dead;
		yield return (object)new WaitForSeconds((float)seconds);
		if ((Object)(object)Game.mInstance != (Object)null && Game.mInstance.gameMode == Game.Mode.LocalOnline)
		{
			RandomPosition();
		}
		else
		{
			int spawnIndex = Random.Range(1, 6);
			if ((Object)(object)GameObject.Find("Spawn_" + spawnIndex) != (Object)null)
			{
				((Component)this).transform.position = GameObject.Find("Spawn_" + spawnIndex).transform.position;
			}
		}
		mStatus = PlayerStatus.idle;
		((Collider)((Component)this).gameObject.GetComponent<CharacterController>()).enabled = true;
		blood = 100;
		bDied = false;
		goDied.renderer.enabled = bDied;
		go.GetComponent<UILabel>().text = string.Empty;
	}

