	public void PlayerDamage(int damage)
	{
		if (bDied)
		{
			return;
		}
		if ((Object)(object)SingleEnemyManager.mInstance != (Object)null)
		{
			float num = 1f;
			if (SingleEnemyManager.mInstance.Difficulty == 1)
			{
				num = 1f;
			}
			else if (SingleEnemyManager.mInstance.Difficulty == 2)
			{
				num = 1.3f;
			}
			else if (SingleEnemyManager.mInstance.Difficulty == 3)
			{
				num = 1.6f;
			}
			blood -= (int)((float)damage * 0.1f * num);
		}
		else
		{
			blood -= damage;
		}
		playBulletHitAudio();
		((MonoBehaviour)this).StartCoroutine(DisplayPlayerBlood());
	}

	public void PlayerDamageStrOnline(string damageInfo)
	{
		string[] array = damageInfo.Split('@');
		int num = int.Parse(array[1]);
		string text = array[0];
		if (Game.mInstance.gameMode != Game.Mode.LocalOnline)
		{
			PlayerDamage(num);
		}
		else
		{
			if (CNRMultiplayerManager.mInstance.CheckIfInOneTeam(text) || bDied || blood <= 0)
			{
				return;
			}
			if (CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame > 0)
			{
				headRate = Mathf.Lerp(CNRMultiplayerManager.mInstance.myArmorInfo.mHeadshotIgnoreRate[0], CNRMultiplayerManager.mInstance.myArmorInfo.mHeadshotIgnoreRate[1], (float)CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame / 100f);
				bodyRate = Mathf.Lerp(CNRMultiplayerManager.mInstance.myArmorInfo.mBodyDamageDefendRate[0], CNRMultiplayerManager.mInstance.myArmorInfo.mBodyDamageDefendRate[1], (float)CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame / 100f);
			}
			else
			{
				headRate = 0f;
				bodyRate = 0f;
			}
			if (num > 500)
			{
				float num2 = Random.Range(0f, 1f);
				if (ignoreHeadshotTimeCache > 0f)
				{
					blood -= 5;
					GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Headshot Protected!");
				}
				else if (num2 < headRate)
				{
					blood -= 5;
					GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Headshot Protected!");
					ignoreHeadshotTimeCache = 0.5f;
				}
				else
				{
					blood -= num;
				}
			}
			else
			{
				blood -= (int)((float)num * (1f - bodyRate));
			}
			if (!CNRMultiplayerManager.mInstance.myArmorInfo.mIsInAutoSupplyStatus)
			{
				if (num <= 20 && num > 0)
				{
					CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame = Math.Max(CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame - 2, 0);
					UIGameSceneDirectorForArmAndBlood.SendMessage("UpdateArmorDurabilityDisplay", (object)CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame, (SendMessageOptions)1);
				}
				else if (num <= 50)
				{
					CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame = Math.Max(CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame - 5, 0);
					UIGameSceneDirectorForArmAndBlood.SendMessage("UpdateArmorDurabilityDisplay", (object)CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame, (SendMessageOptions)1);
				}
				else if (num > 50)
				{
					CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame = Math.Max(CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame - 8, 0);
					UIGameSceneDirectorForArmAndBlood.SendMessage("UpdateArmorDurabilityDisplay", (object)CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame, (SendMessageOptions)1);
				}
			}
			if (blood <= 0 && blood + num > 0)
			{
				blood = 0;
				string[] peerIds = new string[1] { text };
				CNRMultiplayerManager.mInstance.sendMessageToPeersAdapt(peerIds, "ExampleCharacter", "AddOneKill", CNRMultiplayerManager.mInstance.myPlayerInfo.mId + '@' + num.ToString(), reliably: false);
				killNumNoDie = 0;
			}
			playBulletHitAudio();
			((MonoBehaviour)this).StartCoroutine(DisplayPlayerBlood());
		}
	}

	public void AddOneKill(string param)
	{
		string[] array = param.Split('@');
		int num = int.Parse(array[1]);
		CNRMultiplayerManager.mInstance.BroadcastKillEventMessageOnlineAdapt(array[0]);
		killedNum++;
		CNRMultiplayerManager.mInstance.SendKillingCompetitionGetMessage();
		if (CNRMultiplayerManager.mInstance.multiplayerMode == MultiMode.LocalWiFi)
		{
			GrowthManagerKit.AddCharacterExp(2);
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalKillInLocalWifiMultiplayer, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalKillInLocalWifiMultiplayer));
			GrowthManagerKit.AddCoins(2);
		}
		else if (CNRMultiplayerManager.mInstance.multiplayerMode == MultiMode.PhotonCloudOnline)
		{
			GrowthManagerKit.AddCharacterExp(3);
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalKillInWorldwideMultiplayer, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalKillInWorldwideMultiplayer));
			GrowthManagerKit.AddCoins(3);
		}
		killNumNoDie++;
		if (num >= 200)
		{
			GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Headshot!");
			headShotKill.Play();
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalHeadshotKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalHeadshotKill));
		}
		switch (killNumNoDie)
		{
		case 2:
			GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Dominating!");
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalTwoKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalTwoKill));
			break;
		case 4:
			GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Unstoppable!");
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalFourKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalFourKill));
			break;
		case 6:
			GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Rampage!");
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalSixKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalSixKill));
			break;
		case 8:
			GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "Monster Kill!");
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalEightKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalEightKill));
			break;
		case 10:
			GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "God Like!");
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalGoldLikeKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalGoldLikeKill));
			break;
		}
		if (killNumNoDie > 10)
		{
			if (killNumNoDie % 2 == 0)
			{
				GrowthManagerKit.GenGrowthPromptEvent(GrowthPrometType.Killing, 1, "God Like!");
			}
			GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalGoldLikeKill, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalGoldLikeKill));
		}
	}

	public void PlayerDamageOnline(string damageS)
	{
		if (!bDied)
		{
			int num = int.Parse(damageS);
			blood -= num;
			playBulletHitAudio();
			((MonoBehaviour)this).StartCoroutine(DisplayPlayerBlood());
		}
	}

	private IEnumerator DisplayPlayerBlood()
	{
		((Behaviour)GameObject.Find("PlayerBlood").GetComponent<GUITexture>()).enabled = true;
		yield return (object)new WaitForSeconds(0.12f);
		((Behaviour)GameObject.Find("PlayerBlood").GetComponent<GUITexture>()).enabled = false;
	}

	public void addKilledNum(int i)
	{
		killedNum++;
		GrowthManagerKit.AddCharacterExp(i);
		GrowthManagerKit.AddCoins(i);
	}

	public void OnGameOver()
	{
	}

	private void OnDisable()
	{
		UIGameSceneDirector.OnMediKit -= OnMediKit;
		UIGameSceneDirector.OnAddArmor -= OnAddArmor;
		UIMenuDirector.OnSoundSetting -= OnSoundSetting;
	}

	private void OnMediKit()
	{
		if (!bDied)
		{
			blood = 100;
		}
	}

	private void OnAddArmor()
	{
		CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame = 100;
		UIGameSceneDirectorForArmAndBlood.SendMessage("UpdateArmorDurabilityDisplay", (object)CNRMultiplayerManager.mInstance.myArmorInfo.mDurabilityInGame, (SendMessageOptions)1);
	}

	private void OnSoundSetting()
	{
		//IL_002f: Unknown result type (might be due to invalid IL or missing references)
		//IL_006e: Unknown result type (might be due to invalid IL or missing references)
		if (PlayerPrefs.GetInt("IsSoundEffectEnabled", 1) == 0)
		{
			((Component)this).transform.Find("AudioListenerControl").localPosition = new Vector3(0f, 10000f, 0f);
		}
		else if (PlayerPrefs.GetInt("IsSoundEffectEnabled", 1) == 1)
		{
			((Component)this).transform.Find("AudioListenerControl").localPosition = new Vector3(0f, 2f, 0f);
		}
	}

	private void PlayerDamageWhenInFire()
	{
		if (PlayerInFire)
		{
			InFireTime += Time.deltaTime;
			if ((double)InFireTime > 0.5)
			{
				blood -= 8;
				InFireTime = 0f;
			}
		}
	}

	private void PlayerDamageWhenInTieding()
	{
		if (PlayerInTieding)
		{
			InTiedingTime += Time.deltaTime;
			if ((double)InFireTime > 0.2)
			{
				blood--;
				InTiedingTime = 0f;
			}
		}
	}
}
