			bEscape = true;
		}
		if (blood <= 0)
		{
			if (((Component)((Component)this).transform).tag == "FriendTag")
			{
				Game.mInstance.EnemyKillWeNumInTeamMode++;
			}
			else if (((Component)((Component)this).transform).tag == "EnemyTag")
			{
				Game.mInstance.WeKillEnemyNumInTeamMode++;
			}
			bDead = true;
			((Component)enemyAnimation).animation.wrapMode = (WrapMode)1;
			((Component)enemyAnimation).animation.Play("dead");
			Object.Destroy((Object)(object)((Component)((Component)this).transform).GetComponent<MineBotAI>());
			((MonoBehaviour)this).StartCoroutine(waitForSecondsToDestory(2));
		}
	}

	public void decreaseBlood(int nblood)
	{
		if (blood > 0)
		{
			playBulletHitAudio();
			blood -= nblood;
			if (blood >= 45 && blood <= 55)
			{
				bEscape = true;
			}
			if (blood <= 0)
			{
				Game.mInstance.IKillEnemyNum++;
				Game.mInstance.WeKillEnemyNumInTeamMode++;
				bDead = true;
				((Component)enemyAnimation).animation.wrapMode = (WrapMode)1;
				((Component)enemyAnimation).animation.Play("dead");
				Object.Destroy((Object)(object)((Component)((Component)this).transform).GetComponent<MineBotAI>());
				playEnemyDieAudio();
				((MonoBehaviour)this).StartCoroutine(waitForSecondsToDestory(2));
			}
		}
	}

	public void playEnemyDieAudio()
	{
		audioEnemyDie.Play();
	}

	public void playBulletHitAudio()
	{
		audioBulletHit.Play();
	}

	public void setTargetIsPlayer(bool btarget)
	{
		bTargetIsPlayer = btarget;
	}

	private IEnumerator waitForSecondsToDestory(int seconds)
	{
		((Collider)((Component)this).gameObject.GetComponent<CharacterController>()).enabled = false;
		((Collider)((Component)this).gameObject.GetComponent<BoxCollider>()).enabled = false;
		yield return (object)new WaitForSeconds((float)seconds);
		Object.Destroy((Object)(object)((Component)this).gameObject);
	}
}
