		else if (Input.GetMouseButton(0) && Time.time > nextFire)
		{
			nextFire = Time.time + fireRate;
			((Component)this).animation.Rewind("Fire");
			((Component)this).animation.CrossFade("Fire");
			((Component)this).animation["Fire"].speed = animSpeed;
		}
