	private void RifleReload()
	{
		AnimationState val = ((Component)this).animation.CrossFadeQueued("Reload");
		val.speed = animSpeed;
	}

	private void SniperReload()
	{
		AnimationState val = ((Component)this).animation.CrossFadeQueued("Reload_1_3");
		val.speed = animSpeed;
		for (int i = 0; i < 4; i++)
		{
			AnimationState val2 = ((Component)this).animation.CrossFadeQueued("Reload_2_3");
			val2.speed = animSpeed;
		}
		AnimationState val3 = ((Component)this).animation.CrossFadeQueued("Reload_3_3");
		val3.speed = animSpeed;
	}

	private void TakeIn()
	{
		((Component)this).animation.Play("TakeIn");
		((Component)this).animation["TakeIn"].speed = animSpeed;
	}

	private void TakeOut()
	{
		((Component)this).animation.CrossFade("TakeOut");
		((Component)this).animation["TakeOut"].speed = animSpeed;
	}
