		GUI.Label(new Rect(5f, 5f, 500f, 20f), "[ " + (weapIndex + 1).ToString() + " / " + weapons.Count + " ] : " + ((Object)weapons[weapIndex]).name);
		GUI.Label(new Rect((float)(Screen.width - 205), 5f, 500f, 20f), "1 - Previous Weapon");
