		Rigidbody temp = (Rigidbody)(object)((obj is Rigidbody) ? obj : null);
		temp.velocity = FirePoint.TransformDirection(Vector3.forward * 60f);
	}

	private void RifleReload()
	{
		AnimationState val = ((Component)this).animation.CrossFadeQueued("Reload");
		val.speed = animSpeed;
