			{
				return;
			}
			if (value && connected)
			{
				Debug.LogError((object)"Can't start OFFLINE mode while connected!");
				return;
			}
			networkingPeer.Disconnect();
			isOfflineMode = value;
			if (isOfflineMode)
			{
