	public static event Action<string> receivedConnectionRequestFromPeer;

	public static event Action<string> acceptConnectionWithPeerFailed;

	public static event Action<string> peerConnectedForVoiceChat;

	public static event Action<string> peerDisconnectedFromVoiceChat;

	public static event Action peerPickerCancelled;

	static GameKitManager()
	{
		connectedPeers = new List<string>();
		availablePeers = new List<string>();
		AbstractManager.initialize(typeof(GameKitManager));
	}

	public static bool isConnected()
	{
		return connectedPeers.Count > 0;
	}

	public void didConnectToPeer(string peerId)
	{
		connectedPeers.Add(peerId);
		if (GameKitManager.peerConnected != null)
		{
			GameKitManager.peerConnected(peerId);
		}
	}

	public void peerPickerDidCancel(string emptyString)
	{
		connectedPeers.Clear();
		if (GameKitManager.peerPickerCancelled != null)
		{
			GameKitManager.peerPickerCancelled();
		}
	}

	public void peerDidDisconnect(string peerId)
	{
		connectedPeers.Remove(peerId);
		if (GameKitManager.peerDisconnected != null)
		{
			GameKitManager.peerDisconnected(peerId);
		}
	}

	public void peerDidBecameAvailable(string peerId)
	{
		availablePeers.Add(peerId);
		if (GameKitManager.peerBecameAvailable != null)
		{
			GameKitManager.peerBecameAvailable(peerId);
		}
	}

	public void peerDidBecameUnavailable(string peerId)
	{
		availablePeers.Remove(peerId);
		if (GameKitManager.peerBecameUnavailable != null)
		{
			GameKitManager.peerBecameUnavailable(peerId);
		}
	}

	public void didReceiveConnectionRequestFromPeer(string peerId)
	{
		if (GameKitManager.receivedConnectionRequestFromPeer != null)
		{
			GameKitManager.receivedConnectionRequestFromPeer(peerId);
		}
	}

	public void acceptConnectionWithPeerDidFail(string peerId)
	{
		if (GameKitManager.acceptConnectionWithPeerFailed != null)
		{
			GameKitManager.acceptConnectionWithPeerFailed(peerId);
		}
	}

	public void voiceChatServiceDidStart(string peerId)
	{
		if (GameKitManager.peerConnectedForVoiceChat != null)
		{
			GameKitManager.peerConnectedForVoiceChat(peerId);
		}
	}

	public void voiceChatServiceDidStop(string peerId)
	{
		if (GameKitManager.peerDisconnectedFromVoiceChat != null)
		{
			GameKitManager.peerDisconnectedFromVoiceChat(peerId);
		}
	}
}
