	public void SwitchToServer(WWServerList serverSelect)
	{
		PlayerPrefs.SetInt("CurServerTagSaved", (int)serverSelect);
		tCurServer = serverSelect;
		RemoveAllRoomObjs();
		ResetViewCameraPos();
		switch (serverSelect)
		{
		case WWServerList.Default:
			if (PhotonNetwork.connected)
			{
				PhotonNetwork.Disconnect();
			}
			PhotonNetwork.PhotonServerSettings.ServerAddress = "app.exitgamescloud.com";
			break;
		case WWServerList.US:
			if (PhotonNetwork.connected)
			{
				PhotonNetwork.Disconnect();
			}
			PhotonNetwork.PhotonServerSettings.ServerAddress = "app-us.exitgamescloud.com";
			break;
		case WWServerList.EU:
			if (PhotonNetwork.connected)
			{
				PhotonNetwork.Disconnect();
			}
			PhotonNetwork.PhotonServerSettings.ServerAddress = "app-eu-east.exitgamescloud.com";
			break;
		case WWServerList.ASIA:
			if (PhotonNetwork.connected)
			{
				PhotonNetwork.Disconnect();
			}
