			{
				PhotonNetwork.Disconnect();
			}
			PhotonNetwork.PhotonServerSettings.ServerAddress = "app-jp.exitgamescloud.com";
			break;
		default:
			if (PhotonNetwork.connected)
			{
				PhotonNetwork.Disconnect();
			}
			PhotonNetwork.PhotonServerSettings.ServerAddress = "app.exitgamescloud.com";
			break;
