		viewCameraInitPos = viewCamera.transform.localPosition;
		try
		{
			Debug.Log((object)"[CNRModLoader] Initializing mod loader in CNRConnectMenu.Awake()");
			Directory.CreateDirectory("/storage/emulated/0/CNRMods/");
			Debug.Log((object)"[CNRModLoader] Mods directory ready at /storage/emulated/0/CNRMods/");
			string text = "/storage/emulated/0/CNRMods/";
			if (Directory.Exists(text))
			{
				string[] files = Directory.GetFiles(text, "*.dll");
				Debug.Log((object)("[CNRModLoader] Found " + files.Length + " mod DLL files"));
				string[] array = files;
				foreach (string text2 in array)
				{
					try
					{
						Debug.Log((object)("[CNRModLoader] Loading mod: " + text2));
						Assembly.Load(File.ReadAllBytes(text2));
						Debug.Log((object)("[CNRModLoader] Successfully loaded: " + text2));
					}
					catch (Exception ex)
					{
						Debug.LogError((object)("[CNRModLoader] Failed to load " + text2 + ": " + ex.Message));
					}
				}
			}
			else
			{
				Debug.LogWarning((object)("[CNRModLoader] Mods directory not found at " + text));
			}
		}
		catch (Exception ex2)
		{
			Debug.LogError((object)("[CNRModLoader] Error during mod loader initialization: " + ex2.Message));
		}
	}

	private void OnDisable()
