	}

	private void OnEnable()
	{
	}

	private void Update()
	{
		//IL_028c: Unknown result type (might be due to invalid IL or missing references)
		//IL_029c: Unknown result type (might be due to invalid IL or missing references)
		//IL_02d1: Unknown result type (might be due to invalid IL or missing references)
		//IL_02ed: Unknown result type (might be due to invalid IL or missing references)
		//IL_0309: Unknown result type (might be due to invalid IL or missing references)
		MultiplayerSelectDirector.mInstance.newRoomName = newRoomName;
		float num = 3f;
		float num2 = 0f;
		if (!PhotonNetwork.connected)
		{
			connectingLabel.text = "Connecting...";
			if (Time.time - num > num2)
			{
				num2 = Time.time - Time.deltaTime;
			}
			for (; num2 < Time.time; num2 += num)
			{
				PhotonNetwork.ConnectUsingSettings("v2.4");
			}
		}
		else
		{
			connectingLabel.text = string.Empty;
		}
		if (PhotonNetwork.connected && Time.frameCount % 32 == 0)
		{
			allRooms = PhotonNetwork.GetRoomList();
			((Component)roomObjParent).GetComponent<UITable>().Reposition();
		}
		searchString = searchInputLabel.text;
		localRoomInfoListHash.Clear();
		foreach (CNRRoomInfo mCNRRoomInfo in mCNRRoomInfoList)
		{
			mCNRRoomInfo.toBeDestroyed = true;
			localRoomInfoListHash.Add(mCNRRoomInfo.mRoomInfo.name, mCNRRoomInfo);
		}
		if (allRooms != null)
		{
			RoomInfo[] array = allRooms;
			foreach (RoomInfo roomInfo in array)
			{
				if ((string)roomInfo.customProperties["version"] != UserDataController.GetStrVersion() || roomInfo.maxPlayers < playerLimitArray[0] || roomInfo.maxPlayers > playerLimitArray[1] || roomInfo.maxPlayers == roomInfo.playerCount)
				{
					continue;
				}
				bool flag = true;
				int index = 0;
				if (localRoomInfoListHash.Contains(roomInfo.name))
				{
					CNRRoomInfo cNRRoomInfo = (CNRRoomInfo)localRoomInfoListHash[roomInfo.name];
					cNRRoomInfo.toBeDestroyed = false;
					flag = false;
					index = mCNRRoomInfoList.IndexOf(cNRRoomInfo);
				}
				if (flag)
				{
					string text = ((GrowthGameModeTag)int.Parse((string)roomInfo.customProperties["mode"])/*cast due to .constrained prefix*/).ToString();
					string realmapName = GetRealmapName((string)roomInfo.customProperties["map"]);
					if (roomInfo.name.ToLower().Contains(searchString.ToLower()) || text.ToLower().Contains(searchString.ToLower()) || realmapName.ToLower().Contains(searchString.ToLower()))
					{
						Object obj = Object.Instantiate((Object)(object)roomPrefab, roomPrefab.transform.position, roomPrefab.transform.rotation);
						GameObject val = (GameObject)(object)((obj is GameObject) ? obj : null);
						val.transform.parent = roomObjParent;
						val.transform.localScale = roomPrefab.transform.localScale;
						val.transform.position = roomPrefab.transform.position;
						val.transform.rotation = roomPrefab.transform.rotation;
						val.GetComponent<CNRRoomInfo>().mRoomInfo = roomInfo;
						((Component)roomObjParent).GetComponent<UITable>().Reposition();
						mCNRRoomInfoList.Add(val.GetComponent<CNRRoomInfo>());
					}
				}
				else
				{
					mCNRRoomInfoList[index].playerCount = roomInfo.playerCount;
					mCNRRoomInfoList[index].mRoomInfo = roomInfo;
				}
			}
		}
		for (int j = 0; j < mCNRRoomInfoList.Count; j++)
		{
			string text2 = ((GrowthGameModeTag)int.Parse((string)mCNRRoomInfoList[j].mRoomInfo.customProperties["mode"])/*cast due to .constrained prefix*/).ToString();
			string realmapName2 = GetRealmapName((string)mCNRRoomInfoList[j].mRoomInfo.customProperties["map"]);
			if (mCNRRoomInfoList[j].toBeDestroyed || (!mCNRRoomInfoList[j].mRoomInfo.name.ToLower().Contains(searchString.ToLower()) && !text2.ToLower().Contains(searchString.ToLower()) && !realmapName2.ToLower().Contains(searchString.ToLower())))
			{
				GameObject gameObject = ((Component)mCNRRoomInfoList[j]).gameObject;
				mCNRRoomInfoList.RemoveAt(j);
				Object.Destroy((Object)(object)gameObject);
				((Component)roomObjParent).GetComponent<UITable>().Reposition();
				break;
			}
		}
	}

