public enum StrongholdHoldState
{
	copHold,
	robberHold
}
public enum StrongholdUseState
{
	noUsed,
	isusing
}
public class CNRModeInfo
{
	public class StrongholdModeInfo
	{
		public StrongholdHoldState holdState_1;

		public StrongholdUseState useState_1;

		public StrongholdHoldState holdState_2 = StrongholdHoldState.robberHold;

		public StrongholdUseState useState_2;

		public int StrongholdNum = 1;

		public int copResource = 900;

		public int robberResource = 900;

		public readonly int MAX_RESOURCES = 900;

		public void SetStrongholdNum()
		{
		}
	}

	public class KillingCompetitionModeInfo
	{
		public int copKilling;

		public int robberKilling;

		public int MAXKilling = 100;
	}

	public GrowthGameModeTag mCurMode;

	public StrongholdModeInfo mStrongholdInfo;

	public KillingCompetitionModeInfo mKillingCompetitionInfo;

	public CNRModeInfo(GrowthGameModeTag modeTag)
	{
		mCurMode = modeTag;
		mStrongholdInfo = new StrongholdModeInfo();
		mKillingCompetitionInfo = new KillingCompetitionModeInfo();
	}

	public bool ParseStringToModeInfo(string str)
	{
		string[] array = str.Split('_');
		if (mCurMode == GrowthGameModeTag.tStronghold)
		{
			mStrongholdInfo.holdState_1 = (StrongholdHoldState)int.Parse(array[0]);
			mStrongholdInfo.useState_1 = (StrongholdUseState)int.Parse(array[1]);
			mStrongholdInfo.holdState_2 = (StrongholdHoldState)int.Parse(array[2]);
			mStrongholdInfo.useState_2 = (StrongholdUseState)int.Parse(array[3]);
			mStrongholdInfo.StrongholdNum = int.Parse(array[4]);
			mStrongholdInfo.copResource = int.Parse(array[5]);
			mStrongholdInfo.robberResource = int.Parse(array[6]);
		}
		else if (mCurMode == GrowthGameModeTag.tKillingCompetition)
		{
			mKillingCompetitionInfo.copKilling = int.Parse(array[0]);
			mKillingCompetitionInfo.robberKilling = int.Parse(array[1]);
		}
		return true;
	}

	public string ParseModeInfoToString()
	{
		string result = string.Empty;
		if (mCurMode == GrowthGameModeTag.tStronghold)
		{
			object[] array = new object[13];
			int holdState_ = (int)mStrongholdInfo.holdState_1;
			array[0] = holdState_.ToString();
			array[1] = '_';
			int useState_ = (int)mStrongholdInfo.useState_1;
			array[2] = useState_.ToString();
			array[3] = '_';
			int holdState_2 = (int)mStrongholdInfo.holdState_2;
			array[4] = holdState_2.ToString();
			array[5] = '_';
			int useState_2 = (int)mStrongholdInfo.useState_2;
			array[6] = useState_2.ToString();
			array[7] = '_';
			array[8] = mStrongholdInfo.StrongholdNum.ToString();
			array[9] = '_';
			array[10] = mStrongholdInfo.copResource.ToString();
			array[11] = '_';
			array[12] = mStrongholdInfo.robberResource.ToString();
			result = string.Concat(array);
		}
		else if (mCurMode == GrowthGameModeTag.tKillingCompetition)
		{
			result = mKillingCompetitionInfo.copKilling.ToString() + '_' + mKillingCompetitionInfo.robberKilling.ToString();
		}
		return result;
	}

	private void Start()
	{
	}
}
