	[RPC]
	public void ReceiveGMOffer(string param)
	{
		string[] array = param.Split('@');
		int coinsAdd = int.Parse(array[0]);
		int gemsAdd = int.Parse(array[1]);
		GrowthManagerKit.AddCoins(coinsAdd);
		GrowthManagerKit.AddGems(gemsAdd);
	}

