		int coins = int.Parse(array[0]);
		int gems = int.Parse(array[1]);
		int characterLevel = int.Parse(array[2]);
		int newValue = int.Parse(array[3]);
		UserDataController.SetCoins(coins);
		UserDataController.SetGems(gems);
