		if (multiplayerMode == MultiMode.PhotonCloudOnline && PhotonNetwork.connected)
		{
			if (int.Parse((string)PhotonNetwork.room.customProperties["mode"]) == 1)
			{
				myModeInfo = new CNRModeInfo(GrowthGameModeTag.tStronghold);
			}
			else if (int.Parse((string)PhotonNetwork.room.customProperties["mode"]) == 0)
			{
				myModeInfo = new CNRModeInfo(GrowthGameModeTag.tTeamDeathMatch);
			}
			else if (int.Parse((string)PhotonNetwork.room.customProperties["mode"]) == 2)
			{
				myModeInfo = new CNRModeInfo(GrowthGameModeTag.tKillingCompetition);
				int maxPlayers = PhotonNetwork.room.maxPlayers;
				if (maxPlayers <= 2)
				{
					myModeInfo.mKillingCompetitionInfo.MAXKilling = 20;
				}
				else if (maxPlayers <= 4)
				{
					myModeInfo.mKillingCompetitionInfo.MAXKilling = 40;
				}
				else if (maxPlayers <= 6)
				{
					myModeInfo.mKillingCompetitionInfo.MAXKilling = 60;
				}
				else if (maxPlayers <= 8)
				{
					myModeInfo.mKillingCompetitionInfo.MAXKilling = 80;
				}
				else if (maxPlayers <= 10)
				{
					myModeInfo.mKillingCompetitionInfo.MAXKilling = 100;
				}
				else
				{
					myModeInfo.mKillingCompetitionInfo.MAXKilling = 150;
				}
			}
		}
		myArmorInfo = GrowthManagerKit.GetCurSettedArmorInfo();
		if (myArmorInfo.GetAutoSupplyTimeRest() > 0f)
		{
			myArmorInfo.mIsInAutoSupplyStatus = true;
		}
	}

	public void Start()
	{
		GameKitManager.peerConnected += onPeerConnected;
		GameKitManager.peerDisconnected += onPeerDisconnect;
		GameKitManager.peerPickerCancelled += onPeerPickerCanceled;
		GameKitManager.peerBecameAvailable += peerBecameAvailable;
		GameKitManager.peerBecameUnavailable += peerBecameUnavailable;
		GameKitManager.receivedConnectionRequestFromPeer += receivedConnectionRequestFromPeer;
		GameKitManager.peerConnectedForVoiceChat += onPeerConnectedForVoiceChat;
		GameKitManager.peerDisconnectedFromVoiceChat += onPeerDisconnectedFromVoiceChat;
		if (multiplayerMode == MultiMode.PhotonCloudOnline)
		{
			OnlineRefresh();
		}
		else
		{
			Refresh();
		}
	}

	public void OnDisable()
	{
		GameKitManager.peerConnected -= onPeerConnected;
		GameKitManager.peerDisconnected -= onPeerDisconnect;
		GameKitManager.peerPickerCancelled -= onPeerPickerCanceled;
		GameKitManager.peerBecameAvailable -= peerBecameAvailable;
		GameKitManager.peerBecameUnavailable -= peerBecameUnavailable;
		GameKitManager.receivedConnectionRequestFromPeer -= receivedConnectionRequestFromPeer;
		GameKitManager.peerConnectedForVoiceChat -= onPeerConnectedForVoiceChat;
		GameKitManager.peerDisconnectedFromVoiceChat -= onPeerDisconnectedFromVoiceChat;
		if (multiplayerMode == MultiMode.PhotonCloudOnline && !isNewRoundLogic)
		{
			PhotonNetwork.Disconnect();
		}
		if (multiplayerMode == MultiMode.LocalWiFi && GameKitManager.isConnected())
		{
			GameKitBinding.invalidateSession();
		}
		((MonoBehaviour)this).StopAllCoroutines();
	}

	public void OnDestroy()
	{
		if ((Object)(object)mInstance == (Object)(object)this)
		{
			mInstance = null;
		}
	}

	private void Update()
	{
		if (multiplayerMode == MultiMode.PhotonCloudOnline)
		{
			UpdateMyPlayerInfoOnline();
			if (Time.frameCount % 64 == 0)
			{
				if (PhotonNetwork.connected)
				{
					isPhotonConnected = true;
					connectChkDelay = 0;
				}
				else
				{
					connectChkDelay++;
				}
				if (connectChkDelay >= 3)
				{
					isPhotonConnected = false;
				}
			}
		}
		else
		{
			TimeOutCheckLoop();
			UpdateMyPlayerInfo();
		}
		if (myPlayerInfo.mConnnectStatus == ConnectStatus.WaitForOtherPlayers)
		{
			myPlayerLogic.RandomPosition();
			myPlayerInfo.mConnnectStatus = ConnectStatus.InGame;
			mLobbyPanel.SetActive(false);
		}
		SynGameRoundTimeLocal();
		UpdateOtherPlayersObject();
		if (Time.frameCount % 32 == 0)
		{
			SynTeamNumber();
		}
		if (multiplayerMode == MultiMode.PhotonCloudOnline && myModeInfo.mCurMode == GrowthGameModeTag.tStronghold)
		{
			StrongholdModeAllFrameProcess();
		}
		else if (multiplayerMode == MultiMode.PhotonCloudOnline && myModeInfo.mCurMode == GrowthGameModeTag.tKillingCompetition)
		{
			KillingCompetitionModeAllFrameProcess();
		}
		myArmorInfo.AutoSupplyTimeDecreaseUpdate(Time.deltaTime);
	}

