	public void onPeerDisconnect(string peerId)
	{
		Debug.Log((object)("PeerDisconnected event fired with peerId: " + peerId));
		RemovePlayer(peerId);
		if (!GameKitManager.isConnected())
		{
			((MonoBehaviour)this).StopAllCoroutines();
			keepSendingFlag = false;
		}
