	public void AddPlayer(string peerId)
	{
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId == "null")
			{
				otherPlayersInfoList[i] = new PlayerInfo(peerId);
				string item = ParseSendingMsgWithType(MsgType.System, "New Player(id-" + peerId + ") Connected!");
				mMessageList.Add(item);
				break;
			}
		}
	}

	public void RemovePlayer(string peerId)
	{
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId == peerId)
			{
				string item = ParseSendingMsgWithType(MsgType.System, otherPlayersInfoList[i].mNickName + " Disconnected!");
				mMessageList.Add(item);
				otherPlayersInfoList[i] = new PlayerInfo();
				break;
			}
		}
	}

