					otherPlayerObject[i].GetComponent<NetPlayerController>().SetMyInfo(otherPlayersInfoList[i]);
				}
			}
			if (otherPlayersInfoList[i].mId == "null" && (Object)(object)otherPlayerObject[i] != (Object)null)
			{
				Object.Destroy((Object)(object)otherPlayerObject[i]);
				otherPlayerObject[i] = null;
			}
		}
