	public string ParseSendingMsgWithType(MsgType type, string srcMsg)
	{
		object[] array = new object[5];
		int num = (int)type;
		array[0] = num.ToString();
		array[1] = '@';
		int mTeam = (int)myPlayerInfo.mTeam;
		array[2] = mTeam.ToString();
		array[3] = '@';
		array[4] = srcMsg;
		return string.Concat(array);
	}

	public MsgType GetReceiveMsgType(string msg)
	{
		return (MsgType)int.Parse(msg.Split('@')[0]);
	}

	public string GetReceiveMsgContent(string msg)
	{
		string text = msg.Split('@')[0];
		string text2 = msg.Split('@')[1];
		return msg.Substring(text.Length + text2.Length + 2);
	}

	public TeamType GetMsgTeam(string msg)
	{
		return (TeamType)int.Parse(msg.Split('@')[1]);
	}

	public void BroadcastKillEventMessageOnlineAdapt(string killTargetId)
	{
		string text = string.Empty;
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId == killTargetId)
			{
				text = otherPlayersInfoList[i].mNickName;
			}
		}
		string srcMsg = myPlayerInfo.mNickName + " Kill " + text;
		srcMsg = ParseSendingMsgWithType(MsgType.System, srcMsg);
		mMessageList.Add(srcMsg);
		if (multiplayerMode == MultiMode.LocalWiFi)
		{
			GameKitBinding.sendData("CNRMultiplayerManager", "AddMessageOnline", srcMsg, reliably: false);
		}
		else if (PhotonNetwork.connected)
		{
			base.photonView.RPC("AddMessageOnline", PhotonTargets.Others, srcMsg);
		}
	}

	public bool CheckIfInOneTeam(string targetId)
	{
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId == targetId && otherPlayersInfoList[i].mTeam == myPlayerInfo.mTeam)
			{
				return true;
			}
		}
		return false;
	}

	public void SynGameRoundTimeLocal()
	{
		if (myPlayerInfo.mConnnectStatus != ConnectStatus.InGame)
		{
			myPlayerInfo.mGameRoundTime = 0f;
			mGameRoundTimeStart = Time.time;
		}
		else
		{
			myPlayerInfo.mGameRoundTime = Time.time - mGameRoundTimeStart;
		}
		float num = 0f;
		for (int i = 0; i < 20; i++)
		{
			num = Mathf.Max(num, otherPlayersInfoList[i].mGameRoundTime);
		}
		num = Mathf.Max(num, myPlayerInfo.mGameRoundTime);
		mGameRoundTimeRest = 600f - num;
		myPlayerInfo.mGameRoundTime = num;
		if (mGameRoundTimeRest <= 0f)
		{
			mGameRoundTimeRest = 0f;
		}
	}

