	public IEnumerator sendMyPlayerInfoToPeerOnline()
	{
		while (true)
		{
			if (PhotonNetwork.connected)
			{
				if (myModeInfo.mCurMode == GrowthGameModeTag.tTeamDeathMatch)
				{
					base.photonView.RPC("OtherPlayersInfoToLocationOnline", PhotonTargets.Others, PlayerInfo.PlayerInfoToString(myPlayerInfo));
				}
				else if (myModeInfo.mCurMode == GrowthGameModeTag.tStronghold)
				{
					base.photonView.RPC("OtherPlayersInfoToLocationOnline", PhotonTargets.Others, PlayerInfo.PlayerInfoToString(myPlayerInfo));
					if (serverId == myPlayerInfo.mId)
					{
						base.photonView.RPC("ServerModeInfoToLocationOnline", PhotonTargets.Others, myModeInfo.ParseModeInfoToString());
					}
				}
				else if (myModeInfo.mCurMode == GrowthGameModeTag.tKillingCompetition)
				{
					base.photonView.RPC("OtherPlayersInfoToLocationOnline", PhotonTargets.Others, PlayerInfo.PlayerInfoToString(myPlayerInfo));
					if (serverId == myPlayerInfo.mId)
					{
						base.photonView.RPC("ServerModeInfoToLocationOnline", PhotonTargets.Others, myModeInfo.ParseModeInfoToString());
					}
				}
			}
			yield return (object)new WaitForSeconds(0.2f);
		}
	}

	public void OnlineRefresh()
	{
		InitMyPlayerInfoOnline();
		keepSendingFlag = false;
	}

	public void TimeOutCheckLoopOnline()
	{
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId != "null")
			{
				otherPlayerTimeOutCount[i]++;
			}
			if (otherPlayerTimeOutCount[i] >= 900)
			{
				RemovePlayer(otherPlayersInfoList[i].mId);
				otherPlayerTimeOutCount[i] = 0;
			}
		}
	}

	[RPC]
	public void OtherPlayersInfoToLocationOnline(string param)
	{
		PlayerInfo playerInfo = PlayerInfo.StringToPlayerInfo(param);
		if (playerInfo == null)
		{
			return;
		}
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId == playerInfo.mId)
			{
				otherPlayersInfoList[i] = playerInfo;
				otherPlayerTimeOutCount[i] = 0;
				return;
			}
		}
		if ((myModeInfo.mCurMode != GrowthGameModeTag.tStronghold || !StrongholdRoundOverChk()) && (myModeInfo.mCurMode != GrowthGameModeTag.tKillingCompetition || !KillingCompetitionRoundOverChk()))
		{
			AddPlayer(playerInfo.mId);
		}
	}

