	public void OtherPlayersInfoToLocation(string param)
	{
		try
		{
			PlayerInfo playerInfo = PlayerInfo.StringToPlayerInfo(param);
			if (playerInfo == null)
			{
				return;
			}
			for (int i = 0; i < 20; i++)
			{
				if (otherPlayersInfoList[i].mId == playerInfo.mId)
				{
					otherPlayersInfoList[i] = playerInfo;
					otherPlayerTimeOutCount[i] = 0;
					break;
				}
			}
		}
		catch (Exception ex)
		{
			Debug.Log((object)("Exception: " + ex));
		}
	}

	public void Refresh()
	{
		GameKitBinding.invalidateSession();
		GameKitBinding.setSessionMode(GameKitSessionMode.Peer);
		GameKitBinding.setAutoConnectPeers(shouldAutoConnect: true);
		if (Application.loadedLevelName == "FreeRun3")
		{
			GameKitBinding.initializeSessionForOnlineOnly("13141001003", GameKitBinding.getPeerId());
		}
		else if (Application.loadedLevelName == "FreeRun4")
		{
			GameKitBinding.initializeSessionForOnlineOnly("13141001004", GameKitBinding.getPeerId());
		}
