	public void TimeOutCheckLoop()
	{
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId != "null")
			{
				otherPlayerTimeOutCount[i]++;
			}
			if (otherPlayerTimeOutCount[i] >= 300)
			{
				RemovePlayer(otherPlayersInfoList[i].mId);
				otherPlayerTimeOutCount[i] = 0;
			}
		}
	}

	public void UpdateServerIdOnline()
	{
		int num = 2555;
		if (myPlayerInfo.mId != "null")
		{
			num = int.Parse(myPlayerInfo.mId);
		}
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId != "null")
			{
				num = Math.Min(num, int.Parse(otherPlayersInfoList[i].mId));
			}
		}
		if (num == 2555 && myPlayerInfo.mId != "null")
		{
			serverId = myPlayerInfo.mId;
		}
		else
		{
			serverId = num.ToString();
		}
	}

	public void SendStrongholdGetMessage(int strongholdId)
	{
		if (myModeInfo.mCurMode != GrowthGameModeTag.tStronghold)
		{
			return;
		}
		if (myPlayerInfo.mId == serverId)
		{
			if (strongholdId == 1)
			{
				if (myPlayerInfo.mTeam == TeamType.Cop)
				{
					myModeInfo.mStrongholdInfo.holdState_1 = StrongholdHoldState.copHold;
				}
				else if (myPlayerInfo.mTeam == TeamType.Robber)
				{
					myModeInfo.mStrongholdInfo.holdState_1 = StrongholdHoldState.robberHold;
				}
			}
			if (strongholdId == 2)
			{
				if (myPlayerInfo.mTeam == TeamType.Cop)
				{
					myModeInfo.mStrongholdInfo.holdState_2 = StrongholdHoldState.copHold;
				}
				else if (myPlayerInfo.mTeam == TeamType.Robber)
				{
					myModeInfo.mStrongholdInfo.holdState_2 = StrongholdHoldState.robberHold;
				}
			}
			BroadcastMessageOnline(myPlayerInfo.mNickName + " occupy a stronghold!");
		}
		else
		{
			sendMessageToPeersAdapt(new string[1] { serverId }, ((Object)((Component)this).gameObject).name, "SetStrongholdGetFromClient", strongholdId.ToString() + '@' + myPlayerInfo.mId, reliably: false);
		}
	}

	public void SendKillingCompetitionGetMessage()
	{
		if (myModeInfo.mCurMode != GrowthGameModeTag.tKillingCompetition)
		{
			return;
		}
		if (myPlayerInfo.mId == serverId)
		{
			if (myPlayerInfo.mTeam == TeamType.Cop)
			{
				myModeInfo.mKillingCompetitionInfo.copKilling++;
			}
			else if (myPlayerInfo.mTeam == TeamType.Robber)
			{
				myModeInfo.mKillingCompetitionInfo.robberKilling++;
			}
		}
		else
		{
			string[] peerIds = new string[1] { serverId };
			int num = 0;
			num = ((myPlayerInfo.mTeam == TeamType.Cop) ? 1 : 2);
			sendMessageToPeersAdapt(peerIds, ((Object)((Component)this).gameObject).name, "SetKillingCompetitionGetFromClient", num.ToString(), reliably: false);
		}
	}

	public void SetStrongholdGetFromClient(string strongholdIdStr)
	{
		if (myModeInfo.mCurMode != GrowthGameModeTag.tStronghold)
		{
			return;
		}
		string[] array = strongholdIdStr.Split('@');
		int num = int.Parse(array[0]);
		string text = string.Empty;
		TeamType teamType = TeamType.Nil;
		for (int i = 0; i < 20; i++)
		{
			if (otherPlayersInfoList[i].mId == array[1])
			{
				text = otherPlayersInfoList[i].mNickName;
				teamType = otherPlayersInfoList[i].mTeam;
				break;
			}
		}
		if (myPlayerInfo.mId == serverId)
		{
			if (num == 1)
			{
				switch (teamType)
				{
				case TeamType.Cop:
					myModeInfo.mStrongholdInfo.holdState_1 = StrongholdHoldState.copHold;
					break;
				case TeamType.Robber:
					myModeInfo.mStrongholdInfo.holdState_1 = StrongholdHoldState.robberHold;
					break;
				}
			}
			if (num == 2)
			{
				switch (teamType)
				{
				case TeamType.Cop:
					myModeInfo.mStrongholdInfo.holdState_2 = StrongholdHoldState.copHold;
					break;
				case TeamType.Robber:
					myModeInfo.mStrongholdInfo.holdState_2 = StrongholdHoldState.robberHold;
					break;
				}
			}
		}
		BroadcastMessageOnline(text + " occupy a stronghold!");
	}

	public void SetKillingCompetitionGetFromClient(string myTeamType)
	{
		if (myModeInfo.mCurMode == GrowthGameModeTag.tKillingCompetition && myPlayerInfo.mId == serverId)
		{
			if (int.Parse(myTeamType) == 1)
			{
				myModeInfo.mKillingCompetitionInfo.copKilling++;
			}
			else if (int.Parse(myTeamType) == 2)
			{
				myModeInfo.mKillingCompetitionInfo.robberKilling++;
			}
		}
	}

	public void StrongholdResourcesChk()
	{
		shTimeCount += Time.deltaTime;
		if (!(shTimeCount >= SH_MODE_CUT_RATE))
		{
			return;
		}
		if (myModeInfo.mStrongholdInfo.holdState_1 == myModeInfo.mStrongholdInfo.holdState_2)
		{
			if (myModeInfo.mStrongholdInfo.holdState_1 == StrongholdHoldState.copHold)
			{
				if (myModeInfo.mStrongholdInfo.robberResource > 0)
				{
					myModeInfo.mStrongholdInfo.robberResource -= 3;
					if (myModeInfo.mStrongholdInfo.robberResource < 0)
					{
						myModeInfo.mStrongholdInfo.robberResource = 0;
					}
				}
			}
			else if (myModeInfo.mStrongholdInfo.copResource > 0)
			{
				myModeInfo.mStrongholdInfo.copResource -= 3;
				if (myModeInfo.mStrongholdInfo.copResource < 0)
				{
					myModeInfo.mStrongholdInfo.copResource = 0;
				}
			}
		}
		else
		{
			myModeInfo.mStrongholdInfo.robberResource--;
			myModeInfo.mStrongholdInfo.copResource--;
			if (myModeInfo.mStrongholdInfo.robberResource < 0)
			{
				myModeInfo.mStrongholdInfo.robberResource = 0;
			}
			if (myModeInfo.mStrongholdInfo.copResource < 0)
			{
				myModeInfo.mStrongholdInfo.copResource = 0;
			}
		}
		shTimeCount = 0f;
	}

	public bool StrongholdRoundOverChk()
	{
		if (myModeInfo.mStrongholdInfo.robberResource <= 0 || myModeInfo.mStrongholdInfo.copResource <= 0)
		{
			return true;
		}
		return false;
	}

	public bool KillingCompetitionRoundOverChk()
	{
		if (myModeInfo.mKillingCompetitionInfo.robberKilling >= myModeInfo.mKillingCompetitionInfo.MAXKilling || myModeInfo.mKillingCompetitionInfo.copKilling >= myModeInfo.mKillingCompetitionInfo.MAXKilling)
		{
			return true;
		}
		return false;
	}

	public void CalcRoundResultForStrongholdMode(TeamType winTeam)
	{
		if (myPlayerInfo.mTeam == TeamType.Cop)
		{
			copRankInfoList.Add(myPlayerInfo);
		}
		else
		{
			robberRankInfoList.Add(myPlayerInfo);
		}
		for (int i = 0; i < otherPlayersInfoList.Length; i++)
		{
			if (otherPlayersInfoList[i].mTeam == TeamType.Cop)
			{
				if (copRankInfoList.Count == 0)
				{
					copRankInfoList.Add(otherPlayersInfoList[i]);
					continue;
				}
				int count = copRankInfoList.Count;
				for (int j = 0; j < count; j++)
				{
					if (otherPlayersInfoList[i].mKillNum * 2 - otherPlayersInfoList[i].mDeadNum * 1 > copRankInfoList[j].mKillNum * 2 - copRankInfoList[j].mDeadNum * 1)
					{
						copRankInfoList.Insert(j, otherPlayersInfoList[i]);
						break;
					}
					if (otherPlayersInfoList[i].mKillNum * 2 - otherPlayersInfoList[i].mDeadNum * 1 == copRankInfoList[j].mKillNum * 2 - copRankInfoList[j].mDeadNum * 1 && int.Parse(otherPlayersInfoList[i].mId) > int.Parse(copRankInfoList[j].mId))
					{
						copRankInfoList.Insert(j, otherPlayersInfoList[i]);
						break;
					}
					if (j == count - 1)
					{
						copRankInfoList.Add(otherPlayersInfoList[i]);
					}
				}
			}
			else
			{
				if (otherPlayersInfoList[i].mTeam != TeamType.Robber)
				{
					continue;
				}
				if (robberRankInfoList.Count == 0)
				{
					robberRankInfoList.Add(otherPlayersInfoList[i]);
					continue;
				}
				int count2 = robberRankInfoList.Count;
				for (int k = 0; k < count2; k++)
				{
					if (otherPlayersInfoList[i].mKillNum * 2 - otherPlayersInfoList[i].mDeadNum * 1 > robberRankInfoList[k].mKillNum * 2 - robberRankInfoList[k].mDeadNum * 1)
					{
						robberRankInfoList.Insert(k, otherPlayersInfoList[i]);
						break;
					}
					if (otherPlayersInfoList[i].mKillNum * 2 - otherPlayersInfoList[i].mDeadNum * 1 == robberRankInfoList[k].mKillNum * 2 - robberRankInfoList[k].mDeadNum * 1 && int.Parse(otherPlayersInfoList[i].mId) > int.Parse(robberRankInfoList[k].mId))
					{
						robberRankInfoList.Insert(k, otherPlayersInfoList[i]);
						break;
					}
					if (k == count2 - 1)
					{
						robberRankInfoList.Add(otherPlayersInfoList[i]);
					}
				}
			}
		}
		for (int l = 0; l < copRankInfoList.Count; l++)
		{
			GameValueForRatingCalc gameValueForRatingCalc = new GameValueForRatingCalc(GrowthGameModeTag.tStronghold);
			gameValueForRatingCalc.mShModeValue.DeadNum = copRankInfoList[l].mDeadNum;
			gameValueForRatingCalc.mShModeValue.enemyTeamTotalPlayerNum = mRobberTeamPlayers;
			gameValueForRatingCalc.mShModeValue.isWinner = winTeam == copRankInfoList[l].mTeam;
			gameValueForRatingCalc.mShModeValue.killNum = copRankInfoList[l].mKillNum;
			gameValueForRatingCalc.mShModeValue.myTeamTotalPlayerNum = mCopTeamPlayers;
			gameValueForRatingCalc.mShModeValue.rankInMyTeam = l + 1;
			copRatingList.Add(GrowthManagerKit.GetOncePlayRating(gameValueForRatingCalc));
			if (copRankInfoList[l].mId == myPlayerInfo.mId)
			{
				copRatingBroadcastVerifyList.Add(item: true);
				copNewRoundEnableBroadcastVerifyList.Add(item: true);
				myRating = GrowthManagerKit.GetOncePlayRating(gameValueForRatingCalc);
			}
			else
			{
				copRatingBroadcastVerifyList.Add(item: false);
				copNewRoundEnableBroadcastVerifyList.Add(item: false);
			}
		}
		for (int m = 0; m < robberRankInfoList.Count; m++)
		{
			GameValueForRatingCalc gameValueForRatingCalc2 = new GameValueForRatingCalc(GrowthGameModeTag.tStronghold);
			gameValueForRatingCalc2.mShModeValue.DeadNum = robberRankInfoList[m].mDeadNum;
			gameValueForRatingCalc2.mShModeValue.enemyTeamTotalPlayerNum = mCopTeamPlayers;
			gameValueForRatingCalc2.mShModeValue.isWinner = winTeam == robberRankInfoList[m].mTeam;
			gameValueForRatingCalc2.mShModeValue.killNum = robberRankInfoList[m].mKillNum;
			gameValueForRatingCalc2.mShModeValue.myTeamTotalPlayerNum = mRobberTeamPlayers;
			gameValueForRatingCalc2.mShModeValue.rankInMyTeam = m + 1;
			robberRatingList.Add(GrowthManagerKit.GetOncePlayRating(gameValueForRatingCalc2));
			if (robberRankInfoList[m].mId == myPlayerInfo.mId)
			{
				robberRatingBroadcastVerifyList.Add(item: true);
				robberNewRoundEnableBroadcastVerifyList.Add(item: true);
				myRating = GrowthManagerKit.GetOncePlayRating(gameValueForRatingCalc2);
			}
			else
			{
				robberRatingBroadcastVerifyList.Add(item: false);
				robberNewRoundEnableBroadcastVerifyList.Add(item: false);
			}
		}
	}

