	public void SetMyRoundRatingForStrongholdMode(string param)
	{
		string[] array = param.Split('@');
		int num = int.Parse(array[1]);
		TeamType teamType = (TeamType)int.Parse(array[2]);
		myRoundRating = (GrowthGameRatingTag)int.Parse(array[0]);
		TeamType teamType2 = (TeamType)int.Parse(array[3]);
		if (!isClacedResult)
		{
			CalcRoundResultForStrongholdMode(teamType2);
			if (teamType2 == myPlayerInfo.mTeam)
			{
				GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalStrongholdModeVictory, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalStrongholdModeVictory));
			}
			int num2 = myPlayerInfo.mKillNum - myPlayerInfo.mDeadNum;
			if (num2 <= 0)
			{
				num2 = 0;
			}
			GrowthManagerKit.AddCoins(GrowthManagerKit.GetOncePlayCoinsReward(GrowthGameModeTag.tStronghold, myRating) + num2 + 10);
			GrowthManagerKit.AddCharacterExp(GrowthManagerKit.GetOncePlayExpReward(GrowthGameModeTag.tStronghold, myRating));
			UIMenuDirectorExt.mInstance.PopResultPanelEvent(teamType2, myPlayerInfo, myRoundRating, copRatingList, robberRatingList, copRankInfoList, robberRankInfoList);
			isClacedResult = true;
		}
		string[] peerIds = new string[1] { serverId };
		string name = ((Object)((Component)this).gameObject).name;
		string text = num.ToString();
		object obj = '@';
		int num3 = (int)teamType;
		sendMessageToPeersAdapt(peerIds, name, "RatingBroadcastVerifyForStrongholdMode", string.Concat(text, obj, num3.ToString()), reliably: false);
		myPlayerInfo.mStatus = PlayerStatus.idle;
		base.photonView.RPC("OtherPlayersInfoToLocationOnline", PhotonTargets.Others, PlayerInfo.PlayerInfoToString(myPlayerInfo));
		((MonoBehaviour)this).StopAllCoroutines();
	}

