	public void StrongholdModeAllFrameProcess()
	{
		if (Time.frameCount % 32 == 0)
		{
			UpdateServerIdOnline();
		}
		if (!(serverId == myPlayerInfo.mId))
		{
			return;
		}
		StrongholdResourcesChk();
		if (roundOverChkStatusFlag == 0 && StrongholdRoundOverChk())
		{
			roundOverChkStatusFlag = 1;
			if (myModeInfo.mStrongholdInfo.copResource <= 0 && myModeInfo.mStrongholdInfo.robberResource <= 0)
			{
				switch (Random.Range(1, 3))
				{
				case 1:
					CalcRoundResultForStrongholdMode(TeamType.Robber);
					winTeam = TeamType.Robber;
					break;
				case 2:
					CalcRoundResultForStrongholdMode(TeamType.Cop);
					winTeam = TeamType.Cop;
					break;
				}
			}
			else if (myModeInfo.mStrongholdInfo.copResource <= 0)
			{
				CalcRoundResultForStrongholdMode(TeamType.Robber);
				winTeam = TeamType.Robber;
			}
			else if (myModeInfo.mStrongholdInfo.robberResource <= 0)
			{
				CalcRoundResultForStrongholdMode(TeamType.Cop);
				winTeam = TeamType.Cop;
			}
		}
		if (roundOverChkStatusFlag == 1)
		{
			shVerifyTimeCount += Time.deltaTime;
			if (shVerifyTimeCount >= SH_MODE_VERIFY_RATE)
			{
				if (RatingBroadcastAndVerifyForStrongholdMode())
				{
					roundOverChkStatusFlag = 2;
					myPlayerInfo.mStatus = PlayerStatus.idle;
					base.photonView.RPC("OtherPlayersInfoToLocationOnline", PhotonTargets.Others, PlayerInfo.PlayerInfoToString(myPlayerInfo));
					((MonoBehaviour)this).StopAllCoroutines();
					if (!isClacedResult)
					{
						if (winTeam == myPlayerInfo.mTeam)
						{
							GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalStrongholdModeVictory, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalStrongholdModeVictory));
						}
						int num = myPlayerInfo.mKillNum - myPlayerInfo.mDeadNum;
						if (num <= 0)
						{
							num = 0;
						}
						GrowthManagerKit.AddCoins(GrowthManagerKit.GetOncePlayCoinsReward(GrowthGameModeTag.tStronghold, myRating) + num + 10);
						GrowthManagerKit.AddCharacterExp(GrowthManagerKit.GetOncePlayExpReward(GrowthGameModeTag.tStronghold, myRating));
						UIMenuDirectorExt.mInstance.PopResultPanelEvent(winTeam, myPlayerInfo, myRating, copRatingList, robberRatingList, copRankInfoList, robberRankInfoList);
						isClacedResult = true;
					}
				}
				shVerifyTimeCount = 0f;
			}
		}
		if (roundOverChkStatusFlag != 2)
		{
			return;
		}
		shVerifyTimeCount += Time.deltaTime;
		if (shVerifyTimeCount >= SH_MODE_VERIFY_RATE)
		{
			if (NewRoundEnableBroadcastAndVerifyForStrongholdMode())
			{
				roundOverChkStatusFlag = 3;
				UIMenuDirectorExt.mInstance.EnableNewRoundBtn();
			}
			shVerifyTimeCount = 0f;
		}
	}

	public void KillingCompetitionModeAllFrameProcess()
	{
		if (Time.frameCount % 32 == 0)
		{
			UpdateServerIdOnline();
		}
		if (!(serverId == myPlayerInfo.mId))
		{
			return;
		}
		if (roundOverChkStatusFlag == 0 && KillingCompetitionRoundOverChk())
		{
			roundOverChkStatusFlag = 1;
			if (myModeInfo.mKillingCompetitionInfo.copKilling >= myModeInfo.mKillingCompetitionInfo.MAXKilling)
			{
				CalcRoundResultForKillingCompetitionMode(TeamType.Cop);
				winTeam = TeamType.Cop;
			}
			else if (myModeInfo.mKillingCompetitionInfo.robberKilling >= myModeInfo.mKillingCompetitionInfo.MAXKilling)
			{
				CalcRoundResultForKillingCompetitionMode(TeamType.Robber);
				winTeam = TeamType.Robber;
			}
		}
		if (roundOverChkStatusFlag == 1)
		{
			shVerifyTimeCount += Time.deltaTime;
			if (shVerifyTimeCount >= SH_MODE_VERIFY_RATE)
			{
				if (RatingBroadcastAndVerifyForKillingCompetitionMode())
				{
					roundOverChkStatusFlag = 2;
					myPlayerInfo.mStatus = PlayerStatus.idle;
					base.photonView.RPC("OtherPlayersInfoToLocationOnline", PhotonTargets.Others, PlayerInfo.PlayerInfoToString(myPlayerInfo));
					((MonoBehaviour)this).StopAllCoroutines();
					if (!isClacedResult)
					{
						if (winTeam == myPlayerInfo.mTeam)
						{
							GrowthManagerKit.SetFightingStatisticsValue(FightingStatisticsTag.tTotalKillingCompetitionModeVictory, 1 + GrowthManagerKit.GetFightingStatisticsValue(FightingStatisticsTag.tTotalKillingCompetitionModeVictory));
						}
						int num = myPlayerInfo.mKillNum - myPlayerInfo.mDeadNum;
						if (num <= 0)
						{
							num = 0;
						}
						GrowthManagerKit.AddCoins(GrowthManagerKit.GetOncePlayCoinsReward(GrowthGameModeTag.tKillingCompetition, myRating) + num + 10);
						GrowthManagerKit.AddCharacterExp(GrowthManagerKit.GetOncePlayExpReward(GrowthGameModeTag.tKillingCompetition, myRating));
						UIMenuDirectorExt.mInstance.PopResultPanelEvent(winTeam, myPlayerInfo, myRating, copRatingList, robberRatingList, copRankInfoList, robberRankInfoList);
						isClacedResult = true;
					}
				}
				shVerifyTimeCount = 0f;
			}
		}
		if (roundOverChkStatusFlag != 2)
		{
			return;
		}
		shVerifyTimeCount += Time.deltaTime;
		if (shVerifyTimeCount >= SH_MODE_VERIFY_RATE)
		{
			if (NewRoundEnableBroadcastAndVerifyForKillingCompetitionMode())
			{
				roundOverChkStatusFlag = 3;
				UIMenuDirectorExt.mInstance.EnableNewRoundBtn();
			}
			shVerifyTimeCount = 0f;
		}
	}
