public class CNRRoomInfo : MonoBehaviour
{
	public RoomInfo mRoomInfo;

	public bool toBeDestroyed;

	public bool hasBeenSetted;

	public string mapName;

	public string roomName;

	public int playerCount;

	public UILabel mapNameLabel;

	public UILabel PlayerNumberLabel;

	public UILabel roomNameLabel;

	public UISprite mapLogoSprite;

	public UISprite modeLogoSprite;

	private CNRRoomInfo(RoomInfo room)
	{
		mRoomInfo = room;
	}

	public string GetRealmapName(string sceneName)
	{
		return sceneName switch
		{
			"FreeRun3_1" => "Death Platform", 
			"FreeRun4_1" => "Warehouse", 
			"FreeRun5_1" => "Snow", 
			"FreeRun6_1" => "Dusty", 
			"FreeRun7_1" => "Knife Factory", 
			"FreeRun8_1" => "Desert A", 
			"FreeRun9_1" => "Desert B", 
			"FreeRun10_1" => "Chess Hero", 
			"FreeRun11_1" => "Maze Village", 
			"FreeRun12_1" => "Christmas Town", 
			_ => sceneName, 
		};
	}

	public string GetRealmapSpriteName(string sceneName)
	{
		return sceneName switch
		{
			"FreeRun3_1" => "map_1", 
			"FreeRun4_1" => "map_2", 
			"FreeRun5_1" => "map_3", 
			"FreeRun6_1" => "map_4", 
			"FreeRun7_1" => "map_5", 
			"FreeRun8_1" => "map_6", 
			"FreeRun9_1" => "map_7", 
			"FreeRun10_1" => "map_8", 
			"FreeRun11_1" => "map_9", 
			"FreeRun12_1" => "map_10", 
			_ => sceneName, 
		};
	}

	private void Start()
	{
		((Component)this).gameObject.GetComponent<UIDragCamera>().draggableCamera = GameObject.Find("View Camera").GetComponent<UIDraggableCamera>();
	}

	private void Update()
	{
		if (toBeDestroyed)
		{
		}
		if (mRoomInfo != null && !hasBeenSetted)
		{
			mapNameLabel.text = GetRealmapName((string)mRoomInfo.customProperties["map"]);
			roomNameLabel.text = mRoomInfo.name;
			mapLogoSprite.spriteName = GetRealmapSpriteName((string)mRoomInfo.customProperties["map"]);
			mapLogoSprite.MarkAsChanged();
			hasBeenSetted = true;
			switch ((GrowthGameModeTag)int.Parse((string)mRoomInfo.customProperties["mode"]))
			{
			case GrowthGameModeTag.tTeamDeathMatch:
				modeLogoSprite.spriteName = "ModeLogoTeamDeathMatch";
				modeLogoSprite.MarkAsChanged();
				break;
			case GrowthGameModeTag.tStronghold:
				modeLogoSprite.spriteName = "ModeLogoStronghold";
				modeLogoSprite.MarkAsChanged();
				break;
			case GrowthGameModeTag.tKillingCompetition:
				modeLogoSprite.spriteName = "ModeLogoKillingCompetition";
				modeLogoSprite.MarkAsChanged();
				break;
			}
		}
		PlayerNumberLabel.text = playerCount + "/" + mRoomInfo.maxPlayers;
	}

	private void OnClick()
	{
		if (((Behaviour)this).enabled)
		{
			MultiplayerSelectDirector.mInstance.WWJoinRoomNStart(mRoomInfo);
		}
	}
}
public class LobbyButtonEvent : MonoBehaviour
{
	public enum ButtonName
	{
		Nil,
		CopSelectButton,
		RobberSelectButton,
		StartButton,
		RefreshButton,
		WWStartButton,
		WWCopSelectButton,
		WWRobberSelectButton
	}

	public ButtonName mButtonName;

	public UILabel mTeamChangeTipsLabel;

	private void OnClick()
	{
		if (!((Behaviour)this).enabled)
		{
			return;
		}
		switch (mButtonName)
		{
		case ButtonName.CopSelectButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus != ConnectStatus.WaitForOtherPlayers)
			{
				CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Cop;
				CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = ConnectStatus.Ready;
			}
			break;
		case ButtonName.RobberSelectButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus != ConnectStatus.WaitForOtherPlayers)
			{
				CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Robber;
				CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = ConnectStatus.Ready;
			}
			break;
		case ButtonName.StartButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.ConnectedToServer)
			{
				if (Random.Range(1, 3) == 1)
				{
					CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Cop;
				}
				else
				{
					CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Robber;
				}
				CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = ConnectStatus.WaitForOtherPlayers;
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.Ready)
			{
				CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = ConnectStatus.WaitForOtherPlayers;
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.WaitForOtherPlayers)
			{
				CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = ConnectStatus.Ready;
			}
			break;
		case ButtonName.RefreshButton:
			CNRMultiplayerManager.mInstance.Refresh();
			break;
		case ButtonName.WWStartButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Nil)
			{
				if (CNRMultiplayerManager.mInstance.mCopTeamPlayers < CNRMultiplayerManager.mInstance.mRobberTeamPlayers)
				{
					CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Cop;
				}
				else
				{
					CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Robber;
				}
			}
			CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = ConnectStatus.WaitForOtherPlayers;
			break;
		case ButtonName.WWCopSelectButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam != TeamType.Cop)
			{
				if (CNRMultiplayerManager.mInstance.mCopTeamPlayers - CNRMultiplayerManager.mInstance.mRobberTeamPlayers <= 0)
				{
					CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Cop;
					CNRMultiplayerManager.mInstance.myPlayerLogic.RandomPosition();
					CNRMultiplayerManager.mInstance.SynTeamNumber();
				}
				else
				{
					mTeamChangeTipsLabel.text = "Change team error: too many cops!";
				}
			}
			break;
		case ButtonName.WWRobberSelectButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam != TeamType.Robber)
			{
				if (CNRMultiplayerManager.mInstance.mRobberTeamPlayers - CNRMultiplayerManager.mInstance.mCopTeamPlayers <= 0)
				{
					CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam = TeamType.Robber;
					CNRMultiplayerManager.mInstance.myPlayerLogic.RandomPosition();
					CNRMultiplayerManager.mInstance.SynTeamNumber();
				}
				else
				{
					mTeamChangeTipsLabel.text = "Change team error: too many robbers!";
				}
			}
			break;
		}
	}

	private void Start()
	{
	}

	private void Update()
	{
	}
}
public class LobbyDataReader : MonoBehaviour
{
	public enum DataName
	{
		Nil,
		ServerConnectedNum,
		CopSelectButton,
		RobberSelectButton,
		StartButton,
		MyStatusLabel,
		PlayerList,
		GameRoundTimeRest,
		PlayerListInGame,
		WWServerConnectedNum,
		WWStartButton,
		WWPlayerList
	}

	public DataName mData;

	private UILabel[] mPlayersStatus = new UILabel[20];

	private void Start()
	{
		if (mData == DataName.PlayerList || mData == DataName.PlayerListInGame)
		{
			for (int i = 0; i < mPlayersStatus.Length; i++)
			{
				mPlayersStatus[i] = ((Component)((Component)this).transform.FindChild("PlayerStatusLabel_" + (i + 1))).GetComponent<UILabel>();
			}
		}
	}

	private void Update()
	{
		switch (mData)
		{
		case DataName.ServerConnectedNum:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Local Server - WiFi (" + (GameKitManager.connectedPeers.Count + 1) + "/16)";
			break;
		case DataName.CopSelectButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop)
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNullS_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNullS_2";
			}
			else
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNull_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNull_2";
			}
			((Component)this).gameObject.GetComponentInChildren<UISprite>().MarkAsChanged();
			break;
		case DataName.RobberSelectButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber)
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNullS_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNullS_2";
			}
			else
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNull_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNull_2";
			}
			((Component)this).gameObject.GetComponentInChildren<UISprite>().MarkAsChanged();
			break;
		case DataName.StartButton:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.ConnectedToServer)
			{
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Quick Start";
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.Ready)
			{
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Start";
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.WaitForOtherPlayers)
			{
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Cancel";
			}
			break;
		case DataName.MyStatusLabel:
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.ConnectedToServer)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = "Status: In Role Select...";
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.Ready)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = "Status: Ready...";
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == ConnectStatus.WaitForOtherPlayers)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = "Status: Wait For Other Players...";
			}
			else
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = string.Empty;
			}
			break;
		case DataName.PlayerList:
		{
			for (int m = 0; m < CNRMultiplayerManager.mInstance.otherPlayersInfoList.Length; m++)
			{
				ConnectStatus mConnnectStatus3 = CNRMultiplayerManager.mInstance.otherPlayersInfoList[m].mConnnectStatus;
				string text = CNRMultiplayerManager.mInstance.otherPlayersInfoList[m].mTeam.ToString();
				switch (mConnnectStatus3)
				{
				case ConnectStatus.Nil:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": NA";
					break;
				case ConnectStatus.ConnectedToServer:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Connected";
					break;
				case ConnectStatus.Ready:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Select-" + text;
					break;
				case ConnectStatus.WaitForOtherPlayers:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Ready-" + text;
					break;
				case ConnectStatus.InGame:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": InGame-" + text;
					break;
				case ConnectStatus.EndGame:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": EndGame";
					break;
				case ConnectStatus.DisconnectedToServer:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Disconnected";
					break;
				}
			}
			break;
		}
		case DataName.GameRoundTimeRest:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Time - " + (int)CNRMultiplayerManager.mInstance.mGameRoundTimeRest / 60 + " : " + (int)CNRMultiplayerManager.mInstance.mGameRoundTimeRest % 60;
			break;
		case DataName.PlayerListInGame:
		{
			int num3 = 0;
			int num4 = 10;
			for (int k = 0; k < mPlayersStatus.Length; k++)
			{
				mPlayersStatus[k].text = string.Empty;
			}
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop)
			{
				mPlayersStatus[num3].text = CNRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num3++;
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber)
			{
				mPlayersStatus[num4].text = CNRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num4++;
			}
			for (int l = 0; l < CNRMultiplayerManager.mInstance.otherPlayersInfoList.Length; l++)
			{
				ConnectStatus mConnnectStatus2 = CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mConnnectStatus;
				TeamType mTeam2 = CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mTeam;
				if (mConnnectStatus2 == ConnectStatus.Nil || mConnnectStatus2 != ConnectStatus.InGame)
				{
					continue;
				}
				switch (mTeam2)
				{
				case TeamType.Cop:
					mPlayersStatus[num3].text = CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mDeadNum;
					num3++;
					if (num3 > 19)
					{
						num3 = 19;
					}
					break;
				case TeamType.Robber:
					mPlayersStatus[num4].text = CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[l].mDeadNum;
					num4++;
					if (num4 > 19)
					{
						num4 = 19;
					}
					break;
				}
			}
			break;
		}
		case DataName.WWServerConnectedNum:
			if (PhotonNetwork.room != null)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = PhotonNetwork.room.name + " (" + PhotonNetwork.room.playerCount.ToString() + "/" + PhotonNetwork.room.maxPlayers + ")";
			}
			break;
		case DataName.WWStartButton:
			((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Go";
			break;
		case DataName.WWPlayerList:
		{
			int num = 0;
			int num2 = 10;
			for (int i = 0; i < mPlayersStatus.Length; i++)
			{
				mPlayersStatus[i].text = string.Empty;
			}
			if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop)
			{
				mPlayersStatus[num].text = CNRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num++;
			}
			else if (CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber)
			{
				mPlayersStatus[num2].text = CNRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num2++;
			}
			for (int j = 0; j < CNRMultiplayerManager.mInstance.otherPlayersInfoList.Length; j++)
			{
				ConnectStatus mConnnectStatus = CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mConnnectStatus;
				TeamType mTeam = CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mTeam;
				if (mConnnectStatus == ConnectStatus.Nil || mConnnectStatus != ConnectStatus.InGame)
				{
					continue;
				}
				switch (mTeam)
				{
				case TeamType.Cop:
					mPlayersStatus[num].text = CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mDeadNum;
					num++;
					if (num > 19)
					{
						num = 19;
					}
					break;
				case TeamType.Robber:
					mPlayersStatus[num2].text = CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mNickName + " : Kill-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mKillNum + " | Dead-" + CNRMultiplayerManager.mInstance.otherPlayersInfoList[j].mDeadNum;
					num2++;
					if (num2 > 19)
					{
						num2 = 19;
					}
					break;
				}
			}
			break;
		}
		}
	}
