	private string MovementAnimation;

	private string currentBlendedAnimation;

	private string currentWeaponName;

	private string currentAnimation = string.Empty;

	private string blendedAnimation = string.Empty;

	private string prevWeap = string.Empty;

	private void Start()
	{
		if (base.photonView.isMine)
		{
			Object.Destroy((Object)(object)headLookController);
		}
	}

	private void OnPhotonSerializeView(PhotonStream stream, PhotonMessageInfo info)
	{
		if (stream.isWriting)
		{
			stream.SendNext(((Object)animationSyncHelper).name);
			stream.SendNext(((Object)animationForHands).name);
			stream.SendNext(((Object)activeWeapon).name);
		}
		else
		{
			currentAnimation = (string)stream.ReceiveNext();
			blendedAnimation = (string)stream.ReceiveNext();
			currentWeaponName = (string)stream.ReceiveNext();
		}
	}

	private void Update()
	{
		if (base.photonView.isMine)
		{
			return;
		}
		if (MovementAnimation != currentAnimation)
		{
			MovementAnimation = currentAnimation;
