	{
		messages.Clear();
		((Behaviour)this).enabled = false;
	}

	private void OnJoinedRoom()
	{
		((Behaviour)this).enabled = true;
	}

	private void OnCreatedRoom()
	{
		((Behaviour)this).enabled = true;
	}
