{
	public GItemId mId;

	public string mName;

	public GItemPurchaseType mPurchasedType;

	public int mUnlockCLevel;

	public int mSinglePrice;

	public string mNameDisplay;

	public string mInGameLogoSpriteNameFg;

	public string mInGameLogoSpriteNameBg;

	public bool mIsEnabled;

	public float mAutoSupplyTimeRest;

	public float[] mHeadshotIgnoreRate = new float[2];

	public float[] mBodyDamageDefendRate = new float[2];

	public int mDurabilityInGame = 100;

	public bool mIsInAutoSupplyStatus;

	public int[] mAutoSupplyTimeFillLevel = new int[5] { 1, 2, 5, 12, 24 };

	public int GetTimeFillPrice(int hour)
	{
		int num = 100;
		int num2 = 12;
		return hour * num2 * mSinglePrice * hour switch
		{
			1 => 100, 
			2 => 95, 
			5 => 90, 
			12 => 80, 
			24 => 70, 
			_ => 100, 
		} / 100 / 10 * 10;
	}

	public string GetTimeFillOffSaleRateStr(int hour)
	{
		int num = 100;
		num = hour switch
		{
			1 => 100, 
			2 => 95, 
			5 => 90, 
			12 => 80, 
			24 => 70, 
			_ => 100, 
		};
		if (num == 100)
		{
			return string.Empty;
		}
		return "<" + (100 - num) + "% OFF>";
	}

	public void AddAutoSupplyTime(float secondAdd)
	{
		bool flag = true;
		for (int i = 0; i < UserDataController.AllArmorNameList.Length; i++)
		{
			if (UserDataController.AllArmorNameList[i] == mName)
			{
				flag = false;
				break;
			}
		}
		if (!flag)
		{
			UserDataController.SetArmorAutoSupplyTime(mName, UserDataController.GetArmorAutoSupplyTime(mName) + secondAdd);
		}
	}

	public void AutoSupplyTimeDecreaseUpdate(float deltaTime)
	{
		float armorAutoSupplyTime = UserDataController.GetArmorAutoSupplyTime(mName);
		if (armorAutoSupplyTime <= 0f)
		{
			mIsInAutoSupplyStatus = false;
			return;
		}
		UserDataController.SetArmorAutoSupplyTime(mName, Mathf.Max(armorAutoSupplyTime - deltaTime, 0f));
		mIsInAutoSupplyStatus = true;
	}

	public float GetAutoSupplyTimeRest()
	{
		return mAutoSupplyTimeRest;
	}
}
