		GItemId id = mItemBaseValue.mItemDict_kName_vId[name];
		return UserDataController.GetItemInfo(name, id, isSearchForUpgrade: true);
	}

	public bool UpgradeWeaponByName(string name)
	{
		GItemInfo itemInfoByName = GetItemInfoByName(name);
		int mPrice = itemInfoByName.mPrice;
		if (itemInfoByName.mPurchasedType == GItemPurchaseType.CoinsPurchase)
		{
			if (mPrice <= UserDataController.GetCoins())
			{
				if (UserDataController.UpgradeWeapon(name, 1))
				{
					SubCoins(mPrice);
					return true;
				}
				return false;
			}
			return false;
		}
		if (itemInfoByName.mPurchasedType == GItemPurchaseType.GemPurchase)
		{
			if (mPrice <= UserDataController.GetGems())
			{
				if (UserDataController.UpgradeWeapon(name, 1))
				{
					SubGems(mPrice);
					return true;
				}
				return false;
			}
			return false;
		}
		return false;
	}

	public GSkinItemInfo GetSkinItemInfo(string name)
	{
		GItemId id = mItemBaseValue.mItemDict_kName_vId[name];
		return UserDataController.GetSkinItemInfo(name, id);
	}

	public bool EnableSkin(string name)
	{
		GSkinItemInfo skinItemInfo = GetSkinItemInfo(name);
		int mPrice = skinItemInfo.mPrice;
		if (skinItemInfo.mPurchasedType == GItemPurchaseType.CoinsPurchase)
		{
			if (mPrice <= UserDataController.GetCoins())
			{
				if (UserDataController.EnableSkin(name))
				{
					SubCoins(mPrice);
					return true;
				}
				return false;
			}
			return false;
		}
		if (skinItemInfo.mPurchasedType == GItemPurchaseType.GemPurchase)
		{
			if (mPrice <= UserDataController.GetGems())
			{
				if (UserDataController.EnableSkin(name))
				{
					SubGems(mPrice);
					return true;
				}
				return false;
			}
			return false;
		}
		return false;
	}

