		UserDataController.FirstLoadSetting();
		if ((Object)(object)GameObject.Find(((Object)((Component)this).gameObject).name + "_old") != (Object)null)
		{
			Object.Destroy((Object)(object)GameObject.Find(((Object)((Component)this).gameObject).name + "_old"));
