			}
			rewardUnitInfo.rewardCoins = GrowthBaseValue.mGBV_TotalGoldLikeKillReward[num];
			rewardUnitInfo.rewardDescription = "God Like killing numbers.";
			rewardUnitInfo.rewardHonorName = "God Like Killer";
			break;
		case FightingStatisticsTag.tTotalHeadshotKill:
			for (num = 0; num < GrowthBaseValue.mGBV_TotalHeadshotKillTarget.Length && UserDataController.GetFightingStatisticsValue(FightingStatisticsTag.tTotalHeadshotKill) >= GrowthBaseValue.mGBV_TotalHeadshotKillTarget[num]; num++)
