				}
			}
			num = Math.Min(num, GrowthBaseValue.mGBV_TotalHeadshotKillTarget.Length - 1);
			rewardUnitInfo.rewardLv = num + 1;
			if (rewardUnitInfo.rewardLv == GrowthBaseValue.mGBV_TotalHeadshotKillTarget.Length)
