	public int GetOncePlayExpReward(GrowthGameModeTag gameMode, GrowthGameRatingTag gameRating)
	{
		int num = 0;
		int num2 = 0;
		switch (gameMode)
		{
		case GrowthGameModeTag.tTeamDeathMatch:
			num2 = GrowthBaseValue.mGBV_ModeValue[0];
			break;
		case GrowthGameModeTag.tStronghold:
			num2 = GrowthBaseValue.mGBV_ModeValue[1];
			break;
		case GrowthGameModeTag.tKillingCompetition:
			num2 = GrowthBaseValue.mGBV_ModeValue[2];
			break;
		}
		switch (gameRating)
		{
		case GrowthGameRatingTag.RatingTag_Nil:
			num = GrowthBaseValue.mGBV_RatingValue[0];
			break;
		case GrowthGameRatingTag.RatingTag_F:
			num = GrowthBaseValue.mGBV_RatingValue[1];
			break;
		case GrowthGameRatingTag.RatingTag_E:
			num = GrowthBaseValue.mGBV_RatingValue[2];
			break;
		case GrowthGameRatingTag.RatingTag_D:
			num = GrowthBaseValue.mGBV_RatingValue[3];
			break;
		case GrowthGameRatingTag.RatingTag_C:
			num = GrowthBaseValue.mGBV_RatingValue[4];
			break;
		case GrowthGameRatingTag.RatingTag_B:
			num = GrowthBaseValue.mGBV_RatingValue[5];
			break;
		case GrowthGameRatingTag.RatingTag_A:
			num = GrowthBaseValue.mGBV_RatingValue[6];
			break;
		case GrowthGameRatingTag.RatingTag_S:
			num = GrowthBaseValue.mGBV_RatingValue[7];
			break;
		}
		return num * num2 * 1;
	}

