	private void InitUnlockItemsDict()
	{
		for (int i = 1; i <= 100; i++)
		{
			mUnlockItemsDict_kCLevel_vIds.Add(i, new List<GItemId>());
		}
		for (int j = 1; j <= 10; j++)
		{
			for (int k = 1; k <= 10; k++)
			{
				if ((object)Type.GetType("GItemIdTag_3_" + j + "_" + k) != null)
				{
					int length = Enum.GetNames(Type.GetType("GItemIdTag_3_" + j + "_" + k)).GetLength(0);
					for (int l = 0; l < length; l++)
					{
						int i_ = (int)Enum.GetValues(Type.GetType("GItemIdTag_3_" + j + "_" + k)).GetValue(l);
						GItemId gItemId = new GItemId(j, k, i_, 0);
						Debug.Log((object)(gItemId.mId_1 + "_" + gItemId.mId_2 + "_" + gItemId.mId_3));
						int itemUnlockCLevel = GetItemUnlockCLevel(gItemId);
						mUnlockItemsDict_kCLevel_vIds[itemUnlockCLevel].Add(gItemId);
					}
				}
			}
		}
	}

	public int GetItemEnablePrice(GItemId id)
	{
		int result = -1;
		int num = -1;
		switch (id.mId_1)
		{
		case 1:
			num = mWeaponDict_kId_vRank[id];
			result = mWeaponDict_kRank_vEnablePrice[num];
			break;
		case 2:
			num = mArmorDict_kId_vRank[id];
