	public static int GetRamdonCoinsForAutoGift()
	{
		int num = Random.Range(1, 101);
		int num2 = ((num <= 100 && num > 99) ? Random.Range(20, 31) : ((num <= 99 && num > 97) ? Random.Range(10, 21) : ((num > 97 || num <= 80) ? Random.Range(1, 6) : Random.Range(5, 11))));
		return num2 * 10;
	}

	public static AutoGiftInfo RecevieOneGift()
	{
		AutoGiftInfo autoGiftInfo = new AutoGiftInfo();
		int num = PlayerPrefs.GetInt("ChristmasGiftGetCount", 0);
		int num2 = 0;
		switch (num)
		{
		case 0:
			autoGiftInfo.gType = AutoGiftType.GiftBox;
			autoGiftInfo.num = 1;
			autoGiftInfo.spriteName = "GiftBoxBig";
			break;
		case 1:
			num2 = Random.Range(1, 101);
			if (num2 > 50)
			{
				autoGiftInfo.gType = AutoGiftType.GiftBox;
				autoGiftInfo.num = 1;
				autoGiftInfo.spriteName = "GiftBoxBig";
			}
			else
			{
				autoGiftInfo.gType = AutoGiftType.Coins;
				autoGiftInfo.num = GetRamdonCoinsForAutoGift();
				autoGiftInfo.spriteName = "GiftCoinBig";
			}
			break;
		case 2:
			num2 = Random.Range(1, 101);
			if (num2 > 50)
			{
				autoGiftInfo.gType = AutoGiftType.GiftBox;
				autoGiftInfo.num = 1;
				autoGiftInfo.spriteName = "GiftBoxBig";
			}
			else
			{
				autoGiftInfo.gType = AutoGiftType.Coins;
				autoGiftInfo.num = GetRamdonCoinsForAutoGift();
				autoGiftInfo.spriteName = "GiftCoinBig";
			}
			break;
		case 3:
			num2 = Random.Range(1, 101);
			if (num2 > 70)
			{
				autoGiftInfo.gType = AutoGiftType.GiftBox;
				autoGiftInfo.num = 1;
				autoGiftInfo.spriteName = "GiftBoxBig";
			}
			else
			{
				autoGiftInfo.gType = AutoGiftType.Coins;
				autoGiftInfo.num = GetRamdonCoinsForAutoGift();
				autoGiftInfo.spriteName = "GiftCoinBig";
			}
			break;
		case 4:
			num2 = Random.Range(1, 101);
			if (num2 > 80)
			{
				autoGiftInfo.gType = AutoGiftType.GiftBox;
				autoGiftInfo.num = 1;
				autoGiftInfo.spriteName = "GiftBoxBig";
			}
			else
			{
				autoGiftInfo.gType = AutoGiftType.Coins;
				autoGiftInfo.num = GetRamdonCoinsForAutoGift();
				autoGiftInfo.spriteName = "GiftCoinBig";
			}
			break;
		default:
			num2 = Random.Range(1, 101);
			if (num2 > 90)
			{
				autoGiftInfo.gType = AutoGiftType.GiftBox;
				autoGiftInfo.num = 1;
				autoGiftInfo.spriteName = "GiftBoxBig";
			}
			else
			{
				autoGiftInfo.gType = AutoGiftType.Coins;
				autoGiftInfo.num = GetRamdonCoinsForAutoGift();
				autoGiftInfo.spriteName = "GiftCoinBig";
			}
			break;
		}
		PlayerPrefs.SetInt("ChristmasGiftGetCount", PlayerPrefs.GetInt("ChristmasGiftGetCount", 0) + 1);
		SetCurAutoGiftTimeRest(GetCurAutoGiftTimeInterval());
		if (autoGiftInfo.gType == AutoGiftType.GiftBox)
		{
			SetCurGiftBoxTotal(GetCurGiftBoxTotal() + 1);
		}
		else
		{
			AddCoins(autoGiftInfo.num);
		}
		return autoGiftInfo;
	}

