	public static string[] GetUserAllEnabledSkinName()
	{
		List<string> list = new List<string>();
		GItemId id = new GItemId(1, 1, 1, 1);
		for (int i = 0; i < AllSkinNameList.Length; i++)
		{
			if (GetSkinItemInfo(AllSkinNameList[i], id).mIsEnabled)
			{
				list.Add(AllSkinNameList[i]);
			}
		}
		string[] array = new string[list.Count];
		list.CopyTo(array);
		list.Clear();
		return array;
	}

