	public static bool EnableSkin(string name)
	{
		bool result = true;
		PlayerPrefs.SetInt(name, 1);
		return result;
	}

	public static void ProcessOneWeaponEquipTap(string tapedWeaponName)
	{
		string[] curEquippedWeaponNameList = GetCurEquippedWeaponNameList();
		int curWeaponEquipLimitedNum = GetCurWeaponEquipLimitedNum();
		for (int i = 0; i < curEquippedWeaponNameList.Length; i++)
		{
			if (tapedWeaponName == curEquippedWeaponNameList[i])
			{
				PlayerPrefs.SetString("CurWeaponEquiped_" + (i + 1), string.Empty);
				return;
			}
		}
		if (curEquippedWeaponNameList.Length == curWeaponEquipLimitedNum)
		{
			for (int j = 1; j < curEquippedWeaponNameList.Length; j++)
			{
				PlayerPrefs.SetString("CurWeaponEquiped_" + j, PlayerPrefs.GetString("CurWeaponEquiped_" + (j + 1)));
			}
			PlayerPrefs.SetString("CurWeaponEquiped_" + curEquippedWeaponNameList.Length, tapedWeaponName);
		}
		else
		{
