	public static int GetCurWeaponEquipLimitedUnlockLevel()
	{
		return PlayerPrefs.GetInt("CurWeaponEquipLimitedNum", 4) switch
		{
			4 => 15, 
			5 => 40, 
			6 => 70, 
			7 => 100, 
			_ => 100, 
		};
	}

	public static int GetCurWeaponEquipLimitedNum()
	{
		switch (PlayerPrefs.GetInt("CurWeaponEquipLimitedNum", 4))
		{
		case 4:
			if (GetCharacterLevel() >= 15)
			{
				PlayerPrefs.SetInt("CurWeaponEquipLimitedNum", 5);
			}
			break;
		case 5:
			if (GetCharacterLevel() >= 40)
			{
				PlayerPrefs.SetInt("CurWeaponEquipLimitedNum", 6);
			}
			break;
		case 6:
			if (GetCharacterLevel() >= 70)
			{
				PlayerPrefs.SetInt("CurWeaponEquipLimitedNum", 7);
			}
			break;
		case 7:
			if (GetCharacterLevel() >= 100)
			{
				PlayerPrefs.SetInt("CurWeaponEquipLimitedNum", 8);
			}
			break;
		}
		return PlayerPrefs.GetInt("CurWeaponEquipLimitedNum", 4);
	}

	public static void SetCurWeaponEquipLimitedNum(int num)
	{
		PlayerPrefs.SetInt("CurWeaponEquipLimitedNum", num);
	}

	public static string[] GetCurEquippedWeaponNameList()
	{
		List<string> list = new List<string>();
		int curWeaponEquipLimitedNum = GetCurWeaponEquipLimitedNum();
		string empty = string.Empty;
		for (int i = 0; i < curWeaponEquipLimitedNum; i++)
		{
			empty = PlayerPrefs.GetString("CurWeaponEquiped_" + (i + 1));
			if (empty != string.Empty)
			{
				list.Add(empty);
			}
		}
		for (int j = 0; j < curWeaponEquipLimitedNum; j++)
		{
			if (j < list.Count)
			{
				PlayerPrefs.SetString("CurWeaponEquiped_" + (j + 1), list[j]);
			}
			else
			{
				PlayerPrefs.SetString("CurWeaponEquiped_" + (j + 1), string.Empty);
			}
		}
		string[] array = new string[list.Count];
		list.CopyTo(array);
		list.Clear();
		return array;
	}

