	public static GItemInfo GetItemInfo(string name, GItemId id, bool isSearchForUpgrade)
	{
		GItemInfo gItemInfo = new GItemInfo();
		int num = 0;
		string[] curEquippedWeaponNameList = GetCurEquippedWeaponNameList();
		for (int i = 0; i < curEquippedWeaponNameList.Length; i++)
		{
			if (name == curEquippedWeaponNameList[i])
			{
				gItemInfo.mIsEquipped = true;
				break;
			}
		}
		gItemInfo.mName = name;
		switch (name)
		{
		case "BallisticKnife":
			num = PlayerPrefs.GetInt("BallisticKnife", 1);
			if (isSearchForUpgrade)
			{
				num++;
			}
			gItemInfo.mCurWeaponLevel = num;
			gItemInfo.mMaxWeaponLevel = 3;
			if (gItemInfo.mCurWeaponLevel < gItemInfo.mMaxWeaponLevel)
			{
				gItemInfo.mCanUpgrade = true;
			}
			else
			{
				gItemInfo.mCanUpgrade = false;
			}
			if (num == 0)
			{
				gItemInfo.mIsEnabled = false;
			}
			else
			{
				gItemInfo.mIsEnabled = true;
			}
			gItemInfo.mId = id;
			gItemInfo.mPurchasedType = GItemPurchaseType.CoinsPurchase;
			gItemInfo.mUnlockCLevel = 1;
			gItemInfo.mWeaponLevelSpriteName = "WeaponLevel_" + num;
