	public static void SetMyNickName(string name)
	{
		if (name.Length > 16)
		{
			name = name.Remove(16);
		}
		string[] array = name.Split('_');
		if (array.Length > 0)
		{
			name = string.Empty;
			for (int i = 0; i < array.Length; i++)
			{
				name += array[i];
			}
		}
		PlayerPrefs.SetString("LocalMultiplayerNickName", name);
	}

	public static string GetMyNickName()
	{
		return PlayerPrefs.GetString("LocalMultiplayerNickName", "New Player");
	}

	public static void SetMyRoomName(string name)
	{
		if (name.Length > 27)
		{
			name = name.Remove(27);
		}
		PlayerPrefs.SetString("MultiplayerRoomName", name);
	}

