	{
		return PlayerPrefs.GetString("MultiplayerRoomName", string.Empty);
	}

	public static int GetMyRoomNumberSetting()
	{
		return PlayerPrefs.GetInt("MultiplayerRoomNumberSetting", 8);
	}

	public static void SetMyRoomNumberSetting(int num)
	{
		if (num > 12)
		{
			num = 12;
		}
		if (num < 2)
		{
			num = 2;
		}
		PlayerPrefs.SetInt("MultiplayerRoomNumberSetting", num);
	}

	public static string GetStrVersion()
	{
		return PlayerPrefs.GetString("CurrentVersion", "v3.0.2");
	}

	public static int GetCharacterLevel()
	{
		return PlayerPrefs.GetInt("CharacterLevel", 1);
	}

