	{
		PlayerPrefs.SetInt("CharacterLevel", level);
	}

	public static int GetCharacterExp()
	{
		return PlayerPrefs.GetInt("CharacterExp", 0);
	}

	public static void SetCharacterExp(int exp)
	{
		PlayerPrefs.SetInt("CharacterExp", exp);
	}

	public static void AddCharacterExp(int expAdd)
	{
		PlayerPrefs.SetInt("CharacterExp", GetCharacterExp() + expAdd);
	}

	public static int GetCoins()
	{
		return PlayerPrefs.GetInt("GameCoins", 0);
	}

	public static void SetCoins(int coins)
	{
		PlayerPrefs.SetInt("GameCoins", coins);
	}

	public static void AddCoins(int coinsAdd)
	{
		PlayerPrefs.SetInt("GameCoins", GetCoins() + coinsAdd);
	}

	public static void SubCoins(int coinsSub)
	{
		PlayerPrefs.SetInt("GameCoins", GetCoins() - coinsSub);
	}

	public static int GetGems()
	{
		if (PlayerPrefs.GetInt("GameGems", 0) - PlayerPrefs.GetInt("GameGemsOldForDefendHack", 0) >= 2100)
		{
			PlayerPrefs.SetInt("GameGems", 0);
		}
		return PlayerPrefs.GetInt("GameGems", 0);
	}

	public static void SetGems(int gems)
	{
		PlayerPrefs.SetInt("GameGems", gems);
	}

	public static void AddGems(int gemsAdd)
	{
		int num = PlayerPrefs.GetInt("GameGemsOldForDefendHack", 0);
		int num2 = PlayerPrefs.GetInt("GameGems", 0) + gemsAdd;
		if (num2 - num < 2100)
		{
			PlayerPrefs.SetInt("GameGemsOldForDefendHack", num2);
			PlayerPrefs.SetInt("GameGems", num2);
		}
	}

	public static void SubGems(int gemsSub)
	{
		PlayerPrefs.SetInt("GameGems", GetGems() - gemsSub);
	}

