public class WordFilter : MonoBehaviour
{
	public static WordFilter mInstance;

	public string WF_DirtyWordStr;

	public string[] WF_DirtyWordList;

	private void Awake()
	{
		mInstance = this;
	}

	private void OnDestroy()
	{
	}

	private void Start()
	{
		string[] wF_DirtyWordList = WF_DirtyWordStr.Split('@');
		WF_DirtyWordList = wF_DirtyWordList;
	}

	public string MyReplace(string strSource, string strRe, string strTo)
	{
		string text = strSource.ToLower();
		string value = strRe.ToLower();
		int num = text.IndexOf(value);
		if (num != -1)
		{
			strSource = strSource.Substring(0, num) + strTo + MyReplace(strSource.Substring(num + strRe.Length), strRe, strTo);
		}
		return strSource;
	}

	public string FilterString(string orStr)
	{
		string text = orStr;
		for (int i = 0; i < WF_DirtyWordList.Length; i++)
		{
			text = MyReplace(text, WF_DirtyWordList[i], "***");
		}
		return text;
	}

	private void Update()
	{
	}
}
