public class GameCenterProcess : MonoBehaviour
{
	private int count;

	private void OnAwake()
	{
	}

	private void Start()
	{
		GameCenterBinding.authenticateLocalPlayer();
	}

	private void Update()
	{
		count++;
		if (count == 128)
		{
			GameCenterBinding.reportScore((long)PlayerPrefs.GetInt("KillModeSingleRoundKilling", 0), "com.joydo.minestrike.srkinkillmode");
			GameCenterBinding.reportScore((long)PlayerPrefs.GetInt("KillModeTotalKilling", 0), "com.joydo.minestrike.tkinkillmode");
			GameCenterBinding.reportScore((long)PlayerPrefs.GetInt("TeamModeSingleRoundKilling", 0), "com.joydo.minestrike.srkinteammode");
			GameCenterBinding.reportScore((long)PlayerPrefs.GetInt("TeamModeTotalKilling", 0), "com.joydo.minestrike.tkinteammode");
			GameCenterBinding.reportScore((long)PlayerPrefs.GetInt("LocalMultiplayerKill", 0), "com.joydo.minestrike.localmultiplayerkill");
			GameCenterBinding.reportScore((long)PlayerPrefs.GetInt("WorldwideMultiplayerKill", 0), "com.joydo.minestrike.worldwidemultiplayerkill");
			GameCenterBinding.reportScore((long)UserDataController.GetCharacterLevel(), "com.joydo.minestrike.characterlevel");
		}
		if (count > 250)
		{
			count = 250;
		}
	}
}
