	public void GetGiftPackBtnPressed()
	{
		//IL_0074: Unknown result type (might be due to invalid IL or missing references)
		AutoGiftInfo autoGiftInfo = GrowthManagerKit.RecevieOneGift();
		giftNumLabel.text = "x " + autoGiftInfo.num;
		giftSprite.spriteName = autoGiftInfo.spriteName;
		giftSprite.MarkAsChanged();
		rootPanel.SetActive(false);
		GiftPackEmptyObject.SetActive(true);
		TweenScale.Begin(GiftPackEmptyObject, 0.001f, new Vector3(0.01f, 0.01f, 0.01f));
		((MonoBehaviour)this).StartCoroutine(ShowGiftPackPanel(0.01f));
		backgroundAudio.GetComponent<AudioSource>().Pause();
		((Component)this).audio.PlayOneShot(slotAudio[2]);
	}

	private IEnumerator ShowGiftPackPanel(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		TweenScale.Begin(GiftPackEmptyObject, 0.2f, new Vector3(1f, 1f, 1f));
	}

	public void CloseGiftPackPanelBtnPressed()
	{
		rootGiftNumLabel.text = "x " + GrowthManagerKit.GetCurGiftBoxTotal();
		GiftPackEmptyObject.SetActive(false);
