		((Component)this).audio.Stop();
		backgroundAudio.GetComponent<AudioSource>().Play();
	}

	public void LotteryBtnPressed()
	{
		lotteryPanel.SetActive(true);
		rootPanel.SetActive(false);
		backgroundAudio.GetComponent<AudioSource>().Pause();
		giftNumShowLabel.text = "x " + GrowthManagerKit.GetCurGiftBoxTotal();
		gemNumShowLabel.text = "x " + GrowthManagerKit.GetGems();
		coinNumShowLabel.text = "x " + GrowthManagerKit.GetCoins();
		if (GrowthManagerKit.GetCurGiftBoxTotal() > 0)
		{
			((Component)startBtn).GetComponent<UIImageButton>().isEnabled = true;
		}
		else
		{
			((Component)startBtn).GetComponent<UIImageButton>().isEnabled = false;
		}
		((Component)facebookBtn).GetComponent<UIImageButton>().isEnabled = false;
		((Component)twitterBtn).GetComponent<UIImageButton>().isEnabled = false;
	}

	public void StartToLotteryBtnPressed()
	{
		((Component)startBtn).GetComponent<UIImageButton>().isEnabled = false;
		((Component)facebookBtn).GetComponent<UIImageButton>().isEnabled = false;
		((Component)twitterBtn).GetComponent<UIImageButton>().isEnabled = false;
		((Component)closeGiftPackPanelBtn).GetComponent<UIImageButton>().isEnabled = false;
		giftNumShowLabel.text = "x " + (GrowthManagerKit.GetCurGiftBoxTotal() - 1);
		if (slotInfo != null)
		{
			((Component)cursor[slotInfo.resultIndex]).gameObject.SetActive(false);
		}
		slotInfo = GrowthManagerKit.GetSlotsResultInfo();
		for (int i = 0; i < slotInfo.itemList.Count; i++)
		{
			giftSprites[i].spriteName = "Null_SlotLogo";
			giftSprites[i].MarkAsChanged();
			giftNumber[i].text = string.Empty;
		}
		giftResult.SetActive(false);
		((MonoBehaviour)this).StartCoroutine(ShowDefaultGift(1f));
	}

	public void CloseLotteryPanelBtnPressed()
	{
		lotteryPanel.SetActive(false);
		rootPanel.SetActive(true);
		backgroundAudio.GetComponent<AudioSource>().Play();
		giftResult.SetActive(false);
		if (slotInfo != null)
		{
			((Component)cursor[slotInfo.resultIndex]).gameObject.SetActive(false);
			for (int i = 0; i < slotInfo.itemList.Count; i++)
			{
				giftSprites[i].spriteName = "Null_SlotLogo";
				giftSprites[i].MarkAsChanged();
				giftNumber[i].text = string.Empty;
			}
		}
	}

	public void OpenSlotRulePanelBtnPressed()
	{
		lotteryEmptyObject.SetActive(false);
		lotteryRuleEmptyObject.SetActive(true);
		lotteryPanelBgTexture.GetComponent<UITexture>().mainTexture = (Texture)(object)bgTexture2;
	}

