	{
		if (MainMenuDirector.OnFacebook != null)
		{
			MainMenuDirector.OnFacebook();
		}
	}

	public void GenTwitterEvent()
	{
		if (MainMenuDirector.OnTwitter != null)
		{
			MainMenuDirector.OnTwitter();
		}
	}

	private void Awake()
	{
		mInstance = this;
	}

	private void Start()
	{
		rootGiftNumLabel.text = "x " + GrowthManagerKit.GetCurGiftBoxTotal();
		giftNumShowLabel.text = "x " + GrowthManagerKit.GetCurGiftBoxTotal();
		gemNumShowLabel.text = "x " + GrowthManagerKit.GetGems();
		coinNumShowLabel.text = "x " + GrowthManagerKit.GetCoins();
		if (UserDataController.IsFirstUseApp())
		{
			mInstance.MainMenuPanel.SetActive(false);
			mInstance.TermsPopPanel.SetActive(true);
		}
	}

	private void OnDestroy()
	{
		if ((Object)(object)mInstance == (Object)(object)this)
		{
			mInstance = null;
		}
	}

	private void Update()
	{
		if (!GrowthManagerKit.CanGetAutoGift())
		{
			((Component)getGiftPackBtn).GetComponent<UIImageButton>().isEnabled = false;
			getGiftPackFront.fillAmount = GrowthManagerKit.GetAutoGiftProgressFillAmount();
			getGiftPackCountDown.text = (int)GrowthManagerKit.GetCurAutoGiftTimeRest() / 60 + " : " + (int)GrowthManagerKit.GetCurAutoGiftTimeRest() % 60;
		}
		else
		{
			((Component)getGiftPackBtn).GetComponent<UIImageButton>().isEnabled = true;
			getGiftPackFront.fillAmount = 0f;
			getGiftPackCountDown.text = string.Empty;
		}
		if (GrowthManagerKit.GetCurGiftBoxTotal() > 0)
		{
			tapToOpenSlotsLabel.SetActive(true);
		}
		else
		{
			tapToOpenSlotsLabel.SetActive(false);
		}
		CursorAnimation();
	}

	private IEnumerator ShowDefaultGift(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		for (int i = 0; i < slotInfo.itemList.Count; i++)
		{
			giftSprites[i].spriteName = slotInfo.itemList[i].spriteName;
			giftSprites[i].MarkAsChanged();
			giftNumber[i].text = "x " + slotInfo.itemList[i].Num;
		}
		((MonoBehaviour)this).StartCoroutine(SetCanAnimation(0.5f));
	}

	private IEnumerator SetCanAnimation(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		canAnimation = true;
		slotTotalNum = Random.Range(36, 61);
		slotSection1 = slotTotalNum / 3;
		slotSection2 = slotSection1 * 2;
		slotSection3 = slotTotalNum + 12 - slotTotalNum % 12 + slotInfo.resultIndex;
	}

	private void CursorAnimation()
	{
		if (!canAnimation)
		{
			return;
		}
		if (slotCurNum < slotSection1)
		{
			float num = (float)slotSpeedFactor * 0.23f;
			slotTime += Time.deltaTime * num;
			if (slotTime > 0.35f)
			{
				slotTime = 0f;
				slotCurNum++;
				slotSpeedFactor++;
				slotCurIndex = slotCurNum % 12;
				SetCurIndexCursorLight();
			}
		}
		else if (slotCurNum < slotSection2)
		{
			float num2 = (float)slotSpeedFactor * 0.2f;
			slotTime += Time.deltaTime * num2;
			if (slotTime > 0.38f)
			{
				slotTime = 0f;
				slotCurNum++;
				slotCurIndex = slotCurNum % 12;
				SetCurIndexCursorLight();
			}
		}
		else if (slotCurNum < slotSection3)
		{
			float num3 = (float)slotSpeedFactor * 0.2f;
			slotTime += Time.deltaTime * num3;
			if (slotTime > 0.35f)
			{
				slotTime = 0f;
				slotCurNum++;
				if (slotSpeedFactor > 1 && slotSection3 - slotCurNum <= slotSpeedFactor - 2)
				{
					slotSpeedFactor--;
				}
				slotCurIndex = slotCurNum % 12;
				SetCurIndexCursorLight();
			}
		}
		else if (slotCurNum == slotSection3)
		{
			CursorAnimationFinish();
		}
	}

	private void SetCurIndexCursorLight()
	{
		for (int i = 0; i < slotInfo.itemList.Count; i++)
		{
			if (slotCurIndex == i)
			{
				((Component)cursor[i]).gameObject.SetActive(true);
				((Component)this).audio.PlayOneShot(slotAudio[0]);
			}
			else
			{
				((Component)cursor[i]).gameObject.SetActive(false);
			}
		}
	}

	private void CursorAnimationFinish()
	{
		slotTime = 0.5f;
		slotCurNum = 0;
		slotSpeedFactor = 1;
		slotCurIndex = 0;
		canAnimation = false;
		((Component)this).audio.Stop();
		((Component)this).audio.PlayOneShot(slotAudio[1]);
		if (GrowthManagerKit.GetCurGiftBoxTotal() > 0)
		{
			((Component)startBtn).GetComponent<UIImageButton>().isEnabled = true;
		}
		rootGiftNumLabel.text = "x " + GrowthManagerKit.GetCurGiftBoxTotal();
		gemNumShowLabel.text = "x " + GrowthManagerKit.GetGems();
		coinNumShowLabel.text = "x " + GrowthManagerKit.GetCoins();
		giftResult.SetActive(true);
		giftResultSprite.spriteName = slotInfo.itemList[slotInfo.resultIndex].spriteName;
		giftResultSprite.MarkAsChanged();
		giftResultLabel.text = "x " + slotInfo.itemList[slotInfo.resultIndex].Num;
		((Component)closeGiftPackPanelBtn).GetComponent<UIImageButton>().isEnabled = true;
	}
}
public class RatingPopButtonEvent : MonoBehaviour
{
	public enum ButtonName
	{
		Nil,
		RatingNow,
		RemindLater,
		NeverRemind,
		AcceptTerms,
		ShowAgreement
	}

	public ButtonName buttonName;

	private void OnClick()
	{
		if (((Behaviour)this).enabled)
		{
			switch (buttonName)
			{
			case ButtonName.RatingNow:
				MainMenuDirector.mInstance.MainMenuPanel.SetActive(true);
				MainMenuDirector.mInstance.RatingPopPanel.SetActive(false);
				UserDataController.VerifyAppstoreRating();
				Application.OpenURL("https://itunes.apple.com/app/cops-n-robbers-mine-mini-game/id686365571?mt=8");
				break;
			case ButtonName.RemindLater:
				MainMenuDirector.mInstance.MainMenuPanel.SetActive(true);
				MainMenuDirector.mInstance.RatingPopPanel.SetActive(false);
				break;
			case ButtonName.NeverRemind:
				MainMenuDirector.mInstance.MainMenuPanel.SetActive(true);
				MainMenuDirector.mInstance.RatingPopPanel.SetActive(false);
				UserDataController.VerifyAppstoreRating();
				break;
			case ButtonName.AcceptTerms:
				MainMenuDirector.mInstance.MainMenuPanel.SetActive(true);
				MainMenuDirector.mInstance.TermsPopPanel.SetActive(false);
				UserDataController.SetIsFirstUseApp();
				break;
			case ButtonName.ShowAgreement:
				MainMenuDirector.mInstance.MainMenuPanel.SetActive(false);
				MainMenuDirector.mInstance.TermsPopPanel.SetActive(true);
				MainMenuDirector.mInstance.AcceptLabel.GetComponent<UILabel>().text = "OK";
				break;
			}
		}
	}

	private void Start()
	{
	}

	private void Update()
	{
	}
}
