				num = ((num == 2) ? 1 : (num + 1));
				GameObject.Find("GuideTexture").GetComponent<UITexture>().mainTexture = (Texture)(object)mGuideTexture[num - 1];
				GameObject.Find("GuideTexture").GetComponent<UITexture>().MarkAsChanged();
				break;
			}
			case ButtonName.LocalChoice:
				MultiplayerSelectDirector.mInstance.ToSubScene(MSD_SubScene.Local);
				break;
			case ButtonName.WorldWideChoice:
				MultiplayerSelectDirector.mInstance.ToSubScene(MSD_SubScene.WorldWide);
				break;
			case ButtonName.LocalBack:
				MultiplayerSelectDirector.mInstance.ToSubScene(MSD_SubScene.Choice);
				break;
			case ButtonName.WorldWideBack:
				MultiplayerSelectDirector.mInstance.ToSubScene(MSD_SubScene.Choice);
				break;
			case ButtonName.WWJoin:
				break;
			case ButtonName.WWRoomListBack:
				break;
			case ButtonName.WWRoomCreateBack:
				MultiplayerSelectDirector.mInstance.ToSubSceneInWorldWide(MSD_SubSceneInWorldWide.RoomChoice);
				break;
			case ButtonName.WWMapPre:
				MultiplayerSelectDirector.mInstance.ToWWPreMap();
				break;
			case ButtonName.WWMapNext:
				MultiplayerSelectDirector.mInstance.ToWWNextMap();
				break;
			case ButtonName.WWMaxNumAdd:
				MultiplayerSelectDirector.mInstance.WWMaxPlayersAdd();
				break;
			case ButtonName.WWMaxNumSub:
				MultiplayerSelectDirector.mInstance.WWMaxPlayersSub();
				break;
			case ButtonName.WWStart:
				MultiplayerSelectDirector.mInstance.WWCreateRoomNStart();
				break;
			case ButtonName.WWCreate:
				MultiplayerSelectDirector.mInstance.ToSubSceneInWorldWide(MSD_SubSceneInWorldWide.RoomCreate);
				break;
			case ButtonName.LWFMapPre:
				MultiplayerSelectDirector.mInstance.ToLWFPreMap();
				break;
			case ButtonName.LWFMapNext:
				MultiplayerSelectDirector.mInstance.ToLWFNextMap();
				break;
			case ButtonName.LWFStart:
				MultiplayerSelectDirector.mInstance.LWFStart();
				break;
			case ButtonName.WWQuickStart:
				MultiplayerSelectDirector.mInstance.WWJoinRoomNQuickStart();
				break;
			}
		}
	}

	private void Start()
	{
	}

	private void Update()
	{
	}
}
public class MenuRandomSoundEffect : MonoBehaviour
{
	public AudioClip[] mSoundEffects;

	private void SoundEffectPlay_1()
	{
		((Component)this).audio.PlayOneShot(mSoundEffects[0]);
	}

	private void SoundEffectPlay_2()
	{
		((Component)this).audio.PlayOneShot(mSoundEffects[1]);
	}

	private void SoundEffectPlay_3()
	{
		((Component)this).audio.PlayOneShot(mSoundEffects[2]);
	}

	private void RandomSoundEffectPlay()
	{
		if (Time.frameCount % 32 == 0 && Random.Range(1, 4) > 2)
		{
			switch (Random.Range(1, 4))
			{
			case 1:
				SoundEffectPlay_1();
				break;
			case 2:
				SoundEffectPlay_2();
				break;
			case 3:
				SoundEffectPlay_3();
				break;
			case 4:
				break;
			}
		}
	}

	private void Start()
	{
	}

	private void Update()
	{
		RandomSoundEffectPlay();
	}
}
