	public void WWResetModeCheckBox()
	{
		if (isCurMapSupportThisMode(GrowthGameModeTag.tStronghold))
		{
			mModeCheckBoxSH.SetActive(true);
		}
		else
		{
			if (curModeSet == GrowthGameModeTag.tStronghold)
			{
				curModeSet = GrowthGameModeTag.tKillingCompetition;
			}
			mModeCheckBoxSH.SetActive(false);
		}
		if (isCurMapSupportThisMode(GrowthGameModeTag.tTeamDeathMatch))
		{
			mModeCheckBoxTDM.SetActive(true);
		}
		else
		{
			mModeCheckBoxTDM.SetActive(false);
		}
		if (isCurMapSupportThisMode(GrowthGameModeTag.tKillingCompetition))
		{
			mModeCheckBoxTDM.SetActive(true);
		}
		else
		{
			mModeCheckBoxTDM.SetActive(false);
		}
	}

	public void ResetAllTween()
	{
		for (int i = 0; i < TweenAlphaObj.Length; i++)
		{
			TweenAlphaObj[i].Reset();
		}
	}

	public void SwitchToMode(GrowthGameModeTag mode)
	{
		curModeSet = mode;
	}

	public void ToSubScene(MSD_SubScene subS)
	{
		ResetAllTween();
		switch (subS)
		{
		case MSD_SubScene.Choice:
			if (PhotonNetwork.connected)
			{
				PhotonNetwork.Disconnect();
			}
			if ((Object)(object)connectMenu != (Object)null)
			{
				connectMenu.RemoveAllRoomObjs();
				connectMenu.ResetViewCameraPos();
			}
			mUIRootChoice.SetActive(true);
			mUIRootLocal.SetActive(false);
			mUIRootWorldWide.SetActive(false);
			mUIRootLoading.SetActive(false);
			mRoomScrollViewRoot.SetActive(false);
			break;
		case MSD_SubScene.Local:
			mUIRootChoice.SetActive(false);
			mUIRootLocal.SetActive(true);
			mUIRootWorldWide.SetActive(false);
			mUIRootLoading.SetActive(false);
			mRoomScrollViewRoot.SetActive(false);
			break;
		case MSD_SubScene.WorldWide:
			mUIRootChoice.SetActive(false);
			mUIRootLocal.SetActive(false);
			mUIRootWorldWide.SetActive(true);
			mUIRootLoading.SetActive(false);
			mRoomScrollViewRoot.SetActive(true);
			break;
		case MSD_SubScene.Loading:
			mTipsLabel.text = UserDataController.GetRandomTips();
			mUIRootChoice.SetActive(false);
			mUIRootLocal.SetActive(false);
			mUIRootWorldWide.SetActive(false);
			mUIRootLoading.SetActive(true);
			mRoomScrollViewRoot.SetActive(false);
			break;
		}
	}

	public void ToSubSceneInWorldWide(MSD_SubSceneInWorldWide subS)
	{
		ResetAllTween();
		switch (subS)
		{
		case MSD_SubSceneInWorldWide.RoomChoice:
			mRoomChoicePanel.SetActive(true);
			mRoomScrollViewRoot.SetActive(true);
			mRoomCreatePanel.SetActive(false);
			mCurWWSubScene = MSD_SubSceneInWorldWide.RoomChoice;
			break;
		case MSD_SubSceneInWorldWide.RoomCreate:
			if ((Object)(object)connectMenu != (Object)null)
			{
				connectMenu.RemoveAllRoomObjs();
				connectMenu.ResetViewCameraPos();
			}
			if (PhotonNetwork.connected)
			{
				mRoomChoicePanel.SetActive(false);
				mRoomScrollViewRoot.SetActive(false);
				mRoomCreatePanel.SetActive(true);
				mCurWWSubScene = MSD_SubSceneInWorldWide.RoomCreate;
				WWResetModeCheckBox();
			}
			break;
		}
	}

