	public void WWMaxPlayersAdd()
	{
		if (mWWMaxPlayersNum <= 11)
		{
			mWWMaxPlayersNum++;
		}
		UserDataController.SetMyRoomNumberSetting(mWWMaxPlayersNum);
	}

	public void WWMaxPlayersSub()
	{
		if (mWWMaxPlayersNum > 2)
		{
			mWWMaxPlayersNum--;
		}
		UserDataController.SetMyRoomNumberSetting(mWWMaxPlayersNum);
	}

	public void WWJoinRoomNQuickStart()
	{
		RoomInfo[] roomList = PhotonNetwork.GetRoomList();
		List<RoomInfo> list = new List<RoomInfo>();
		for (int i = 0; i < roomList.Length; i++)
		{
			if (roomList[i].maxPlayers != roomList[i].playerCount && (string)roomList[i].customProperties["version"] == UserDataController.GetStrVersion())
			{
				list.Add(roomList[i]);
			}
		}
		if (list.Count > 0)
		{
			int index = Random.Range(0, list.Count);
			ToSubScene(MSD_SubScene.Loading);
			PhotonNetwork.playerName = GrowthManagerKit.GetMyNickName();
			PhotonNetwork.JoinRoom(list[index].name);
			mCurWWMapSelect = (string)list[index].customProperties["map"];
			((MonoBehaviour)this).StopAllCoroutines();
			((MonoBehaviour)this).StartCoroutine(WWRoomJoinTimeOutChk());
			list.Clear();
		}
		else
		{
			mJoinTipsShowTimeCount = 0f;
			if (roomList.Length == 0)
			{
				mJoinTipsLabel.text = "<Tips: No room created...>";
			}
			else
			{
				mJoinTipsLabel.text = "<Tips: All rooms are full...>";
			}
		}
	}

	public void WWJoinRoomNStart(RoomInfo room)
	{
		if (room.maxPlayers == room.playerCount)
		{
			mJoinTipsShowTimeCount = 0f;
			mJoinTipsLabel.text = "<Tips: Selected room is full...>";
			return;
		}
		ToSubScene(MSD_SubScene.Loading);
		PhotonNetwork.JoinRoom(room.name);
		PhotonNetwork.playerName = GrowthManagerKit.GetMyNickName();
		mCurWWMapSelect = (string)room.customProperties["map"];
		((MonoBehaviour)this).StopAllCoroutines();
		((MonoBehaviour)this).StartCoroutine(WWRoomJoinTimeOutChk());
	}

	public void WWCreateRoomNStart()
	{
		ToSubScene(MSD_SubScene.Loading);
		string[] propsToListInLobby = new string[3] { "map", "version", "mode" };
		Hashtable hashtable = new Hashtable();
		hashtable.Add("map", mCurWWMapSelect);
		Hashtable hashtable2 = hashtable;
		hashtable2.Add("version", UserDataController.GetStrVersion());
		int num = (int)curModeSet;
		hashtable2.Add("mode", num.ToString());
		PhotonNetwork.CreateRoom(UserDataController.GetMyRoomName(), isVisible: true, isOpen: true, mWWMaxPlayersNum, hashtable2, propsToListInLobby);
		PhotonNetwork.playerName = GrowthManagerKit.GetMyNickName();
		((MonoBehaviour)this).StopAllCoroutines();
		((MonoBehaviour)this).StartCoroutine(WWRoomCreateTimeOutChk());
	}

	public IEnumerator WWRoomCreateTimeOutChk()
	{
		yield return (object)new WaitForSeconds(15f);
		mLoadingLabel.text = "Connection timeout...";
		PhotonNetwork.Disconnect();
		yield return (object)new WaitForSeconds(3f);
		mLoadingLabel.text = "Loading...";
		ToSubScene(MSD_SubScene.WorldWide);
		ToSubSceneInWorldWide(MSD_SubSceneInWorldWide.RoomChoice);
	}

	public IEnumerator WWRoomJoinTimeOutChk()
	{
		yield return (object)new WaitForSeconds(15f);
		mLoadingLabel.text = "Connection timeout...";
		PhotonNetwork.Disconnect();
		yield return (object)new WaitForSeconds(3f);
		mLoadingLabel.text = "Loading...";
		ToSubScene(MSD_SubScene.WorldWide);
		ToSubSceneInWorldWide(MSD_SubSceneInWorldWide.RoomChoice);
	}

	public IEnumerator WWTipRoomNameExist()
	{
		mLoadingLabel.text = "Room Name Already Exist!";
		PhotonNetwork.Disconnect();
		yield return (object)new WaitForSeconds(3f);
		mLoadingLabel.text = "Loading...";
		ToSubScene(MSD_SubScene.WorldWide);
		ToSubSceneInWorldWide(MSD_SubSceneInWorldWide.RoomChoice);
	}

	public IEnumerator WWTipRoomFull()
	{
		mLoadingLabel.text = "Selected Room Is Full!";
		yield return (object)new WaitForSeconds(3f);
		mLoadingLabel.text = "Loading...";
		ToSubScene(MSD_SubScene.WorldWide);
		ToSubSceneInWorldWide(MSD_SubSceneInWorldWide.RoomChoice);
	}

	private void OnJoinedRoom()
	{
		((MonoBehaviour)this).StopAllCoroutines();
		Application.LoadLevel(mCurWWMapSelect);
	}

	private void OnPhotonCreateRoomFailed()
	{
		((MonoBehaviour)this).StopAllCoroutines();
		((MonoBehaviour)this).StartCoroutine(WWTipRoomNameExist());
	}

	private void OnPhotonJoinRoomFailed()
	{
		((MonoBehaviour)this).StopAllCoroutines();
		((MonoBehaviour)this).StartCoroutine(WWTipRoomFull());
	}

	public IEnumerator StartLWFScene()
	{
		ToSubScene(MSD_SubScene.Loading);
		yield return (object)new WaitForSeconds(0.5f);
		Application.LoadLevel(mCurLWFMapSelect);
	}

	public void LWFStart()
	{
		((MonoBehaviour)this).StopAllCoroutines();
		((MonoBehaviour)this).StartCoroutine(StartLWFScene());
	}

	public IEnumerator StartChoiceBack()
	{
		ToSubScene(MSD_SubScene.Loading);
		yield return (object)new WaitForSeconds(0.2f);
		Application.LoadLevel("MainMenu");
	}

	public void ChoiceBack()
	{
		((MonoBehaviour)this).StopAllCoroutines();
		((MonoBehaviour)this).StartCoroutine(StartChoiceBack());
	}

	private void Update()
	{
		if (((Behaviour)mMaxNumLabel).enabled)
		{
			mMaxNumLabel.text = "Max Players: " + mWWMaxPlayersNum;
		}
		if (mJoinTipsLabel.text != string.Empty)
		{
			mJoinTipsShowTimeCount += Time.deltaTime;
			if (mJoinTipsShowTimeCount >= 3f)
			{
				mJoinTipsLabel.text = string.Empty;
				mJoinTipsShowTimeCount = 0f;
			}
		}
	}
}
public class PauseCheckBox : MonoBehaviour
{
	public enum cbType
	{
		Nil,
		SystemMsgSwitchCheckbox,
		SendToTeamCheckbox,
		ReceiveCheckbox,
		NoSoundCheckbox
	}

	public cbType type;

	public UICheckbox checkBox;

	private void OnClick()
	{
		switch (type)
		{
		case cbType.ReceiveCheckbox:
			UserDataController.SwitchChatMessageReceiveType();
			break;
		case cbType.SendToTeamCheckbox:
			UserDataController.SwitchChatMessageSendType();
			break;
		case cbType.SystemMsgSwitchCheckbox:
			UserDataController.SwitchSystemMessageInChat();
			break;
		case cbType.NoSoundCheckbox:
			SoundSetting();
			break;
		}
	}

	private void Start()
	{
		checkBox = ((Component)((Component)this).transform).GetComponent<UICheckbox>();
		switch (type)
		{
		case cbType.ReceiveCheckbox:
			break;
		case cbType.SendToTeamCheckbox:
			break;
		case cbType.SystemMsgSwitchCheckbox:
			break;
		case cbType.NoSoundCheckbox:
			if (UserDataController.IsSoundEffectEnabled())
			{
				checkBox.isChecked = true;
			}
			else
			{
				checkBox.isChecked = false;
			}
			break;
		}
	}

	private void Update()
	{
		switch (type)
		{
		case cbType.ReceiveCheckbox:
			if (UserDataController.GetChatMessageReceiveType() == MsgType.TeamOnly)
			{
				checkBox.isChecked = true;
			}
			else
			{
				checkBox.isChecked = false;
			}
			break;
		case cbType.SendToTeamCheckbox:
			if (UserDataController.GetChatMessageSendType() == MsgType.TeamOnly)
			{
				checkBox.isChecked = true;
			}
			else
			{
				checkBox.isChecked = false;
			}
			break;
		case cbType.SystemMsgSwitchCheckbox:
			if (UserDataController.IsSystemMessageInChatClosed())
			{
				checkBox.isChecked = true;
			}
			else
			{
				checkBox.isChecked = false;
			}
			break;
		}
	}

	private void SoundSetting()
	{
		UserDataController.SwitchSoundEffectSetting();
		if (UserDataController.IsSoundEffectEnabled())
		{
			checkBox.isChecked = true;
		}
		else
		{
			checkBox.isChecked = false;
		}
		UIMenuDirector.mInstance.GenSoundSettingEvent();
	}
}
public class PhotonPingShow : MonoBehaviour
{
	private int pingNum;

	private int pingValue = 1000;

	private UISprite pingSprite;

	private void Start()
	{
		pingSprite = ((Component)this).gameObject.GetComponent<UISprite>();
	}

	private void Update()
	{
		if (Time.frameCount % 64 != 0)
		{
			return;
		}
		if (!PhotonNetwork.connected)
		{
			pingNum = 0;
		}
		else
		{
			pingValue = PhotonNetwork.GetPing();
			if (pingValue >= 500)
			{
				pingNum = 1;
			}
			if (pingValue >= 300 && pingValue < 500)
			{
				pingNum = 2;
			}
			if (pingValue >= 200 && pingValue < 300)
			{
				pingNum = 3;
			}
			if (pingValue >= 100 && pingValue < 200)
			{
				pingNum = 4;
			}
			if (pingValue < 100)
			{
				pingNum = 5;
			}
		}
		if ((Object)(object)pingSprite != (Object)null && pingSprite.spriteName != "ping_" + pingNum)
		{
			pingSprite.spriteName = "ping_" + pingNum;
			pingSprite.MarkAsChanged();
		}
	}
}
public class ExportSkin : MonoBehaviour
{
	public static ExportSkin mInstance;

	public Texture2D[] skinTex = (Texture2D[])(object)new Texture2D[33];

	public UIImageButton exportBtn;

	public UILabel exportStatus;

	private void Awake()
	{
		mInstance = this;
	}

	private void OnDestroy()
	{
		if ((Object)(object)mInstance == (Object)(object)this)
		{
			mInstance = null;
		}
	}

	[DllImport("__Internal")]
	private static extern void _PngWriteToAlbum(string path);

	public static void ExportSkinToAlbum(string path)
	{
		Debug.Log((object)"ExportSkinToAlbum ExportSkinToAlbum");
		_PngWriteToAlbum(path);
	}

	public void ExportCurSkin(int tag)
	{
		Debug.Log((object)("tag = " + tag));
		string path = Application.persistentDataPath + "/CurSkin.png";
		byte[] bytes = skinTex[tag].EncodeToPNG();
		File.WriteAllBytes(path, bytes);
		((Component)exportBtn).GetComponent<UIImageButton>().isEnabled = false;
		exportStatus.text = "Staus: Exporting...";
		((Component)exportStatus).gameObject.SetActive(true);
		((MonoBehaviour)this).StartCoroutine(ExportSkinFunction(path));
		((MonoBehaviour)this).StartCoroutine(ExportStatusSuccess());
	}

	private IEnumerator ExportSkinFunction(string path)
	{
		yield return (object)new WaitForSeconds(0.1f);
		ExportSkinToAlbum(path);
	}

	private IEnumerator ExportStatusSuccess()
	{
		yield return (object)new WaitForSeconds(2f);
		exportStatus.text = "Staus: Export Success!";
		exportStatus.color = Color.green;
		((MonoBehaviour)this).StartCoroutine(ExportBtnRecover());
	}

	private IEnumerator ExportBtnRecover()
	{
		yield return (object)new WaitForSeconds(1f);
		((Component)exportBtn).GetComponent<UIImageButton>().isEnabled = true;
		((Component)exportStatus).gameObject.SetActive(false);
		exportStatus.color = Color.white;
	}
}
