	private void SetArmorData()
	{
		curUsedArmorInfo = GrowthManagerKit.GetCurSettedArmorInfo();
		curArmorInfo = curUsedArmorInfo;
		armorNameList = UserDataController.AllArmorNameList;
		armorFillTimeLevelTotal = curArmorInfo.mAutoSupplyTimeFillLevel.Length;
		armorFillTimeLevel = curArmorInfo.mAutoSupplyTimeFillLevel;
		armorRemainingTimeLabel.text = parseTimeSeconds((int)curArmorInfo.mAutoSupplyTimeRest, 0);
		for (int i = 0; i < armorNameList.Length; i++)
		{
			if (curArmorInfo.mName == armorNameList[i])
			{
				curShowArmorType = i;
				break;
			}
		}
		((Component)armorTextrue.transform).GetComponent<UITexture>().mainTexture = (Texture)(object)armorTextrueArray[curShowArmorType];
		((Component)equipmentArmorTexture).gameObject.SetActive(true);
		armorRemainingTimeLabel.text = parseTimeSeconds((int)curArmorInfo.mAutoSupplyTimeRest, 0);
		timeFillScaleLabel.text = curArmorInfo.GetTimeFillOffSaleRateStr(armorFillTimeLevel[armorFillTimeIndex]);
		int timeFillPrice = curArmorInfo.GetTimeFillPrice(armorFillTimeLevel[armorFillTimeIndex]);
		timePriceLabel.text = timeFillPrice.ToString();
		if (GrowthManagerKit.GetCoins() < timeFillPrice || curArmorInfo.mAutoSupplyTimeRest >= 172800f)
		{
			armorTimeFillBtn.isEnabled = false;
		}
		else
		{
			armorTimeFillBtn.isEnabled = true;
		}
	}

