		curShowArmorType++;
		if (curShowArmorType > 2)
		{
			curShowArmorType = 0;
		}
		ShowCurArmorInfo();
	}

	private void ShowCurArmorInfo()
	{
		curArmorInfo = GrowthManagerKit.GetArmorItemInfoByName(armorNameList[curShowArmorType]);
		if (curUsedArmorInfo.mName == armorNameList[curShowArmorType])
		{
			((Component)equipmentArmorTexture).gameObject.SetActive(true);
		}
		else
