		((Component)armorTextrue.transform).GetComponent<UITexture>().mainTexture = (Texture)(object)armorTextrueArray[curShowArmorType];
		armorRemainingTimeLabel.text = parseTimeSeconds((int)curArmorInfo.mAutoSupplyTimeRest, 0);
		timeFillScaleLabel.text = curArmorInfo.GetTimeFillOffSaleRateStr(armorFillTimeLevel[armorFillTimeIndex]);
