	private void GetWeaponData()
	{
		//IL_0060: Unknown result type (might be due to invalid IL or missing references)
		//IL_0070: Unknown result type (might be due to invalid IL or missing references)
		//IL_00b0: Unknown result type (might be due to invalid IL or missing references)
		//IL_00d2: Unknown result type (might be due to invalid IL or missing references)
		//IL_00f4: Unknown result type (might be due to invalid IL or missing references)
		gItemInfo = GrowthManagerKit.GetUserAllEnabledWeaponItemInfo();
		if (gItemInfo != null)
		{
			newWeaponObj = (GameObject[])(object)new GameObject[gItemInfo.Length];
			((Component)weaponObjParent).GetComponent<UITable>().columns = gItemInfo.Length;
			for (int i = 0; i < gItemInfo.Length; i++)
			{
				ref GameObject reference = ref newWeaponObj[i];
				Object obj = Object.Instantiate((Object)(object)weaponPrefab, weaponPrefab.transform.position, weaponPrefab.transform.rotation);
				reference = (GameObject)(object)((obj is GameObject) ? obj : null);
				newWeaponObj[i].transform.parent = weaponObjParent;
				newWeaponObj[i].transform.localScale = weaponPrefab.transform.localScale;
				newWeaponObj[i].transform.position = weaponPrefab.transform.position;
				newWeaponObj[i].transform.rotation = weaponPrefab.transform.rotation;
				if (gItemInfo[i] != null)
				{
					newWeaponObj[i].GetComponent<UIProfileWeaponPrefab>().gItemInfo = gItemInfo[i];
				}
				else
				{
					Debug.Log((object)"gItemInfo[i] is null");
				}
			}
			((Component)weaponObjParent).GetComponent<UITable>().Reposition();
		}
		SetEquipWindow();
	}

	private void SetEquipWindow()
	{
		equipLimitedNum = GrowthManagerKit.GetCurWeaponEquipLimitedNum();
		gItemInfoEquiped = GrowthManagerKit.GetCurEquippedWeaponItemInfoList();
		if (gItemInfoEquiped != null)
		{
			if (gItemInfoEquiped.Length < equipLimitedNum)
			{
				for (int i = 0; i < 8; i++)
				{
					if (i < gItemInfoEquiped.Length)
					{
						equipedWindow[i].GetComponent<UIProfileEquipedDisplay>().ReadData(gItemInfoEquiped[i], isLocked: false);
					}
					else if (i < equipLimitedNum)
					{
						equipedWindow[i].GetComponent<UIProfileEquipedDisplay>().ReadData(null, isLocked: false);
					}
					else
					{
						equipedWindow[i].GetComponent<UIProfileEquipedDisplay>().ReadData(null, isLocked: true);
					}
				}
			}
			else if (gItemInfoEquiped.Length == equipLimitedNum)
			{
				for (int j = 0; j < 8; j++)
				{
					if (j < gItemInfoEquiped.Length)
					{
						equipedWindow[j].GetComponent<UIProfileEquipedDisplay>().ReadData(gItemInfoEquiped[j], isLocked: false);
					}
					else
					{
						equipedWindow[j].GetComponent<UIProfileEquipedDisplay>().ReadData(null, isLocked: true);
					}
				}
			}
			else
			{
				Debug.Log((object)"Error : gItemInfoEquiped.Length > equipLimitedNum");
			}
			return;
		}
		for (int k = 0; k < 8; k++)
		{
			if (k < equipLimitedNum)
			{
				equipedWindow[k].GetComponent<UIProfileEquipedDisplay>().ReadData(null, isLocked: false);
			}
			else
			{
				equipedWindow[k].GetComponent<UIProfileEquipedDisplay>().ReadData(null, isLocked: true);
			}
		}
	}

	public void UpdateWeaponData()
	{
		gItemInfo = GrowthManagerKit.GetUserAllEnabledWeaponItemInfo();
		if (gItemInfo != null)
		{
			for (int i = 0; i < gItemInfo.Length; i++)
			{
				if (gItemInfo[i] != null)
				{
					newWeaponObj[i].GetComponent<UIProfileWeaponPrefab>().gItemInfo = gItemInfo[i];
					newWeaponObj[i].GetComponent<UIProfileWeaponPrefab>().ReadData(gItemInfo[i]);
				}
				else
				{
					Debug.Log((object)"gItemInfo[i] is null");
				}
			}
		}
		SetEquipWindow();
	}

	private void GetSkinData()
	{
		skinNameList = GrowthManagerKit.GetUserAllEnabledSkinName();
		gSkinItemInfo = GrowthManagerKit.GetUserAllEnabledSkinItemInfo();
		curSkinInfo = GrowthManagerKit.GetCurSettedSkinInfo();
		skinNum = gSkinItemInfo.Length;
		idList = new int[skinNum];
		for (int i = 0; i < skinNum; i++)
		{
			idList[i] = gSkinItemInfo[i].mId.mId_3;
			if (gSkinItemInfo[i].mNameDisplay == curSkinInfo.mNameDisplay)
			{
				curSkinId = idList[i] - 1;
				skinUsingId = idList[i] - 1;
				curSkinIndexinIdList = i;
			}
		}
	}

	private void SetSkinData()
	{
		setMaterial(curSkinId);
		skinDisNameLabel.text = gSkinItemInfo[curSkinIndexinIdList].mNameDisplay;
		if (curSkinId == skinUsingId)
		{
			((Component)((Component)setSkinBtn).transform).GetComponent<UIImageButton>().isEnabled = false;
			skinSetLabel.text = "Equipped";
		}
		else
		{
			((Component)((Component)setSkinBtn).transform).GetComponent<UIImageButton>().isEnabled = true;
			skinSetLabel.text = "Set";
		}
	}

