				((Component)BgSprite).GetComponent<UISprite>().spriteName = "WeaponCarryLocked";
				((Component)BgSprite).GetComponent<UISprite>().MarkAsChanged();
			}
			return;
		}
		if (info != null)
		{
			if ((Object)(object)LogoSprite != (Object)null)
			{
				((Component)LogoSprite).gameObject.SetActive(true);
				((Component)LogoSprite).GetComponent<UISprite>().spriteName = info.mLogoSpriteName;
				((Component)LogoSprite).GetComponent<UISprite>().MarkAsChanged();
