			((Component)LogoSprite).gameObject.SetActive(false);
		}
		if ((Object)(object)BgSprite != (Object)null)
		{
			((Component)BgSprite).GetComponent<UISprite>().spriteName = "WeaponCarryUnlocked";
			((Component)BgSprite).GetComponent<UISprite>().MarkAsChanged();
		}
	}
