public class PuchaseStausLabel : MonoBehaviour
{
	private float fTime;

	private void Start()
	{
	}

	private void Update()
	{
		//IL_0063: Unknown result type (might be due to invalid IL or missing references)
		//IL_00f6: Unknown result type (might be due to invalid IL or missing references)
		if (UIStoreDirector.mInstance.purchaseStaus == UIStoreDirector.PurchaseStaus.Failed || UIStoreDirector.mInstance.purchaseStaus == UIStoreDirector.PurchaseStaus.Successful)
		{
			fTime += Time.deltaTime;
			if (fTime > 6f)
			{
				UIStoreDirector.mInstance.purchaseStaus = UIStoreDirector.PurchaseStaus.Nil;
				fTime = 0f;
				((Component)this).gameObject.GetComponent<UILabel>().color = Color.white;
			}
		}
		switch (UIStoreDirector.mInstance.purchaseStaus)
		{
		case UIStoreDirector.PurchaseStaus.Processing:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Purchase processing...";
			break;
		case UIStoreDirector.PurchaseStaus.Successful:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Purchase successful!";
			break;
		case UIStoreDirector.PurchaseStaus.Failed:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Purchase failed : " + UIStoreDirector.mInstance.purchaseError;
			((Component)this).gameObject.GetComponent<UILabel>().color = Color.red;
			break;
		case UIStoreDirector.PurchaseStaus.Nil:
			((Component)this).gameObject.GetComponent<UILabel>().text = string.Empty;
			break;
		}
	}
