			UIMenuDirectorExt.mInstance.SendMsgBtnPressed();
			break;
		case ButtonName.Aim:
			UIMenuDirectorExt.mInstance.AimBtnPressed();
			break;
		case ButtonName.BottomUp:
			UIMenuDirectorExt.mInstance.BottomUpBtnPressed();
			break;
		case ButtonName.BottomDown:
			UIMenuDirectorExt.mInstance.BottomDownBtnPressed();
			break;
		case ButtonName.TopUp:
			UIMenuDirectorExt.mInstance.TopUpBtnPressed();
			break;
		case ButtonName.TopDown:
			UIMenuDirectorExt.mInstance.TopDownBtnPressed();
			break;
		case ButtonName.GotoHall:
			Application.LoadLevel("MultiPlayerSelect");
			break;
		case ButtonName.PushChatText:
			if (UIMenuDirector.mInstance.isShowChatText)
			{
				UIMenuDirector.mInstance.PushChatTextEvent(bTemp: true);
				UIMenuDirector.mInstance.isShowChatText = false;
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "PushChatText";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "PushChatText";
			}
			else
			{
				UIMenuDirector.mInstance.PushChatTextEvent(bTemp: false);
				UIMenuDirector.mInstance.isShowChatText = true;
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "PopChatText";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "PopChatText";
			}
			break;
		case ButtonName.WeaponSwitch:
			UIMenuDirector.mInstance.isSwitched = true;
			break;
		case ButtonName.Equipment:
			Application.LoadLevel("ProfileScene");
			break;
		case ButtonName.Reload:
			PlayerPrefs.SetInt("FpsReload", 1);
			break;
		case ButtonName.NewRound:
			UIMenuDirectorExt.mInstance.StrongHoldNewRoundBtnPressed();
			break;
		case ButtonName.MoreGameScene:
			Application.LoadLevel("MoreGame");
			break;
		case ButtonName.SwitchLeft:
			PlayerPrefs.SetInt("WeaponSwipeLeft", 1);
			break;
		case ButtonName.SwitchRight:
			PlayerPrefs.SetInt("WeaponSwipeRight", 1);
			break;
		case ButtonName.ToHelpScene:
			Application.LoadLevel("Help");
			break;
		case ButtonName.AddCoins:
			UIMenuDirectorExt.mInstance.AddCoinsBtnPressed();
			break;
		case ButtonName.AddGems:
			UIMenuDirectorExt.mInstance.AddGemsBtnPressed();
			break;
		case ButtonName.CloseShop:
			UIMenuDirectorExt.mInstance.CloseShopBtnPressed();
			break;
		case ButtonName.ShowVideoBtn:
			VideoRecordController.ShowVideoRecordInfo();
			break;
		case ButtonName.RecordBtnInGame:
			if (VideoRecordController.IsRecording())
			{
				VideoRecordController.StopRecording();
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "VideoRecord_Start";
				((Component)this).gameObject.GetComponent<UIImageButton>().hoverSprite = "VideoRecord_Start";
				((Component)this).gameObject.GetComponent<UIImageButton>().pressedSprite = "VideoRecord_Start";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "VideoRecord_Start";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().MarkAsChanged();
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = string.Empty;
			}
			else
			{
				VideoRecordController.StartRecording();
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "VideoRecord_Stop";
				((Component)this).gameObject.GetComponent<UIImageButton>().hoverSprite = "VideoRecord_Stop";
				((Component)this).gameObject.GetComponent<UIImageButton>().pressedSprite = "VideoRecord_Stop";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "VideoRecord_Stop";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().MarkAsChanged();
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = ".REC";
			}
			break;
		case ButtonName.Nil:
			break;
		case ButtonName.FpsFire:
			break;
		}
	}

	private void OnPress()
	{
		if (buttonName == ButtonName.FpsFire)
		{
			if (PlayerPrefs.GetInt("FpsOnFire", 0) == 0)
			{
				PlayerPrefs.SetInt("FpsOnFire", 1);
			}
			else
			{
				PlayerPrefs.SetInt("FpsOnFire", 0);
			}
		}
	}

	private void Start()
	{
		if (buttonName == ButtonName.InnerLeaderboard)
		{
			InnerLeaderboard = GameObject.Find("Panel(LocalLeaderboard)");
			if ((Object)(object)InnerLeaderboard != (Object)null)
			{
				TweenAlpha.Begin(InnerLeaderboard, 0.05f, 0f);
				((MonoBehaviour)this).StartCoroutine(PushInnerLeaderboard(0.05f));
			}
		}
		if (buttonName == ButtonName.InnerLeaderboardBack)
		{
			InnerLeaderboard = GameObject.Find("Panel(LocalLeaderboard)");
			if ((Object)(object)InnerLeaderboard != (Object)null)
			{
				TweenAlpha.Begin(InnerLeaderboard, 0.05f, 0f);
				((MonoBehaviour)this).StartCoroutine(PushInnerLeaderboard(0.05f));
			}
		}
	}

	private void Update()
	{
		switch (buttonName)
		{
		}
	}

	private IEnumerator PushInnerLeaderboard(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		if ((Object)(object)InnerLeaderboard != (Object)null)
		{
			InnerLeaderboard.SetActive(false);
		}
	}
}
