				int num5 = text.Length % 30;
				if (num5 != 0)
				{
					num4++;
				}
				for (int i = 0; i < 8; i++)
				{
					if (i + 1 > num4)
					{
						msgLineCacheList[i - num4] = msgLineCacheList[i];
						msgCountList[i - num4] = msgCountList[i];
					}
				}
				for (int j = 0; j < num4 && j < 8; j++)
				{
					if (j == 0)
					{
						msgLineCacheList[8 - j - 1] = text.Substring((num4 - j - 1) * 30, num5);
					}
					else
					{
						msgLineCacheList[8 - j - 1] = text.Substring((num4 - j - 1) * 30, 30);
					}
					msgCountList[8 - j - 1] = 0;
				}
				CRMultiplayerManager.mInstance.mMessageList.RemoveAt(0);
			}
			((Component)this).gameObject.GetComponent<UILabel>().text = string.Empty;
			for (int k = 0; k < 8; k++)
			{
				msgCountList[k]++;
				if (msgCountList[k] > 256)
				{
					msgLineCacheList[k] = string.Empty;
					msgCountList[k] = 0;
				}
				if (msgLineCacheList[k] != string.Empty)
				{
					UILabel component = ((Component)this).gameObject.GetComponent<UILabel>();
					component.text = component.text + "\n" + msgLineCacheList[k];
