public class UIGameSceneDirector : MonoBehaviour
{
	public delegate void MediKitEventHandler();

	public delegate void AddArmorEventHandler();

	private const int mediKitPrice = 30;

	public static UIGameSceneDirector mInstance;

	public UIImageButton addArmorBtn;

	public UISprite addArmorBackgroudF;

	public UISprite addArmorBackgroudB;

	public GameObject addArmorTip;

	public UILabel addArmorTipLabel;

	public UIImageButton mediKitBtn;

	public UISprite mediKitBackgroudF;

	public UISprite mediKitBackgroudB;

	public GameObject mediKitTip;

	public UILabel mediKitTipLabel;

	private float fMediTime;

	private bool canUseMediKit;

	private int preBlood;

	public static event MediKitEventHandler OnMediKit;

	public static event AddArmorEventHandler OnAddArmor;

	public void MediKitBtnPressed()
	{
		Debug.Log((object)"MediKitBtnPressed");
		if (GrowthManagerKit.GetCoins() >= 30)
		{
			GrowthManagerKit.SubCoins(30);
			canUseMediKit = false;
			((Component)mediKitBtn).GetComponent<UIImageButton>().isEnabled = false;
			GenMediKitEvent();
			((Component)mediKitBtn).gameObject.SetActive(false);
			mediKitTipLabel.text = " - " + 30;
			mediKitTip.SetActive(true);
			((MonoBehaviour)this).StartCoroutine(PushMediKitTip(1f));
		}
		else
		{
			((Component)mediKitBtn).gameObject.SetActive(false);
			mediKitTipLabel.text = "  Lack";
			mediKitTip.SetActive(true);
			((MonoBehaviour)this).StartCoroutine(PushMediKitTip(1f));
		}
	}

	private IEnumerator PushMediKitTip(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		((Component)mediKitBtn).gameObject.SetActive(true);
		mediKitTip.SetActive(false);
	}

	public void GenMediKitEvent()
	{
		if (UIGameSceneDirector.OnMediKit != null)
		{
			UIGameSceneDirector.OnMediKit();
		}
	}

	public void AddArmorBtnPressed()
	{
		Debug.Log((object)"AddArmorBtnPressed");
		int mSinglePrice = CNRMultiplayerManager.mInstance.myArmorInfo.mSinglePrice;
		if (GrowthManagerKit.GetCoins() >= mSinglePrice)
		{
			GenAddArmorEvent();
			((Component)addArmorBtn).GetComponent<UIImageButton>().isEnabled = false;
			addArmorTipLabel.text = " - " + mSinglePrice;
			((Component)addArmorBtn).gameObject.SetActive(false);
			addArmorTip.SetActive(true);
			((MonoBehaviour)this).StartCoroutine(PushAddBulletTip(1f));
		}
		else
		{
			addArmorTipLabel.text = "  Lack";
			((Component)addArmorBtn).gameObject.SetActive(false);
			addArmorTip.SetActive(true);
			((MonoBehaviour)this).StartCoroutine(PushAddBulletTip(1f));
		}
	}

	public void GenAddArmorEvent()
	{
		if (UIGameSceneDirector.OnAddArmor != null)
		{
			UIGameSceneDirector.OnAddArmor();
		}
	}

	private IEnumerator PushAddBulletTip(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		((Component)addArmorBtn).gameObject.SetActive(true);
		addArmorTip.SetActive(false);
	}

	private void Awake()
	{
		mInstance = this;
	}

	private void OnDestroy()
	{
		if ((Object)(object)mInstance == (Object)(object)this)
		{
			mInstance = null;
		}
	}

	private void Start()
	{
		if ((Object)(object)mediKitBtn != (Object)null)
		{
			((Component)mediKitBtn).GetComponent<UIImageButton>().isEnabled = false;
		}
		if ((Object)(object)addArmorBtn != (Object)null)
		{
			((Component)addArmorBtn).GetComponent<UIImageButton>().isEnabled = false;
		}
		preBlood = PlayerLogic.mInstance.blood;
		SetArmorDurabilityDisplay();
	}

	private void Update()
	{
		if (!canUseMediKit)
		{
			fMediTime += Time.deltaTime;
			mediKitBackgroudF.fillAmount = fMediTime / 180f;
			if (fMediTime >= 180f)
			{
				fMediTime = 0f;
				canUseMediKit = true;
				if (PlayerLogic.mInstance.blood < 100)
				{
					((Component)mediKitBtn).GetComponent<UIImageButton>().isEnabled = true;
				}
				else
				{
					((Component)mediKitBtn).GetComponent<UIImageButton>().isEnabled = false;
				}
			}
		}
		else if (PlayerLogic.mInstance.blood > 0)
		{
			if (PlayerLogic.mInstance.blood < 100 && preBlood != PlayerLogic.mInstance.blood)
			{
				((Component)mediKitBtn).GetComponent<UIImageButton>().isEnabled = true;
				preBlood = PlayerLogic.mInstance.blood;
			}
		}
		else if (preBlood != PlayerLogic.mInstance.blood)
		{
			((Component)mediKitBtn).GetComponent<UIImageButton>().isEnabled = false;
			preBlood = PlayerLogic.mInstance.blood;
		}
	}

	private void SetArmorDurabilityDisplay()
	{
		addArmorBtn.normalSprite = CNRMultiplayerManager.mInstance.myArmorInfo.mInGameLogoSpriteNameBg;
		addArmorBtn.pressedSprite = CNRMultiplayerManager.mInstance.myArmorInfo.mInGameLogoSpriteNameBg;
		addArmorBtn.hoverSprite = CNRMultiplayerManager.mInstance.myArmorInfo.mInGameLogoSpriteNameBg;
		addArmorBtn.disabledSprite = CNRMultiplayerManager.mInstance.myArmorInfo.mInGameLogoSpriteNameBg;
		((Component)addArmorBtn).GetComponentInChildren<UISprite>().spriteName = CNRMultiplayerManager.mInstance.myArmorInfo.mInGameLogoSpriteNameBg;
		addArmorBackgroudF.spriteName = CNRMultiplayerManager.mInstance.myArmorInfo.mInGameLogoSpriteNameFg;
	}

	public void UpdateArmorDurabilityDisplay(int iTemp)
	{
		((Component)addArmorBackgroudF).GetComponent<UISprite>().fillAmount = (float)iTemp * 0.01f;
		Debug.Log((object)((Component)addArmorBackgroudF).GetComponent<UISprite>().fillAmount);
		if (iTemp < 100)
		{
			((Component)addArmorBtn).GetComponent<UIImageButton>().isEnabled = true;
		}
		else
		{
			((Component)addArmorBtn).GetComponent<UIImageButton>().isEnabled = false;
		}
	}
}
public class UIInputOnSubmit : MonoBehaviour
{
	public UILabel showLabel;

	private void Start()
	{
	}

	private void Update()
	{
	}

	private void OnSubmit(string str)
	{
		if (str == string.Empty)
		{
			Debug.Log((object)"str == null");
			if ((Object)(object)UIMenuDirector.mInstance != (Object)null)
			{
				UIMenuDirector.mInstance.ResetChatTextPosition();
			}
		}
		else if ((Object)(object)UIMenuDirector.mInstance != (Object)null)
		{
			UIMenuDirector.mInstance.GenSendMsgEvent(StringFix(showLabel.text));
			UIMenuDirector.mInstance.ResetChatTextPosition();
		}
	}

	private string StringFix(string str)
	{
		str = str.Replace("|", string.Empty);
		return str;
	}
}
public class UIInputOnSubmitNickName : MonoBehaviour
{
	public UILabel NickNameLabel;

	private bool canChangeNickName;

	private void Start()
	{
		NickNameLabel.text = GrowthManagerKit.GetMyNickName();
	}

	private void Update()
	{
		if (canChangeNickName)
		{
			canChangeNickName = false;
			NickNameLabel.text = GrowthManagerKit.GetMyNickName();
		}
	}

	private void OnSubmit()
	{
		string text = StringFix(NickNameLabel.text);
		NickNameLabel.text = text;
		if ((Object)(object)WordFilter.mInstance != (Object)null)
		{
			NickNameLabel.text = WordFilter.mInstance.FilterString(NickNameLabel.text);
		}
		GrowthManagerKit.SetMyNickName(NickNameLabel.text);
		canChangeNickName = true;
	}

	private string StringFix(string str)
	{
		str = str.Replace("_", "-");
		str = str.Replace("|", string.Empty);
		return str;
	}
}
