	private string GetSceneNameByTag(SceneTag sTag)
	{
		return sTag switch
		{
			SceneTag.MainMenu => "MainMenu", 
			SceneTag.FreeRun => "FreeRun", 
			SceneTag.FreeRun2 => "FreeRun2", 
			SceneTag.MultiplayerLocal => "MultiplayerSelect", 
			SceneTag.SinglePlayer => "SinglePlayerMode", 
			SceneTag.CNR => "CRScene1", 
			SceneTag.Store => "StoreScene", 
			SceneTag.Nil => null, 
			_ => null, 
		};
	}

	public void ToScene(SceneTag sTag)
	{
		switch (sTag)
		{
		case SceneTag.FreeRun:
			GenGameModSelectEvent(SceneModTag.SceneModTag_1);
			break;
		case SceneTag.FreeRun2:
			GenGameModSelectEvent(SceneModTag.SceneModTag_2);
			break;
		case SceneTag.CNR:
			curSceneTag = sTag;
			((MonoBehaviour)this).StartCoroutine(StartSingleScene());
			return;
		}
		Application.LoadLevel(GetSceneNameByTag(sTag));
		curSceneTag = sTag;
	}

	public void ToSelectedModPic(SceneModTag sTag)
	{
		switch (sTag)
		{
		case SceneModTag.SceneModTag_1:
			curSceneTag = SceneTag.FreeRun;
			((MonoBehaviour)this).StartCoroutine(StartSingleScene());
			break;
		case SceneModTag.SceneModTag_2:
			curSceneTag = SceneTag.FreeRun2;
			((MonoBehaviour)this).StartCoroutine(StartSingleScene());
			break;
		case SceneModTag.SceneModTag_4:
			curSceneTag = SceneTag.MultiplayerLocal;
			break;
		case SceneModTag.SceneModTag_5:
			curSceneTag = SceneTag.SinglePlayer;
			break;
		case SceneModTag.SceneModTag_6:
			curSceneTag = SceneTag.CNR;
			break;
		case SceneModTag.SceneModTag_3:
			break;
		}
	}

	private IEnumerator StartSingleScene()
	{
		PushPanel(PanelTag.LUIRootLoading);
		PopPanel(PanelTag.UIRootLoading);
		yield return (object)new WaitForSeconds(0.5f);
		Application.LoadLevel(GetSceneNameByTag(curSceneTag));
	}

