	private void Start()
	{
		isChat = false;
		PlayerPrefs.SetInt("FpsOnFire", 0);
		if ((Object)(object)resultPanel != (Object)null)
		{
			resultPanel.SetActiveRecursively(false);
			resultPanel.SetActive(true);
		}
		if ((Object)(object)newRoundBtn != (Object)null)
		{
			DisableBtn(newRoundBtn);
		}
	}

	private void Update()
	{
		if ((Object)(object)CNRMultiplayerManager.mInstance != (Object)null)
		{
			if (!CNRMultiplayerManager.mInstance.isPhotonConnected)
			{
				PopPanel(PanelTag.LostConnection);
				PushPanel(PanelTag.PausePanel);
			}
			else
			{
				PushPanel(PanelTag.LostConnection);
			}
		}
	}

