	public void DisableBtn(GameObject btn)
	{
		btn.GetComponent<UIImageButton>().isEnabled = false;
	}

	public void EnableBtn(GameObject btn)
	{
		btn.GetComponent<UIImageButton>().isEnabled = true;
	}

