	public void ReadResult(TeamType winTeam, PlayerInfo myPInfo, GrowthGameRatingTag myRating, List<GrowthGameRatingTag> copRatingList, List<GrowthGameRatingTag> robberRatingList, List<PlayerInfo> copRankInfoList, List<PlayerInfo> robberRankInfoList)
	{
		if ((Object)(object)resultInfoList != (Object)null)
		{
			if (CNRMultiplayerManager.mInstance.myModeInfo.mCurMode == GrowthGameModeTag.tStronghold)
			{
				resultInfoList.GetComponent<ResultInfoListDataReader>().ShowStrongholdModeResult(winTeam, myPInfo, myRating, copRatingList, robberRatingList, copRankInfoList, robberRankInfoList);
			}
			else if (CNRMultiplayerManager.mInstance.myModeInfo.mCurMode == GrowthGameModeTag.tKillingCompetition)
			{
				resultInfoList.GetComponent<ResultInfoListDataReader>().ShowKillingCompetitionModeResult(winTeam, myPInfo, myRating, copRatingList, robberRatingList, copRankInfoList, robberRankInfoList);
			}
		}
	}

	private void EquipAWP()
	{
		if ((Object)(object)AimBtn != (Object)null)
		{
			AimBtn.SetActive(true);
		}
	}

	private void NoEquipAWP()
	{
		if ((Object)(object)AimBtn != (Object)null)
		{
			AimBtn.SetActive(false);
		}
	}

	public void AddBulletCallBack(int iTemp)
	{
		if (iTemp > 0)
		{
			addBulletTipsLabel.GetComponent<UILabel>().text = " - " + iTemp;
		}
		else
		{
			addBulletTipsLabel.GetComponent<UILabel>().text = "  Lack";
		}
		PopPanel(PanelTag.AddBulletTipsPanel);
		((MonoBehaviour)this).StartCoroutine(PushAddBulletTipsPanel(1f));
		if ((Object)(object)switchBtn != (Object)null)
		{
			switchBtn.SetActive(false);
		}
	}
}
