public class ResultInfoListDataReader : MonoBehaviour
{
	private const int MAX_DISPLAY_NUM = 7;

	public UILabel[] mCopNickName = new UILabel[7];

	public UILabel[] mCopKillDeadNum = new UILabel[7];

	public UILabel[] mCopRating = new UILabel[7];

	public UILabel[] mRobberNickName = new UILabel[7];

	public UILabel[] mRobberKillDeadNum = new UILabel[7];

	public UILabel[] mRobberRating = new UILabel[7];

	public UILabel coinNumLabel;

	public UILabel expNumLabel;

	public UILabel copResourceNumLabel;

	public UILabel robberResourceNumLabel;

	private int coinNum;

	private int expNum;

	private int copResourceNum;

	private int robberResourceNum;

	private int resourceTotalNum;

	private float copResFillAmount;

	private float robberResFillAmount;

	public UISprite ratingSprite;

	public UISprite copResSprite;

	public UISprite robberResSprite;

	public UISprite robberWinSprite;

	public UISprite copWinSprite;

	private bool canStartAnimationCop;

	private bool canStartAnimationRob;

	private bool canStartAnimation;

	private bool isCopWin;

	public GameObject showRatingAudio;

	private int copKillNum;

	private int robberKillNum;

	private int killTotalNum;

	private float copKillFillAmount;

	private float robberKillFillAmount;

	private void Awake()
	{
		robberWinSprite.alpha = 0f;
		copWinSprite.alpha = 0f;
		for (int i = 0; i < 7; i++)
		{
			mCopNickName[i] = ((Component)((Component)this).transform.FindChild("Label(NickB" + (i + 1) + ")")).GetComponent<UILabel>();
			mCopKillDeadNum[i] = ((Component)((Component)this).transform.FindChild("Label(KillB" + (i + 1) + ")")).GetComponent<UILabel>();
			mCopRating[i] = ((Component)((Component)this).transform.FindChild("Label(RB" + (i + 1) + ")")).GetComponent<UILabel>();
			mCopNickName[i].text = string.Empty;
			mCopKillDeadNum[i].text = string.Empty;
			mCopRating[i].text = string.Empty;
			mRobberNickName[i] = ((Component)((Component)this).transform.FindChild("Label(Nick" + (i + 1) + ")")).GetComponent<UILabel>();
			mRobberKillDeadNum[i] = ((Component)((Component)this).transform.FindChild("Label(Kill" + (i + 1) + ")")).GetComponent<UILabel>();
			mRobberRating[i] = ((Component)((Component)this).transform.FindChild("Label(R" + (i + 1) + ")")).GetComponent<UILabel>();
			mRobberNickName[i].text = string.Empty;
			mRobberKillDeadNum[i].text = string.Empty;
			mRobberRating[i].text = string.Empty;
		}
	}

	public void ShowStrongholdModeResult(TeamType winTeam, PlayerInfo myPInfo, GrowthGameRatingTag myRating, List<GrowthGameRatingTag> copRatingList, List<GrowthGameRatingTag> robberRatingList, List<PlayerInfo> copRankInfoList, List<PlayerInfo> robberRankInfoList)
	{
		for (int i = 0; i < copRankInfoList.Count; i++)
		{
			Debug.Log((object)("Cop-" + copRankInfoList[i].mNickName + " : " + copRatingList[i]));
		}
		for (int j = 0; j < robberRankInfoList.Count; j++)
		{
			Debug.Log((object)("Rob-" + robberRankInfoList[j].mNickName + " : " + robberRatingList[j]));
		}
		for (int k = 0; k < 7; k++)
		{
			if (k < copRankInfoList.Count && k < copRatingList.Count)
			{
				mCopNickName[k].text = copRankInfoList[k].mNickName;
				mCopKillDeadNum[k].text = copRankInfoList[k].mKillNum + "/" + copRankInfoList[k].mDeadNum;
				mCopRating[k].text = copRatingList[k].ToString().Split('_')[1];
			}
			if (k < robberRankInfoList.Count && k < robberRatingList.Count)
			{
				mRobberNickName[k].text = robberRankInfoList[k].mNickName;
				mRobberKillDeadNum[k].text = robberRankInfoList[k].mKillNum + "/" + robberRankInfoList[k].mDeadNum;
				mRobberRating[k].text = robberRatingList[k].ToString().Split('_')[1];
			}
		}
		int num = CNRMultiplayerManager.mInstance.myPlayerInfo.mKillNum - CNRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
		if (num <= 0)
		{
			num = 0;
		}
		coinNum = GrowthManagerKit.GetOncePlayCoinsReward(GrowthGameModeTag.tStronghold, myRating) + num + 10;
		expNum = GrowthManagerKit.GetOncePlayExpReward(GrowthGameModeTag.tStronghold, myRating);
		coinNumLabel.text = "+" + coinNum;
		expNumLabel.text = "+" + expNum;
		SetMyRatingSprite(myRating);
		if ((Object)(object)CNRMultiplayerManager.mInstance != (Object)null && CNRMultiplayerManager.mInstance.myModeInfo.mCurMode == GrowthGameModeTag.tStronghold)
		{
			copResourceNum = CNRMultiplayerManager.mInstance.myModeInfo.mStrongholdInfo.copResource;
			robberResourceNum = CNRMultiplayerManager.mInstance.myModeInfo.mStrongholdInfo.robberResource;
			resourceTotalNum = CNRMultiplayerManager.mInstance.myModeInfo.mStrongholdInfo.MAX_RESOURCES;
			if (winTeam == TeamType.Robber)
			{
				copResourceNum = 0;
				robberWinSprite.alpha = 1f;
				copWinSprite.alpha = 0f;
				copResourceNumLabel.text = "+" + copResourceNum;
				robberResourceNumLabel.text = "+" + robberResourceNum;
			}
			else
			{
				robberResourceNum = 0;
				robberWinSprite.alpha = 0f;
				copWinSprite.alpha = 1f;
				copResourceNumLabel.text = "+" + copResourceNum;
				robberResourceNumLabel.text = "+" + robberResourceNum;
			}
			copResFillAmount = copResourceNum * 100 / resourceTotalNum;
			robberResFillAmount = robberResourceNum * 100 / resourceTotalNum;
			copResFillAmount /= 100f;
			robberResFillAmount /= 100f;
			((Component)copResSprite).GetComponent<UISprite>().fillAmount = copResFillAmount;
			((Component)robberResSprite).GetComponent<UISprite>().fillAmount = robberResFillAmount;
		}
		((MonoBehaviour)this).StartCoroutine(ShowRatingSprite(0.6f));
	}

	public void ShowKillingCompetitionModeResult(TeamType winTeam, PlayerInfo myPInfo, GrowthGameRatingTag myRating, List<GrowthGameRatingTag> copRatingList, List<GrowthGameRatingTag> robberRatingList, List<PlayerInfo> copRankInfoList, List<PlayerInfo> robberRankInfoList)
	{
		for (int i = 0; i < copRankInfoList.Count; i++)
		{
			Debug.Log((object)("Cop-" + copRankInfoList[i].mNickName + " : " + copRatingList[i]));
		}
		for (int j = 0; j < robberRankInfoList.Count; j++)
		{
			Debug.Log((object)("Rob-" + robberRankInfoList[j].mNickName + " : " + robberRatingList[j]));
		}
		for (int k = 0; k < 7; k++)
		{
			if (k < copRankInfoList.Count && k < copRatingList.Count)
			{
				mCopNickName[k].text = copRankInfoList[k].mNickName;
				mCopKillDeadNum[k].text = copRankInfoList[k].mKillNum + "/" + copRankInfoList[k].mDeadNum;
				mCopRating[k].text = copRatingList[k].ToString().Split('_')[1];
			}
			if (k < robberRankInfoList.Count && k < robberRatingList.Count)
			{
				mRobberNickName[k].text = robberRankInfoList[k].mNickName;
				mRobberKillDeadNum[k].text = robberRankInfoList[k].mKillNum + "/" + robberRankInfoList[k].mDeadNum;
				mRobberRating[k].text = robberRatingList[k].ToString().Split('_')[1];
			}
		}
		int num = CNRMultiplayerManager.mInstance.myPlayerInfo.mKillNum - CNRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
		if (num <= 0)
		{
			num = 0;
		}
		coinNum = GrowthManagerKit.GetOncePlayCoinsReward(GrowthGameModeTag.tKillingCompetition, myRating) + num + 10;
		expNum = GrowthManagerKit.GetOncePlayExpReward(GrowthGameModeTag.tKillingCompetition, myRating);
		coinNumLabel.text = "+" + coinNum;
		expNumLabel.text = "+" + expNum;
		SetMyRatingSprite(myRating);
		if ((Object)(object)CNRMultiplayerManager.mInstance != (Object)null && CNRMultiplayerManager.mInstance.myModeInfo.mCurMode == GrowthGameModeTag.tKillingCompetition)
		{
			killTotalNum = CNRMultiplayerManager.mInstance.myModeInfo.mKillingCompetitionInfo.MAXKilling;
			copKillNum = CNRMultiplayerManager.mInstance.myModeInfo.mKillingCompetitionInfo.copKilling;
			robberKillNum = CNRMultiplayerManager.mInstance.myModeInfo.mKillingCompetitionInfo.robberKilling;
			if (copKillNum > killTotalNum)
			{
				copKillNum = killTotalNum;
			}
			if (robberKillNum > killTotalNum)
			{
				robberKillNum = killTotalNum;
			}
			copKillFillAmount = copKillNum * 100 / killTotalNum;
			robberKillFillAmount = robberKillNum * 100 / killTotalNum;
			((Component)copResSprite).GetComponent<UISprite>().fillAmount = copKillFillAmount / 100f;
			((Component)robberResSprite).GetComponent<UISprite>().fillAmount = robberKillFillAmount / 100f;
			robberResourceNumLabel.text = robberKillNum + "/" + killTotalNum;
			copResourceNumLabel.text = copKillNum + "/" + killTotalNum;
			if (winTeam == TeamType.Robber)
			{
				robberWinSprite.alpha = 1f;
				copWinSprite.alpha = 0f;
			}
			else
			{
				robberWinSprite.alpha = 0f;
				copWinSprite.alpha = 1f;
			}
		}
		((MonoBehaviour)this).StartCoroutine(ShowRatingSprite(0.6f));
	}

	private void FillAmountAnimation()
	{
		if ((Object)(object)copResSprite != (Object)null)
		{
			if (copResFillAmount >= 0f)
			{
				copResFillAmount -= 0.004f;
				((Component)copResSprite).GetComponent<UISprite>().fillAmount = copResFillAmount;
			}
			if (copResourceNum > 0 && Time.frameCount % 5 == 0)
			{
				copResourceNum--;
				copResourceNumLabel.text = "+" + copResourceNum;
			}
			if (copResFillAmount <= 0f && copResourceNum <= 0)
			{
				canStartAnimationCop = false;
			}
		}
		if ((Object)(object)robberResSprite != (Object)null)
		{
			if (robberResFillAmount >= 0f)
			{
				robberResFillAmount -= 0.004f;
				((Component)robberResSprite).GetComponent<UISprite>().fillAmount = robberResFillAmount;
			}
			if (robberResourceNum > 0 && Time.frameCount % 5 == 0)
			{
				robberResourceNum--;
				robberResourceNumLabel.text = "+" + robberResourceNum;
			}
			if (robberResFillAmount <= 0f && robberResourceNum <= 0)
			{
				canStartAnimationRob = false;
			}
		}
	}

	private void SetMyRatingSprite(GrowthGameRatingTag myRating)
	{
		ratingSprite.alpha = 0f;
		switch (myRating)
		{
		case GrowthGameRatingTag.RatingTag_A:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_A";
			break;
		case GrowthGameRatingTag.RatingTag_B:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_B";
			break;
		case GrowthGameRatingTag.RatingTag_C:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_C";
			break;
		case GrowthGameRatingTag.RatingTag_D:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_D";
			break;
		case GrowthGameRatingTag.RatingTag_E:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_E";
			break;
		case GrowthGameRatingTag.RatingTag_F:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_F";
			break;
		case GrowthGameRatingTag.RatingTag_S:
			((Component)ratingSprite).GetComponent<UISprite>().spriteName = "Rating_S";
			break;
		}
	}

	private void Update()
	{
		if (canStartAnimationRob || canStartAnimationCop)
		{
			FillAmountAnimation();
		}
		else if (canStartAnimation)
		{
			showRatingAudio.GetComponent<AudioSource>().Play();
			((MonoBehaviour)this).StartCoroutine(ShowRatingSprite(0.5f));
		}
	}

	private IEnumerator ShowRatingSprite(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		if (!canStartAnimationRob && !canStartAnimationCop)
		{
			canStartAnimation = false;
			ratingSprite.alpha = 1f;
		}
	}

	private IEnumerator DelayToAShowAnimation(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		canStartAnimation = true;
		canStartAnimationCop = true;
		canStartAnimationRob = true;
	}
}
