public class UIPopMessagePrefab : MonoBehaviour
{
	public enum MessageTag
	{
		Nil,
		Coin,
		Exp,
		KillInfo
	}

	public MessageTag messageTag;

	public UILabel coinNumLabel;

	public UILabel expNumLabel;

	public UILabel killInfoNumLabel;

	public readonly float LIFE_CYCLE_TIME = 1.5f;

	private void Start()
	{
		//IL_0021: Unknown result type (might be due to invalid IL or missing references)
		//IL_004d: Unknown result type (might be due to invalid IL or missing references)
		//IL_0053: Expected O, but got Unknown
		ReadData();
		TweenPosition.Begin(((Component)this).gameObject, LIFE_CYCLE_TIME, new Vector3(0f, 0.27f, 0f)).method = UITweener.Method.EaseOut;
		foreach (Transform item in ((Component)this).gameObject.transform)
		{
			Transform val = item;
			TweenAlpha.Begin(((Component)val).gameObject, LIFE_CYCLE_TIME, 0f);
		}
	}

	private void Update()
	{
	}

	private void ReadData()
	{
		if (UIPopMessageDirector.mInstance.mPopMessageList.Count <= 0)
		{
			return;
		}
		switch (messageTag)
		{
		case MessageTag.Coin:
			if ((Object)(object)coinNumLabel != (Object)null)
			{
				coinNumLabel.text = UIPopMessageDirector.mInstance.mPopMessageList[0];
				UIPopMessageDirector.mInstance.mPopMessageList.RemoveAt(0);
				UIPopMessageDirector.mInstance.mPopMessageTypeList.RemoveAt(0);
			}
			break;
		case MessageTag.Exp:
			if ((Object)(object)expNumLabel != (Object)null)
			{
				expNumLabel.text = UIPopMessageDirector.mInstance.mPopMessageList[0];
				UIPopMessageDirector.mInstance.mPopMessageList.RemoveAt(0);
				UIPopMessageDirector.mInstance.mPopMessageTypeList.RemoveAt(0);
			}
			break;
		case MessageTag.KillInfo:
			if ((Object)(object)killInfoNumLabel != (Object)null)
			{
				killInfoNumLabel.text = UIPopMessageDirector.mInstance.mPopMessageList[0];
				UIPopMessageDirector.mInstance.mPopMessageList.RemoveAt(0);
				UIPopMessageDirector.mInstance.mPopMessageTypeList.RemoveAt(0);
			}
			break;
		}
	}
}
