		UISinglePlayerDirector.OnReadArchive += OnReadArchive;
	}

	private void OnDisable()
	{
		UISinglePlayerDirector.OnChapterChoice -= OnChapterChoice;
		UISinglePlayerDirector.OnDifficultySelect -= OnDifficultySelect;
		UISinglePlayerDirector.OnReadArchive -= OnReadArchive;
	}

	private void Start()
	{
	}

	private void Update()
	{
	}

	private void OnChapterChoice(UISinglePlayerDirector.ChapterIndex index)
	{
		Debug.Log((object)("OnChapterChoice" + (int)index));
	}

	private void OnDifficultySelect(UISinglePlayerDirector.DifficultyLevel level)
	{
		PlayerPrefs.SetInt("SingleModeChapterOneBulletAndBloodPakStoreShow", 0);
		PlayerPrefs.SetInt("SingleModeChapterOneDifficulty", (int)(level + 1));
		PlayerPrefs.SetInt("SingleModeChapterOneBloodPakNum", 0);
		PlayerPrefs.SetInt("SingleModeChapterOneBulletPakNum", 0);
		PlayerPrefs.SetInt("SingleModeChapterOneCurrentPoint", 0);
		PlayerPrefs.SetInt("SingleModeRespawnLimit", 5);
		Application.LoadLevel("SingleMode_1");
	}

	private void OnReadArchive()
	{
		PlayerPrefs.SetInt("SingleModeChapterOneSavedApply", 0);
		PlayerPrefs.SetInt("SingleModeChapterOneDifficulty", PlayerPrefs.GetInt("SingleModeChapterOneDifficultySaved", 1));
		PlayerPrefs.SetInt("SingleModeChapterOneBloodPakNum", PlayerPrefs.GetInt("SingleModeChapterOneBloodPakNumSaved", 0));
		PlayerPrefs.SetInt("SingleModeChapterOneBulletPakNum", PlayerPrefs.GetInt("SingleModeChapterOneBulletPakNumSaved", 0));
		PlayerPrefs.SetInt("SingleModeChapterOneCurrentPoint", PlayerPrefs.GetInt("SingleModeChapterOneCurrentPointSaved", 0));
		PlayerPrefs.SetInt("SingleModeRespawnLimit", PlayerPrefs.GetInt("SingleModeRespawnLimitSaved", 5));
		Application.LoadLevel(PlayerPrefs.GetString("SingleModeChapterOneBarrierLvSaved", "SingleMode_1"));
	}
}
