public class UISingleGameSceneDirector : MonoBehaviour
{
	public delegate void SaveNQuitEventHandler();

	public delegate void YesToRespawnEventHandler();

	public delegate void NoToRespawnEventHandler();

	public static UISingleGameSceneDirector mInstance;

	public GameObject equipPanel;

	public GameObject toolBarPanel;

	public GameObject controlPanel;

	public GameObject shopPanel;

	public GameObject gameOverPanel;

	public GameObject diedPanel;

	public UIImageButton shopAddCoinBtn;

	public UIImageButton shopAddGemBtn;

	public UIImageButton equipAddCoinBtn;

	public GameObject gemsPage;

	public GameObject coinPage;

	private int medikitNum;

	private int clipNum;

	public UILabel medikitNumLabel;

	public UILabel clipNumLabel;

	public UILabel medikitLeftNumLabel;

	public UILabel clipLeftNumLabel;

	public UILabel medikitLimitNumLabel;

	public UILabel clipLimitNumLabel;

	public UILabel medikitPriceLabel;

	public UILabel clipPriceLabel;

	public GameObject titleLabel;

	public GameObject coinLackLabel;

	public UILabel storyLabel;

	public UIImageButton closeShopBtn;

	public UIImageButton equipcloseShopBtn;

	public UIImageButton diedCloseShopBtn;

	public GameObject haveRespawnTimes;

	public GameObject noRespawnTimes;

	public UILabel respawnTimesLabel;

	public UILabel respawnCostLabel;

	public UILabel gameOverTitleLabel;

	public UILabel gameOverPointLabel;

	public UILabel gameOverCoinLabel;

	public UILabel gameOverExpLabel;

	public UILabel gameOverScoreLabel;

	private int shopType = 1;

	public UILabel storyTipLabel;

	public static event SaveNQuitEventHandler OnSaveNQuit;

	public static event YesToRespawnEventHandler OnYesToRespawn;

	public static event NoToRespawnEventHandler OnNoToRespawn;

	public void GenSaveNQuitEvent()
	{
		if (UISingleGameSceneDirector.OnSaveNQuit != null)
		{
			UISingleGameSceneDirector.OnSaveNQuit();
		}
	}

	public void GenYesToRespawnEvent()
	{
		if (UISingleGameSceneDirector.OnYesToRespawn != null)
		{
			UISingleGameSceneDirector.OnYesToRespawn();
		}
	}

	public void GenNoToRespawnEvent()
	{
		if (UISingleGameSceneDirector.OnNoToRespawn != null)
		{
			UISingleGameSceneDirector.OnNoToRespawn();
		}
	}

	private void Awake()
	{
		mInstance = this;
	}

	private void OnDestroy()
	{
		if ((Object)(object)mInstance == (Object)(object)this)
		{
			mInstance = null;
		}
	}

	private void Start()
	{
		if (PlayerPrefs.GetInt("SingleModeChapterOneBulletAndBloodPakStoreShow", 0) == 1)
		{
			equipPanel.SetActive(false);
			toolBarPanel.SetActive(true);
			controlPanel.GetComponent<UIPanel>().alpha = 1f;
		}
		else
		{
			equipPanel.SetActive(true);
			toolBarPanel.SetActive(false);
			controlPanel.GetComponent<UIPanel>().alpha = 0f;
			clipLimitNumLabel.text = SingleModeSupplyManager.mInstance.BulletPakNumBuyLimit.ToString();
			medikitLimitNumLabel.text = SingleModeSupplyManager.mInstance.BloodPakNumBuyLimit.ToString();
			medikitLeftNumLabel.text = (SingleModeSupplyManager.mInstance.BloodPakNumBuyLimit - SingleModeSupplyManager.mInstance.BloodPakNumBuyed).ToString();
			clipLeftNumLabel.text = (SingleModeSupplyManager.mInstance.BulletPakNumBuyLimit - SingleModeSupplyManager.mInstance.BulletPakNumBuyed).ToString();
			medikitPriceLabel.text = "x " + SingleModeSupplyManager.mInstance.BloodPakPrices[SingleModeSupplyManager.mInstance.BloodPakNumBuyed];
			clipPriceLabel.text = "x " + SingleModeSupplyManager.mInstance.BulletPakPrices[SingleModeSupplyManager.mInstance.BulletPakNumBuyed];
		}
		storyLabel.text = SingleModeSupplyManager.mInstance.story;
	}

	private void Update()
	{
	}

	public void MediKitEquipBtnPressed()
	{
		if (SingleModeSupplyManager.mInstance.BloodPakNumBuyLimit - SingleModeSupplyManager.mInstance.BloodPakNumBuyed > 0 && GrowthManagerKit.GetCoins() >= SingleModeSupplyManager.mInstance.BloodPakPrices[SingleModeSupplyManager.mInstance.BloodPakNumBuyed])
		{
			medikitPriceLabel.text = "x " + SingleModeSupplyManager.mInstance.BloodPakPrices[SingleModeSupplyManager.mInstance.BloodPakNumBuyed];
			SingleModeSupplyManager.mInstance.BloodPakBuy();
			medikitLeftNumLabel.text = (SingleModeSupplyManager.mInstance.BloodPakNumBuyLimit - SingleModeSupplyManager.mInstance.BloodPakNumBuyed).ToString();
			medikitNum++;
			medikitNumLabel.text = "x " + medikitNum;
		}
	}

	public void ClipEquipBtnPressed()
	{
		if (SingleModeSupplyManager.mInstance.BulletPakNumBuyLimit - SingleModeSupplyManager.mInstance.BulletPakNumBuyed > 0 && GrowthManagerKit.GetCoins() >= SingleModeSupplyManager.mInstance.BulletPakPrices[SingleModeSupplyManager.mInstance.BulletPakNumBuyed])
		{
			clipPriceLabel.text = "x " + SingleModeSupplyManager.mInstance.BulletPakPrices[SingleModeSupplyManager.mInstance.BulletPakNumBuyed];
			SingleModeSupplyManager.mInstance.BulletPakBuy();
			clipLeftNumLabel.text = (SingleModeSupplyManager.mInstance.BulletPakNumBuyLimit - SingleModeSupplyManager.mInstance.BulletPakNumBuyed).ToString();
			clipNum++;
			clipNumLabel.text = "x " + clipNum;
		}
	}

	private IEnumerator TwinkleLabel(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		titleLabel.SetActive(true);
		coinLackLabel.SetActive(false);
	}

	public void EquipToStartBtnPressed()
	{
		equipPanel.SetActive(false);
		toolBarPanel.SetActive(true);
		controlPanel.GetComponent<UIPanel>().alpha = 1f;
	}

	public void AddCoinBtnPressed()
	{
		Debug.Log((object)"AddCoinBtnPressed");
		shopType = 1;
		shopPanel.SetActive(true);
		toolBarPanel.SetActive(false);
		controlPanel.SetActive(false);
		gemsPage.SetActive(false);
		coinPage.SetActive(true);
		((Component)shopAddCoinBtn).gameObject.SetActive(true);
		((Component)shopAddGemBtn).gameObject.SetActive(true);
		shopAddCoinBtn.isEnabled = false;
		shopAddGemBtn.isEnabled = true;
	}

	public void AddGemBtnPressed()
	{
		Debug.Log((object)"AddGemBtnPressed");
		shopType = 1;
		shopPanel.SetActive(true);
		toolBarPanel.SetActive(false);
		controlPanel.SetActive(false);
		gemsPage.SetActive(true);
		coinPage.SetActive(false);
		((Component)shopAddCoinBtn).gameObject.SetActive(true);
		((Component)shopAddGemBtn).gameObject.SetActive(true);
		shopAddCoinBtn.isEnabled = true;
		shopAddGemBtn.isEnabled = false;
	}

	public void CloseShopBtnPressed()
	{
		if (shopType == 1)
		{
			Debug.Log((object)"shopType == 1");
			shopPanel.SetActive(false);
			toolBarPanel.SetActive(true);
			controlPanel.SetActive(true);
		}
		else if (shopType == 2)
		{
			Debug.Log((object)"shopType == 2");
			shopPanel.SetActive(false);
			equipPanel.SetActive(true);
		}
		else if (shopType == 3)
		{
			Debug.Log((object)"shopType == 3");
			shopPanel.SetActive(false);
			diedPanel.SetActive(true);
			toolBarPanel.SetActive(true);
			controlPanel.SetActive(true);
			ShowDiedPanel();
		}
	}

	public void EquipAddCoinBtnPressed()
	{
		Debug.Log((object)"EquipAddCoinBtnPressed");
		shopType = 2;
		shopPanel.SetActive(true);
		equipPanel.SetActive(false);
		gemsPage.SetActive(false);
		coinPage.SetActive(true);
		((Component)shopAddCoinBtn).gameObject.SetActive(false);
		((Component)shopAddGemBtn).gameObject.SetActive(false);
	}

	public void EquipCloseShopBtnPressed()
	{
		shopPanel.SetActive(false);
		equipPanel.SetActive(true);
	}

	public void SaveNQuitBtnPressed()
	{
		GenSaveNQuitEvent();
		Application.LoadLevel("LoadingToMenu");
	}

	public void UseMediKitBtnPressed()
	{
		SingleModeSupplyManager.mInstance.BloodPakUse();
	}

	public void UseClipBtnPressed()
	{
		SingleModeSupplyManager.mInstance.BulletPakUse();
	}

	public void ShowDiedPanel()
	{
		diedPanel.SetActive(true);
		if (PlayerPrefs.GetInt("SingleModeRespawnLimit", 0) > 0)
		{
			haveRespawnTimes.SetActive(true);
			noRespawnTimes.SetActive(false);
			respawnTimesLabel.text = PlayerPrefs.GetInt("SingleModeRespawnLimit", 0).ToString();
			respawnCostLabel.text = SingleModeRespawnControl.mInstance.RespawnPrice[5 - PlayerPrefs.GetInt("SingleModeRespawnLimit", 5)].ToString();
		}
		else
		{
			haveRespawnTimes.SetActive(false);
			noRespawnTimes.SetActive(true);
		}
	}

	public void YesToRespawnBtnPressed()
	{
		if (GrowthManagerKit.GetGems() < SingleModeRespawnControl.mInstance.RespawnPrice[5 - PlayerPrefs.GetInt("SingleModeRespawnLimit", 5)])
		{
			shopType = 3;
			shopPanel.SetActive(true);
			diedPanel.SetActive(false);
			toolBarPanel.SetActive(false);
			controlPanel.SetActive(false);
			gemsPage.SetActive(true);
			coinPage.SetActive(false);
			((Component)shopAddCoinBtn).gameObject.SetActive(false);
			((Component)shopAddGemBtn).gameObject.SetActive(false);
		}
		else
		{
			GenYesToRespawnEvent();
			diedPanel.SetActive(false);
		}
		Debug.Log((object)"YesToRespawnBtnPressed");
	}

	public void DieCloseShopBtnPressed()
	{
		shopPanel.SetActive(true);
		diedPanel.SetActive(false);
		toolBarPanel.SetActive(true);
		controlPanel.SetActive(true);
	}

	public void NoToRespawnBtnPressed()
	{
		GenNoToRespawnEvent();
		Debug.Log((object)"NOToRespawnBtnPressed");
		ShowGameOverPanel(bTemp: false);
	}

	public void ShowGameOverPanel(bool bTemp)
	{
		Debug.Log((object)"ShowGameOverPanel");
		diedPanel.SetActive(false);
		gameOverPanel.SetActive(true);
		if (bTemp)
		{
			gameOverTitleLabel.text = "Victory!";
		}
		else
		{
			gameOverTitleLabel.text = "Game Over";
		}
		gameOverPointLabel.text = SingleModeRespawnControl.mInstance.singleModePointGet.ToString();
		gameOverCoinLabel.text = SingleModeRespawnControl.mInstance.singleModeCoinGet.ToString();
		gameOverExpLabel.text = SingleModeRespawnControl.mInstance.singleModeExpGet.ToString();
		gameOverScoreLabel.text = SingleModeRespawnControl.mInstance.singleModeScoreGet.ToString();
	}
}
