public class UISinglePlayerDirector : MonoBehaviour
{
	public enum ChapterIndex
	{
		Chapter1,
		Chapter2,
		Chapter3
	}

	public enum DifficultyLevel
	{
		Easy,
		Normal,
		Hard
	}

	public delegate void ReadArchiveEventHandler();

	public delegate void ChapterChoiceEventHandler(ChapterIndex index);

	public delegate void DifficultySelectEventHandler(DifficultyLevel level);

	private const int chapterTotalNum = 3;

	public static UISinglePlayerDirector mInstance;

	public GameObject singlePlayerPanel;

	public GameObject chapterChoicePanel;

	public GameObject difficultySelectPanel;

	public GameObject loadingPanel;

	public UILabel loadingLabel;

	public UIImageButton readArchiveBtn;

	public GameObject chapterBgTexture;

	public Texture2D[] chapterBgTextrueArray = (Texture2D[])(object)new Texture2D[3];

	public UIImageButton chapterBtn2;

	public UIImageButton chapterBtn3;

	public UIImageButton easyBtn;

	public UIImageButton normalBtn;

	public UIImageButton hardBtn;

	public UILabel highScoreLabel;

	public UILabel scoresLabel;

	public UILabel giftBoxNumLabel;

	public UIImageButton exchangeBtn;

	public static event ReadArchiveEventHandler OnReadArchive;

	public static event ChapterChoiceEventHandler OnChapterChoice;

	public static event DifficultySelectEventHandler OnDifficultySelect;

	public void GenReadArchiveEvent()
	{
		if (UISinglePlayerDirector.OnReadArchive != null)
		{
			UISinglePlayerDirector.OnReadArchive();
		}
	}

	public void GenChapterChoiceEvent(ChapterIndex index)
	{
		if (UISinglePlayerDirector.OnChapterChoice != null)
		{
			UISinglePlayerDirector.OnChapterChoice(index);
		}
	}

	public void GenDifficultySelectEvent(DifficultyLevel level)
	{
		if (UISinglePlayerDirector.OnDifficultySelect != null)
		{
			UISinglePlayerDirector.OnDifficultySelect(level);
		}
	}

	private void Awake()
	{
		mInstance = this;
	}

	private void OnDestroy()
	{
		if ((Object)(object)mInstance == (Object)(object)this)
		{
			mInstance = null;
		}
	}

	private void Start()
	{
		chapterBtn2.isEnabled = false;
		chapterBtn3.isEnabled = false;
		highScoreLabel.text = PlayerPrefs.GetInt("SingleModeChapterOneHighScore", 0).ToString();
		scoresLabel.text = PlayerPrefs.GetInt("SingleModeChapterOneTotalPoint", 0).ToString();
		giftBoxNumLabel.text = GrowthManagerKit.GetCurGiftBoxTotal().ToString();
		if (PlayerPrefs.GetInt("SingleModeChapterOneTotalPoint", 0) < 300)
		{
			exchangeBtn.isEnabled = false;
		}
		if (PlayerPrefs.GetInt("SingleModeChapterOneSavedApply", 0) == 0)
		{
			readArchiveBtn.isEnabled = false;
		}
		if (PlayerPrefs.GetInt("SingleModePassNormal", 0) == 0)
		{
			if (PlayerPrefs.GetInt("SingleModePassEasy", 0) == 0)
			{
				normalBtn.isEnabled = false;
				hardBtn.isEnabled = false;
			}
			else
			{
				hardBtn.isEnabled = false;
			}
		}
	}

	private void Update()
	{
	}

	public void ReadArchiveBtnPressed()
	{
		singlePlayerPanel.SetActive(false);
		loadingPanel.SetActive(true);
		loadingLabel.text = "Reading...";
		GenReadArchiveEvent();
	}

	public void NewGameBtnPressed()
	{
		singlePlayerPanel.SetActive(false);
		chapterChoicePanel.SetActive(true);
	}

	public void MainMenuBtnPressed()
	{
		Application.LoadLevel("LoadingToMenu");
	}

	public void ChapterChoiceBtnPressed(ChapterIndex index)
	{
		chapterChoicePanel.SetActive(false);
		difficultySelectPanel.SetActive(true);
		((Component)chapterBgTexture.transform).GetComponent<UITexture>().mainTexture = (Texture)(object)chapterBgTextrueArray[(int)index];
		GenChapterChoiceEvent(index);
	}

	public void DifficultySelectBtnPressed(DifficultyLevel level)
	{
		difficultySelectPanel.SetActive(false);
		loadingPanel.SetActive(true);
		GenDifficultySelectEvent(level);
	}

	public void BackToSingleBtnPressed()
	{
		singlePlayerPanel.SetActive(true);
		chapterChoicePanel.SetActive(false);
	}

	public void BackToChapterBtnPressed()
	{
		difficultySelectPanel.SetActive(false);
		chapterChoicePanel.SetActive(true);
	}

	public void ExchangeGiftBoxBtnPressed()
	{
		PlayerPrefs.SetInt("SingleModeChapterOneTotalPoint", PlayerPrefs.GetInt("SingleModeChapterOneTotalPoint", 0) - 300);
		GrowthManagerKit.AddGiftBox(1);
		scoresLabel.text = PlayerPrefs.GetInt("SingleModeChapterOneTotalPoint", 0).ToString();
		giftBoxNumLabel.text = GrowthManagerKit.GetCurGiftBoxTotal().ToString();
		if (PlayerPrefs.GetInt("SingleModeChapterOneTotalPoint", 0) < 300)
		{
			exchangeBtn.isEnabled = false;
		}
	}
}
