			UIStoreDirector.mInstance.UpgradeBtnPressed(((Component)((Component)this).gameObject.transform.parent).GetComponent<UIStoreWeaponPrefab>().gItemInfo, ((Component)((Component)this).gameObject.transform.parent).GetComponent<UIStoreWeaponPrefab>().upgradeGItemInfo, ((Component)((Component)this).gameObject.transform.parent).GetComponent<UIStoreWeaponPrefab>().weaponName, ((Component)this).gameObject.transform.parent);
