	private void GetWeaponData()
	{
		//IL_00e4: Unknown result type (might be due to invalid IL or missing references)
		//IL_00f4: Unknown result type (might be due to invalid IL or missing references)
		//IL_0126: Unknown result type (might be due to invalid IL or missing references)
		//IL_0141: Unknown result type (might be due to invalid IL or missing references)
		//IL_015c: Unknown result type (might be due to invalid IL or missing references)
		weaponNameList = GrowthManagerKit.GetAllWeaponNameList();
		if (weaponNameList.Length > 0)
		{
			gItemInfo = new GItemInfo[weaponNameList.Length];
			upgradeGItemInfo = new GItemInfo[weaponNameList.Length];
			for (int i = 0; i < weaponNameList.Length; i++)
			{
				gItemInfo[i] = GrowthManagerKit.GetItemInfoByName(weaponNameList[i]);
				upgradeGItemInfo[i] = GrowthManagerKit.GetUpgradeItemInfoByName(weaponNameList[i]);
			}
		}
		if (gItemInfo.Length % 2 == 0)
		{
			((Component)weaponObjParent).GetComponent<UITable>().columns = gItemInfo.Length / 2;
		}
		else
		{
			((Component)weaponObjParent).GetComponent<UITable>().columns = gItemInfo.Length / 2 + 1;
		}
		for (int j = 0; j < gItemInfo.Length; j++)
		{
			Object obj = Object.Instantiate((Object)(object)weaponPrefab, weaponPrefab.transform.position, weaponPrefab.transform.rotation);
			GameObject val = (GameObject)(object)((obj is GameObject) ? obj : null);
			val.transform.parent = weaponObjParent;
			val.transform.localScale = weaponPrefab.transform.localScale;
			val.transform.position = weaponPrefab.transform.position;
			val.transform.rotation = weaponPrefab.transform.rotation;
			if (gItemInfo[j] != null)
			{
				val.GetComponent<UIStoreWeaponPrefab>().weaponName = weaponNameList[j];
				val.GetComponent<UIStoreWeaponPrefab>().gItemInfo = gItemInfo[j];
				val.GetComponent<UIStoreWeaponPrefab>().upgradeGItemInfo = upgradeGItemInfo[j];
			}
			else
			{
				Debug.Log((object)"gItemInfo[i] is null");
			}
		}
		((Component)weaponObjParent).GetComponent<UITable>().Reposition();
	}

	private void GetSkinData()
	{
		curSkinInfo = GrowthManagerKit.GetCurSettedSkinInfo();
		skinNameList = GrowthManagerKit.GetAllSkinNameList();
		if (skinNameList.Length <= 0)
		{
			return;
		}
		gSkinItemInfo = new GSkinItemInfo[skinNameList.Length];
		for (int i = 0; i < skinNameList.Length; i++)
		{
			gSkinItemInfo[i] = GrowthManagerKit.GetSkinItemInfoByName(skinNameList[i]);
			if (gSkinItemInfo[i].mNameDisplay == curSkinInfo.mNameDisplay)
			{
				curSkinId = i;
				skinUsingId = i;
			}
		}
	}

	private void SetSkinData()
	{
		setMaterial(curSkinId);
		skinDisNameLabel.text = gSkinItemInfo[curSkinId].mNameDisplay;
		skinPriceLabel.text = gSkinItemInfo[curSkinId].mPrice.ToString();
		if (gSkinItemInfo[curSkinId].mPurchasedType == GItemPurchaseType.CoinsPurchase)
		{
			skinPriceCoin.spriteName = "Coin";
			skinPriceCoin.MarkAsChanged();
		}
		else if (gSkinItemInfo[curSkinId].mPurchasedType == GItemPurchaseType.GemPurchase)
		{
			skinPriceCoin.spriteName = "Gem";
			skinPriceCoin.MarkAsChanged();
		}
		if (!gSkinItemInfo[curSkinId].mIsEnabled)
		{
			((Component)skinLockSprite.transform).GetComponent<UISprite>().alpha = 1f;
			skinSetUnlockLabel.text = "Unlock";
		}
		else
		{
			((Component)skinLockSprite.transform).GetComponent<UISprite>().alpha = 0f;
			skinSetUnlockLabel.text = "Set";
		}
		if (curSkinId == skinUsingId)
		{
			((Component)((Component)setUnlockBtn).transform).GetComponent<UIImageButton>().isEnabled = false;
			skinSetUnlockLabel.text = "Equipped";
		}
		else
		{
			((Component)((Component)setUnlockBtn).transform).GetComponent<UIImageButton>().isEnabled = true;
		}
	}

	private void ScrollViewReposition()
	{
	}

	private void ChangeMaterial(Material hatMat, Material bodyMat)
	{
		((Component)body1.transform).renderer.material = bodyMat;
		((Component)body2.transform).renderer.material = bodyMat;
		((Component)body3.transform).renderer.material = bodyMat;
		((Component)body4.transform).renderer.material = bodyMat;
		((Component)body5.transform).renderer.material = bodyMat;
		((Component)body6.transform).renderer.material = bodyMat;
	}

	private void setMaterial(int iTemp)
	{
		ChangeMaterial(hatSkin[iTemp], bodySkin[iTemp]);
	}
}
