public class UIStoreFrontSprite : MonoBehaviour
{
	public UISprite Sprite_AK_1;

	public UISprite Sprite_AK_2;

	public UISprite Sprite_AK_3;

	public UISprite Sprite_M4_1;

	public UISprite Sprite_M4_2;

	public UISprite Sprite_M4_3;

	public UISprite Sprite_Deagle_1;

	public UISprite Sprite_Deagle_2;

	public UISprite Sprite_Deagle_3;

	public UISprite Sprite_Rifle_1;

	public UISprite Sprite_Rifle_2;

	public UISprite Sprite_Rifle_3;

	private UserDataKit.Weapon_Type wType;

	private void OnEnable()
	{
		UIMenuDirector.OnUpgrade += OnUpgrade;
		UIMenuDirector.OnCancel += OnCancel;
		UIMenuDirector.OnVerifyOK += OnVerifyOK;
		UIMenuDirector.OnTipsOK += OnTipsOK;
	}

	private void OnDisable()
	{
		UIMenuDirector.OnUpgrade -= OnUpgrade;
		UIMenuDirector.OnCancel -= OnCancel;
		UIMenuDirector.OnVerifyOK -= OnVerifyOK;
		UIMenuDirector.OnTipsOK -= OnTipsOK;
	}

	private void Start()
	{
		UpdateShow();
	}

	private void Update()
	{
	}

	private void OnUpgrade(UserDataKit.Weapon_Type mtag)
	{
		Debug.Log((object)"OnUpgrade");
		wType = mtag;
	}

	private void OnVerifyOK()
	{
		if (UserDataKit.GetWeaponLevel(wType) == 1)
		{
			switch (wType)
			{
			case UserDataKit.Weapon_Type.AK:
				UserDataKit.SubCoins(2000);
				break;
			case UserDataKit.Weapon_Type.Deagle:
				UserDataKit.SubCoins(500);
				break;
			case UserDataKit.Weapon_Type.M4:
				UserDataKit.SubCoins(1500);
				break;
			case UserDataKit.Weapon_Type.Rifle:
				UserDataKit.SubCoins(1000);
				break;
			}
			UserDataKit.SetWeaponLevel(wType, 2);
		}
		else if (UserDataKit.GetWeaponLevel(wType) == 2)
		{
			switch (wType)
