public class UIStoreWeaponPrefab : MonoBehaviour
{
	public enum WPType
	{
		Nil,
		WPType_WeaponPrefab,
		WPType_WeaponPrefabUpgrade
	}

	public GItemInfo gItemInfo;

	public GItemInfo upgradeGItemInfo;

	public string weaponName;

	public GameObject saleOffLabel;

	public GameObject nameLabel;

	public GameObject priceLabel;

	public GameObject logoSprite;

	public GameObject levelSprite;

	public GameObject powerSprite;

	public GameObject clipsSprite;

	public GameObject rateSprite;

	public GameObject lockSprite;

	public GameObject upgradeBtn;

	public GameObject coinSprite;

	public WPType wpType;

	private void Start()
	{
		if (wpType == WPType.WPType_WeaponPrefab)
		{
			((Component)this).gameObject.GetComponent<UIDragCamera>().draggableCamera = GameObject.Find("View Camera").GetComponent<UIDraggableCamera>();
			readData(gItemInfo);
		}
		else if (wpType != WPType.WPType_WeaponPrefabUpgrade)
		{
		}
	}

	private void Update()
	{
	}

	public void readData(GItemInfo info)
	{
