		//IL_0104: Unknown result type (might be due to invalid IL or missing references)
		if ((Object)(object)coinSprite != (Object)null && info.mPurchasedType != GItemPurchaseType.CoinsPurchase && info.mPurchasedType == GItemPurchaseType.GemPurchase)
		{
			coinSprite.GetComponent<UISprite>().spriteName = "Gem";
			coinSprite.GetComponent<UISprite>().MarkAsChanged();
		}
		if (!info.mCanUpgrade)
		{
			if ((Object)(object)upgradeBtn != (Object)null)
			{
				upgradeBtn.SetActive(false);
			}
			if ((Object)(object)priceLabel != (Object)null)
			{
				priceLabel.SetActive(false);
			}
			if ((Object)(object)saleOffLabel != (Object)null)
			{
				saleOffLabel.SetActive(false);
			}
			if ((Object)(object)coinSprite != (Object)null)
			{
				coinSprite.SetActive(false);
			}
		}
		if (info.mIsEnabled)
		{
			if ((Object)(object)lockSprite != (Object)null)
			{
				lockSprite.SetActive(false);
				nameLabel.GetComponent<UILabel>().color = Color.white;
			}
		}
		else
		{
			if ((Object)(object)lockSprite != (Object)null)
			{
				lockSprite.SetActive(true);
				nameLabel.GetComponent<UILabel>().color = Color.gray;
			}
			if ((Object)(object)upgradeBtn != (Object)null)
			{
				((Component)upgradeBtn.transform).GetComponentInChildren<UILabel>().text = "Unlock";
			}
		}
		if ((Object)(object)nameLabel != (Object)null)
		{
			nameLabel.GetComponent<UILabel>().text = info.mNameDisplay;
		}
		if ((Object)(object)priceLabel != (Object)null)
		{
			priceLabel.GetComponent<UILabel>().text = info.mPrice.ToString();
		}
		if ((Object)(object)saleOffLabel != (Object)null)
		{
			saleOffLabel.GetComponent<UILabel>().text = info.offRateDescription;
		}
		if ((Object)(object)logoSprite != (Object)null)
		{
			logoSprite.GetComponent<UISprite>().spriteName = info.mLogoSpriteName;
			logoSprite.GetComponent<UISprite>().MarkAsChanged();
		}
		if ((Object)(object)levelSprite != (Object)null)
		{
			levelSprite.GetComponent<UISprite>().spriteName = info.mWeaponLevelSpriteName;
			levelSprite.GetComponent<UISprite>().MarkAsChanged();
		}
		if ((Object)(object)powerSprite != (Object)null)
		{
			powerSprite.GetComponent<UISprite>().spriteName = info.mPowerSpriteName;
			powerSprite.GetComponent<UISprite>().MarkAsChanged();
		}
		if ((Object)(object)clipsSprite != (Object)null)
		{
			clipsSprite.GetComponent<UISprite>().spriteName = info.mClipSpriteName;
			clipsSprite.GetComponent<UISprite>().MarkAsChanged();
		}
		if ((Object)(object)rateSprite != (Object)null)
		{
			rateSprite.GetComponent<UISprite>().spriteName = info.mFireRateSpriteName;
			rateSprite.GetComponent<UISprite>().MarkAsChanged();
		}
	}
