public class UserDataKit : MonoBehaviour
{
	public enum Weapon_Type
	{
		Nil,
		Deagle,
		AK,
		M4,
		Rifle
	}

	public static void SetMyNickName(string name)
	{
		PlayerPrefs.SetString("LocalMultiplayerNickName", name);
	}

	public static string GetMyNickName()
	{
		return PlayerPrefs.GetString("LocalMultiplayerNickName", "New Player");
	}

	public static void SetMyRoomName(string name)
	{
		PlayerPrefs.SetString("MultiplayerRoomName", name);
	}

	public static string GetMyRoomName()
	{
		return PlayerPrefs.GetString("MultiplayerRoomName", string.Empty);
	}

	public static int GetCoins()
	{
		return PlayerPrefs.GetInt("GameCoins", 0);
	}

	public static void SetCoins(int coins)
	{
		PlayerPrefs.SetInt("GameCoins", coins);
	}

	public static void AddCoins(int coins)
	{
		PlayerPrefs.SetInt("GameCoins", coins + GetCoins());
	}

	public static bool SubCoins(int coins)
	{
		int coins2 = GetCoins();
		if (coins2 >= coins)
		{
			PlayerPrefs.SetInt("GameCoins", coins2 - coins);
			return true;
		}
		return false;
	}

	public static void SetWeaponLevel(Weapon_Type type, int iTemp)
	{
		switch (type)
		{
		case Weapon_Type.AK:
			PlayerPrefs.SetInt("AK", iTemp);
			break;
		case Weapon_Type.Deagle:
			PlayerPrefs.SetInt("Deagle", iTemp);
			break;
		case Weapon_Type.M4:
			PlayerPrefs.SetInt("M4", iTemp);
			break;
		case Weapon_Type.Rifle:
			PlayerPrefs.SetInt("Rifle", iTemp);
			break;
		}
	}

	public static int GetWeaponLevel(Weapon_Type type)
	{
		return type switch
		{
			Weapon_Type.AK => PlayerPrefs.GetInt("AK", 1), 
			Weapon_Type.Deagle => PlayerPrefs.GetInt("Deagle", 1), 
			Weapon_Type.M4 => PlayerPrefs.GetInt("M4", 1), 
			Weapon_Type.Rifle => PlayerPrefs.GetInt("Rifle", 1), 
			_ => 1, 
		};
	}

	private void Start()
	{
	}

	private void Update()
	{
	}
}
