	{
		hand = ((Component)((Component)this).transform.Find("Capsule/handother/handright/hand")).gameObject;
		sword = ((Component)((Component)this).transform.Find("Capsule/handother/handright/sword")).gameObject;
		bow = ((Component)((Component)this).transform.Find("Capsule/handother/handright/bow")).gameObject;
		club = ((Component)((Component)this).transform.Find("Capsule/handother/handright/club")).gameObject;
		ladder = ((Component)((Component)this).transform.Find("Capsule/handother/handright/ladder")).gameObject;
		valve = ((Component)((Component)this).transform.Find("Capsule/handother/handright/valve")).gameObject;
		if (((Component)this).gameObject.tag.Equals("Cop"))
		{
			sword.SetActive(true);
			hand.SetActive(false);
			bow.SetActive(false);
			club.SetActive(false);
			ladder.SetActive(false);
			valve.SetActive(false);
			tempWeaponName = "sword";
		}
		if (((Component)this).gameObject.tag.Equals("Robber"))
		{
			hand.SetActive(true);
			sword.SetActive(false);
			bow.SetActive(false);
			club.SetActive(false);
			ladder.SetActive(false);
			valve.SetActive(false);
			tempWeaponName = "hand";
		}
	}

	private void Update()
	{
		if (weaponSelectName != tempWeaponName)
		{
			tempWeaponName = weaponSelectName;
			switch (tempWeaponName)
			{
			case "hand":
				hand.SetActive(true);
				sword.SetActive(false);
				bow.SetActive(false);
				club.SetActive(false);
				ladder.SetActive(false);
				valve.SetActive(false);
				break;
			case "sword":
				hand.SetActive(false);
				sword.SetActive(true);
				bow.SetActive(false);
				club.SetActive(false);
				ladder.SetActive(false);
				valve.SetActive(false);
				break;
			case "bow":
				hand.SetActive(false);
				sword.SetActive(false);
				bow.SetActive(true);
				club.SetActive(false);
				ladder.SetActive(false);
				valve.SetActive(false);
				break;
			case "club":
				hand.SetActive(false);
				sword.SetActive(false);
				bow.SetActive(false);
				club.SetActive(true);
				ladder.SetActive(false);
				valve.SetActive(false);
				break;
			case "ladder":
				hand.SetActive(false);
				sword.SetActive(false);
				bow.SetActive(false);
				club.SetActive(false);
				ladder.SetActive(true);
				valve.SetActive(false);
