public class CRWeaponManager : MonoBehaviour
{
	public List<CRWeaponScript> allWeapons = new List<CRWeaponScript>();

	private float SwitchTime = 0.5f;

	public CRWeaponScript SelectedWeapon;

	public int index;

	public AudioClip takeInAudio;

	private GameObject defaultPrimaryWeap;

	private GameObject defaultSecondaryWeap;

	private bool canSwitch;

	private Camera cam;

	private RaycastHit hit;

	private GameObject UIRoot;

	private bool playerDieFlag;

	private string iconName = string.Empty;

	private CRSTProp m_Props;

	private void Awake()
	{
		m_Props = default(CRSTProp);
		for (int i = 0; i < ((Component)this).transform.childCount; i++)
		{
			((Component)((Component)this).transform.GetChild(i)).gameObject.SetActive(false);
		}
		for (int j = 0; j < allWeapons.Count; j++)
		{
			((Component)allWeapons[j]).gameObject.SetActive(false);
		}
		TakeFirstWeapon(((Component)allWeapons[index]).gameObject);
		UIRoot = GameObject.Find("UIRoot");
	}

	private void Update()
	{
		if ((double)Time.timeScale < 0.01)
		{
			return;
		}
		SelectedWeapon = allWeapons[index];
		for (int i = 0; i < 6; i++)
		{
			CRPlayer.mInstance.m_STProps[i].PropSelected = false;
			if (SelectedWeapon.weaponName == CRPlayer.mInstance.m_STProps[i].PropIconName && SelectedWeapon.weaponName != "hand")
			{
				CRPlayer.mInstance.m_STProps[i].PropSelected = true;
			}
		}
		if (allWeapons.Count < 2 || !canSwitch || playerDieFlag || !CRInput.mInstance.m_bSwitch)
		{
			return;
		}
		CRInput.mInstance.m_bSwitch = false;
		iconName = CRInput.mInstance.m_PropIconName;
		for (int j = 0; j < allWeapons.Count; j++)
		{
			if (allWeapons[j].weaponName.Equals(iconName))
			{
				if (j != index)
				{
					SwitchWeapons(((Component)allWeapons[index]).gameObject, ((Component)allWeapons[j]).gameObject);
				}
				index = j;
			}
		}
	}

	private void TakeFirstWeapon(GameObject nextWeapon)
	{
		((Component)this).audio.clip = takeInAudio;
		((Component)this).audio.Play();
		nextWeapon.SetActive(true);
		nextWeapon.SendMessage("selectWeapon");
		canSwitch = true;
	}

	public void SwitchWeapons(GameObject currentWeapon, GameObject nextWeapon)
	{
		canSwitch = false;
		if (currentWeapon.active)
		{
			currentWeapon.SendMessage("deselectWeapon");
		}
		((Component)this).audio.clip = takeInAudio;
		((Component)this).audio.Play();
		currentWeapon.SetActive(false);
		nextWeapon.SetActive(true);
		nextWeapon.SendMessage("selectWeapon");
		canSwitch = true;
	}

	private void PlayerDie()
	{
		playerDieFlag = true;
	}

	private void PlayerRebirth()
	{
		playerDieFlag = false;
	}
}
