		attackAnimation = ((Component)((Component)this).transform.Find("handother1/handright1")).GetComponent<Animation>();
		attackAnimation.Play("Idle_1");
		camDefaultRotation = mainCamera.transform.localRotation;
		defaultFov = mainCamera.camera.fieldOfView;
		defaultPosition = ((Component)this).transform.localPosition;
		arrowLabel = GameObject.Find("arrowAmount").GetComponent<UILabel>();
		((Behaviour)arrowLabel).enabled = false;
		if (WeaponType == weaponType.SWORD)
		{
			swordAwake();
		}
		if (WeaponType == weaponType.BOW)
		{
			bowAwake();
		}
		if (WeaponType == weaponType.CLUB)
		{
			clubAwake();
		}
		if (WeaponType == weaponType.HAND)
		{
			handAwake();
		}
		if (WeaponType == weaponType.LADDER)
		{
			ladderAwake();
		}
		if (WeaponType == weaponType.VALVE)
		{
			valveAwake();
		}
	}

	private void Update()
	{
		if (!((double)Time.timeScale < 0.01))
		{
			Aiming();
			RotationRealism();
			SmoothMove();
			if (Recoil)
			{
			}
			if (WeaponType == weaponType.BOW)
			{
				bowFixedUpdate();
				((Behaviour)arrowLabel).enabled = true;
				arrowLabel.text = bow.ammoCount + " | 100";
			}
			else
			{
				((Behaviour)arrowLabel).enabled = false;
			}
		}
	}

	private void LateUpdate()
	{
		if (!((double)Time.timeScale < 0.01) && CRInput.mInstance.m_bFire && !playerDieFlag)
		{
			if (WeaponType == weaponType.SWORD && canFire && !isReload)
			{
				swordOneShot();
			}
			if (WeaponType == weaponType.BOW && canFire && !isReload)
			{
				bowFIre();
			}
			if (WeaponType == weaponType.CLUB && canFire && !isReload)
			{
				clubOneShot();
			}
			if (WeaponType == weaponType.HAND && canFire && !isReload)
			{
				handOneShot();
			}
			if (WeaponType == weaponType.LADDER && canFire && !isReload)
			{
				ladderOneShot();
			}
			if (WeaponType == weaponType.VALVE && canFire && !isReload)
			{
				valveOneShot();
			}
			CRInput.mInstance.m_bFire = false;
		}
	}

