		UIMenuDirector.OnGamePaused += OnGamePaused;
		UIMenuDirector.OnGamePlay += OnGamePlay;
		UIMenuDirector.OnGameRestart += OnGameRestart;
		UIMenuDirector.OnGameResume += OnGameResume;
		UIMenuDirector.OnCRRestart += OnCRRestart;
		UIMenuDirector.OnRespawn += OnRespawn;
		UIMenuDirector.OnSendMsg += OnSendMsg;
	}

	private void OnDisable()
	{
		UIMenuDirector.OnGameOver -= OnGameOver;
		UIMenuDirector.OnGamePaused -= OnGamePaused;
		UIMenuDirector.OnGamePlay -= OnGamePlay;
		UIMenuDirector.OnGameRestart -= OnGameRestart;
		UIMenuDirector.OnGameResume -= OnGameResume;
		UIMenuDirector.OnCRRestart -= OnCRRestart;
		UIMenuDirector.OnRespawn -= OnRespawn;
		UIMenuDirector.OnSendMsg -= OnSendMsg;
	}

	private void OnGameOver()
	{
		m_Gamestate = CRGameState.GameOver;
	}

	private void OnGamePaused()
	{
		m_Gamestate = CRGameState.GamePause;
	}

	private void OnGamePlay()
	{
		m_Gamestate = CRGameState.InGame;
	}

	private void OnGameRestart()
	{
		m_Gamestate = CRGameState.InGame;
	}

	private void OnGameResume()
	{
		m_Gamestate = CRGameState.InGame;
	}

	private void OnCRRestart()
	{
		CRMultiplayerManager.mInstance.isRestartNewRound = true;
		Application.LoadLevel(Application.loadedLevel);
	}

	private void OnRespawn()
	{
		//IL_000f: Unknown result type (might be due to invalid IL or missing references)
		((Component)CRPlayer.mInstance).transform.position = CRSpwan.mInstance.GetSpawnRobberPosition();
		CRPlayer.mInstance.setBlood(100);
		CRPlayer.mInstance.setLiftState(CRLifeState.Live);
		CRExampleSkin.mInstance.characterChoose = false;
		Debug.Log((object)("OnRespawn, lifestate: " + CRPlayer.mInstance.getLifeState()));
	}

	private void OnSendMsg(string sendmsg)
	{
		CRMultiplayerManager.mInstance.BroadcastMessageOnline(CRMultiplayerManager.mInstance.GetMyNickName() + " : " + sendmsg);
	}

	private void playWinAudio()
	{
		((Component)this).audio.clip = m_WinAudio;
		((Component)this).audio.Play();
	}

	private void playLoseAudio()
	{
		((Component)this).audio.clip = m_LoseAudio;
		((Component)this).audio.Play();
	}

	private void Update()
	{
		//IL_0026: Unknown result type (might be due to invalid IL or missing references)
		//IL_007b: Unknown result type (might be due to invalid IL or missing references)
		//IL_00bf: Unknown result type (might be due to invalid IL or missing references)
		if (!bDisplayEdoor && CRMultiplayerManager.mInstance.mEDoorOpenOrClose == 0)
		{
			goEntranceDoor.transform.position = entranceDoorPosition;
			bDisplayEdoor = true;
		}
		if (!bColliderDoor && CRMultiplayerManager.mInstance.mEDoorOpenOrClose == 1)
		{
			if (CRPlayer.mInstance.m_Playertype == CRPlayerType.PlayerCop)
			{
				Debug.Log((object)"mEDoorOpenOrClose: 1, cop");
				CRMultiplayerManager.mInstance.myPlayerObj.transform.position = m_InitCopPosition;
				bColliderDoor = true;
			}
			else if (CRPlayer.mInstance.m_Playertype == CRPlayerType.PlayerRobber)
			{
				Debug.Log((object)"mEDoorOpenOrClose: 1, robber");
				CRMultiplayerManager.mInstance.myPlayerObj.transform.position = CRSpwan.mInstance.GetSpawnRobberPosition();
				bColliderDoor = true;
			}
		}
		if (m_Gamestate == CRGameState.InGame)
		{
			switch (CRMultiplayerManager.mInstance.mWinOrLose)
			{
			case 0:
				Debug.Log((object)"0: you win");
				CRMultiplayerManager.mInstance.StopSynAction();
				UIMenuDirectorExt.mInstance.CRGameOverEvent(0);
				m_Gamestate = CRGameState.GameOver;
				playWinAudio();
				break;
			case 1:
				Debug.Log((object)"1: you lose");
				CRMultiplayerManager.mInstance.StopSynAction();
				UIMenuDirectorExt.mInstance.CRGameOverEvent(1);
				m_Gamestate = CRGameState.GameOver;
				playLoseAudio();
				break;
			}
		}
	}
}
