	private void Init()
	{
		mPlayerInfo = ((Component)this).gameObject.GetComponent<CRPlayerInfo>();
		m_Lifestate = CRLifeState.Live;
		m_Playertype = CRPlayerType.PlayerRobber;
		m_STProps = new CRSTProp[6];
		m_Propslist = new List<CRSTProp>();
		InitProp();
		InitBlood();
