	private void Start()
	{
	}

	private CRActionStatus getActionStatus()
	{
		playerActionState actionState = ((Component)this).GetComponent<CRJoyStickController>().actionState;
		CRActionStatus result = CRActionStatus.Idle;
		switch (actionState)
		{
		case playerActionState.idle:
			result = CRActionStatus.Idle;
			break;
		case playerActionState.walk:
			result = CRActionStatus.Walk;
			break;
		case playerActionState.idleattack:
			result = CRActionStatus.IdleAttack;
			if (m_Playertype != CRPlayerType.PlayerCop)
			{
			}
			break;
		case playerActionState.walkattack:
			result = CRActionStatus.WalkAttack;
			if (m_Playertype != CRPlayerType.PlayerCop)
			{
			}
			break;
		case playerActionState.jump:
			result = CRActionStatus.Jump;
			break;
		case playerActionState.onladder:
			result = CRActionStatus.Onladder;
			break;
		}
		return result;
	}

	private CRHandheldStatus getWeaponType()
	{
		goweaponmanager = ((Component)((Component)this).transform.Find("LookObject/Main Camera/Weapon Camera/WeaponManager")).gameObject;
		string weaponName = goweaponmanager.GetComponent<CRWeaponManager>().SelectedWeapon.weaponName;
		CRHandheldStatus cRHandheldStatus = CRHandheldStatus.Hand;
		return weaponName switch
		{
			"hand" => CRHandheldStatus.Hand, 
			"sword" => CRHandheldStatus.Sword, 
			"bow" => CRHandheldStatus.Bow, 
			"club" => CRHandheldStatus.Club, 
			"ladder" => CRHandheldStatus.Ladder, 
			"valve" => CRHandheldStatus.Valve, 
			_ => CRHandheldStatus.Hand, 
		};
	}

	private void WirteToPlayerInfo()
	{
		//IL_0062: Unknown result type (might be due to invalid IL or missing references)
		//IL_0067: Unknown result type (might be due to invalid IL or missing references)
		//IL_0078: Unknown result type (might be due to invalid IL or missing references)
		//IL_007d: Unknown result type (might be due to invalid IL or missing references)
		mPlayerInfo.mHp = m_Blood;
		mPlayerInfo.mWeaponType = getWeaponType();
		if (m_Lifestate == CRLifeState.Live)
		{
			mPlayerInfo.mStatus = CRSurvivalStatus.Alive;
		}
		else if (m_Lifestate == CRLifeState.Died)
		{
			mPlayerInfo.mStatus = CRSurvivalStatus.Dead;
		}
		mPlayerInfo.mPosition = ((Component)this).transform.position;
		mPlayerInfo.mBodyRotation = ((Component)this).transform.rotation;
		if (mPlayerInfo.mTeam == CRTeamType.Cop)
		{
			m_Playertype = CRPlayerType.PlayerCop;
		}
		else if (mPlayerInfo.mTeam == CRTeamType.Robber)
		{
			m_Playertype = CRPlayerType.PlayerRobber;
		}
		mPlayerInfo.mActionStatus = getActionStatus();
	}

	private void Update()
	{
		//IL_0258: Unknown result type (might be due to invalid IL or missing references)
		if (CRGame.mInstance.m_Gamestate != CRGameState.InGame)
		{
			return;
		}
		if (m_Lifestate == CRLifeState.Live)
		{
			for (int i = 0; i < m_STProps.Length; i++)
			{
				if (m_STProps[i].PropNum > 0)
				{
					bool flag = false;
					for (int j = 0; j < m_Propslist.Count; j++)
					{
						if (m_Propslist[j].PropIconName == m_STProps[i].PropIconName)
						{
							m_Propslist[j] = m_STProps[i];
							flag = true;
							break;
						}
					}
					if (!flag && m_STProps[i].PropIconName != "hand")
					{
						m_Propslist.Add(m_STProps[i]);
					}
					continue;
				}
				int count = m_Propslist.Count;
				for (int k = 0; k < count; k++)
				{
					if (m_STProps[i].PropIconName == m_Propslist[k].PropIconName)
					{
						m_Propslist.RemoveAt(k);
						break;
					}
				}
			}
		}
		if (m_Playertype == CRPlayerType.PlayerCop)
		{
			if (m_Lifestate == CRLifeState.Live)
			{
				if (m_Blood <= 0)
				{
					m_Lifestate = CRLifeState.Died;
				}
				if (Time.frameCount % 30 == 0)
				{
					m_Blood += 5;
					if (m_Blood >= 100)
					{
						m_Blood = 100;
					}
				}
			}
		}
		else if (m_Playertype == CRPlayerType.PlayerRobber && m_Lifestate == CRLifeState.Live)
		{
			if (m_Blood <= 0)
			{
				m_Lifestate = CRLifeState.Died;
			}
			if (Time.frameCount % 10 == 0)
			{
				m_Blood++;
				if (m_Blood >= 100)
				{
					m_Blood = 100;
				}
			}
		}
		if (m_Lifestate == CRLifeState.Died)
		{
			if (m_Playertype == CRPlayerType.PlayerRobber)
			{
				UIMenuDirectorExt.mInstance.CRGameOverEvent(2);
				((Component)this).transform.position = GameObject.Find("SpawnPosition/PositionDead").transform.position;
				m_Lifestate = CRLifeState.Null;
				((Component)this).audio.clip = RobberCopDieVoice;
				((Component)this).audio.Play();
				CRMultiplayerManager.mInstance.BroadcastMessageOnline(CRMultiplayerManager.mInstance.GetMyNickName() + " was killed!");
			}
			else if (m_Playertype == CRPlayerType.PlayerCop)
			{
				CRMultiplayerManager.mInstance.SetRobberWinOrLoseState(bwinorlose: true);
				CRMultiplayerManager.mInstance.mWinOrLose = 1;
				m_Lifestate = CRLifeState.Null;
				((Component)this).audio.clip = RobberCopDieVoice;
				((Component)this).audio.Play();
			}
		}
		else
		{
			WirteToPlayerInfo();
		}
		if (CRMultiplayerManager.mInstance.mGameRoundTimeRest < 0.01f)
		{
			if (m_Playertype == CRPlayerType.PlayerCop)
			{
				CRMultiplayerManager.mInstance.mWinOrLose = 0;
			}
			else if (m_Playertype == CRPlayerType.PlayerRobber)
			{
				CRMultiplayerManager.mInstance.mWinOrLose = 1;
			}
		}
	}

