		setWeaponType();
		if (PlayerInfo.mStatus == CRSurvivalStatus.Alive)
		{
			m_Lifestate = CRLifeState.Live;
		}
		else if (PlayerInfo.mStatus == CRSurvivalStatus.Dead)
		{
			m_Lifestate = CRLifeState.Died;
			audioEnemyDie.Play();
		}
		((Component)this).transform.position = PlayerInfo.mPosition;
		((Component)this).transform.rotation = PlayerInfo.mBodyRotation;
		setActionStatus();
	}

