	{
		switch (PlayerInfo.mActionStatus)
		{
		case CRActionStatus.Idle:
			m_MillorPlayerAnimationCtrl.actionState = playerActionState.idle;
			break;
		case CRActionStatus.Walk:
			m_MillorPlayerAnimationCtrl.actionState = playerActionState.walk;
			break;
		case CRActionStatus.IdleAttack:
			m_MillorPlayerAnimationCtrl.actionState = playerActionState.idleattack;
			break;
		case CRActionStatus.WalkAttack:
			m_MillorPlayerAnimationCtrl.actionState = playerActionState.walkattack;
			break;
		case CRActionStatus.Jump:
			m_MillorPlayerAnimationCtrl.actionState = playerActionState.jump;
			break;
		case CRActionStatus.Onladder:
			m_MillorPlayerAnimationCtrl.actionState = playerActionState.onladder;
			break;
		}
	}

	private void setWeaponType()
	{
		switch (PlayerInfo.mWeaponType)
		{
		case CRHandheldStatus.Hand:
			m_MillorPlayerWeaponSelect.weaponSelectName = "hand";
			break;
		case CRHandheldStatus.Sword:
			m_MillorPlayerWeaponSelect.weaponSelectName = "sword";
			break;
		case CRHandheldStatus.Bow:
			m_MillorPlayerWeaponSelect.weaponSelectName = "bow";
