		case CRHandheldStatus.Club:
			m_MillorPlayerWeaponSelect.weaponSelectName = "club";
			break;
		case CRHandheldStatus.Ladder:
			m_MillorPlayerWeaponSelect.weaponSelectName = "ladder";
			break;
		case CRHandheldStatus.Valve:
			m_MillorPlayerWeaponSelect.weaponSelectName = "valve";
			break;
		}
	}
