	}

	private void OnJump()
	{
		CRInput.mInstance.m_bJump = true;
	}

	private IEnumerator waitForSetJump(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		CRInput.mInstance.m_bJump = false;
	}

	private void OnRightTap()
	{
		CRInput.mInstance.m_bUse = true;
	}

	private IEnumerator waitForSetRightTap(float seconds)
	{
		yield return (object)new WaitForSeconds(seconds);
		CRInput.mInstance.m_bUse = false;
	}

