	public void SetDoorValveState()
	{
		if (m_Doorvalvestate == CRDoorValveState.DoorValveUp)
		{
			m_Doorvalvestate = CRDoorValveState.DoorValveDown;
			for (int i = 0; i < CRGame.mInstance.goDoors.Length; i++)
			{
				if (CRGame.mInstance.goDoors[i].GetComponent<CRDoor>().m_DoorID == m_DoorID)
				{
					CRGame.mInstance.goDoors[i].GetComponent<CRDoor>().DoorOpen();
				}
			}
		}
		else if (m_Doorvalvestate == CRDoorValveState.DoorValveDown)
		{
			m_Doorvalvestate = CRDoorValveState.DoorValveUp;
			for (int j = 0; j < CRGame.mInstance.goDoors.Length; j++)
			{
				if (CRGame.mInstance.goDoors[j].GetComponent<CRDoor>().m_DoorID == m_DoorID)
				{
					CRGame.mInstance.goDoors[j].GetComponent<CRDoor>().DoorClose();
				}
			}
		}
		UpdateValveState();
	}

	private void UpdateValveState()
	{
		//IL_0013: Unknown result type (might be due to invalid IL or missing references)
		//IL_0034: Unknown result type (might be due to invalid IL or missing references)
		if (m_Doorvalvestate == CRDoorValveState.DoorValveUp)
		{
			((Component)this).transform.rotation = m_UpRotation;
		}
		else if (m_Doorvalvestate == CRDoorValveState.DoorValveDown)
		{
			((Component)this).transform.rotation = m_DownRotation;
		}
	}
}
