public class CRLobbyButtonEvent : MonoBehaviour
{
	public enum ButtonName
	{
		Nil,
		CopSelectButton,
		RobberSelectButton,
		StartButton,
		RefreshButton,
		WWStartButton,
		WWCopSelectButton,
		WWRobberSelectButton
	}

	public ButtonName mButtonName;

	private void OnClick()
	{
		if (!((Behaviour)this).enabled)
		{
			return;
		}
		switch (mButtonName)
		{
		case ButtonName.CopSelectButton:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus != CRConnectStatus.WaitForOtherPlayers)
			{
				CRMultiplayerManager.mInstance.myPlayerInfo.mTeam = CRTeamType.Cop;
				CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = CRConnectStatus.Ready;
			}
			break;
		case ButtonName.RobberSelectButton:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus != CRConnectStatus.WaitForOtherPlayers)
			{
				CRMultiplayerManager.mInstance.myPlayerInfo.mTeam = CRTeamType.Robber;
				CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = CRConnectStatus.Ready;
			}
			break;
		case ButtonName.StartButton:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.ConnectedToServer)
			{
				if (Random.Range(1, 3) == 1)
				{
					CRMultiplayerManager.mInstance.myPlayerInfo.mTeam = CRTeamType.Cop;
				}
				else
				{
					CRMultiplayerManager.mInstance.myPlayerInfo.mTeam = CRTeamType.Robber;
				}
				CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = CRConnectStatus.WaitForOtherPlayers;
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.Ready)
			{
				CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = CRConnectStatus.WaitForOtherPlayers;
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.WaitForOtherPlayers)
			{
				CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = CRConnectStatus.Ready;
			}
			break;
		case ButtonName.RefreshButton:
			CRMultiplayerManager.mInstance.Refresh();
			break;
		case ButtonName.WWStartButton:
			CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus = CRConnectStatus.WaitForOtherPlayers;
			break;
		case ButtonName.WWCopSelectButton:
			CRMultiplayerManager.mInstance.myPlayerInfo.mTeam = CRTeamType.Cop;
			break;
		case ButtonName.WWRobberSelectButton:
			CRMultiplayerManager.mInstance.myPlayerInfo.mTeam = CRTeamType.Robber;
			break;
		}
	}

	private void Start()
	{
	}

	private void Update()
	{
	}
}
public class CRLobbyDataReader : MonoBehaviour
{
	public enum DataName
	{
		Nil,
		ServerConnectedNum,
		CopSelectButton,
		RobberSelectButton,
		StartButton,
		MyStatusLabel,
		PlayerList,
		GameRoundTimeRest,
		PlayerListInGame,
		WWServerConnectedNum,
		WWStartButton,
		WWPlayerList,
		IsServer
	}

	public DataName mData;

	private UILabel[] mPlayersStatus = new UILabel[20];

	private void Start()
	{
		if (mData == DataName.PlayerList || mData == DataName.PlayerListInGame)
		{
			for (int i = 0; i < mPlayersStatus.Length; i++)
			{
				mPlayersStatus[i] = ((Component)((Component)this).transform.FindChild("PlayerStatusLabel_" + (i + 1))).GetComponent<UILabel>();
			}
		}
	}

	private void Update()
	{
		switch (mData)
		{
		case DataName.ServerConnectedNum:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Local Server - WiFi (" + (GameKitManager.connectedPeers.Count + 1) + "/16)";
			break;
		case DataName.CopSelectButton:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mTeam == CRTeamType.Cop)
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNullS_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNullS_2";
			}
			else
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNull_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNull_2";
			}
			((Component)this).gameObject.GetComponentInChildren<UISprite>().MarkAsChanged();
			break;
		case DataName.RobberSelectButton:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mTeam == CRTeamType.Robber)
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNullS_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNullS_2";
			}
			else
			{
				((Component)this).gameObject.GetComponent<UIImageButton>().normalSprite = "ButtonNull_2";
				((Component)this).gameObject.GetComponentInChildren<UISprite>().spriteName = "ButtonNull_2";
			}
			((Component)this).gameObject.GetComponentInChildren<UISprite>().MarkAsChanged();
			break;
		case DataName.StartButton:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.ConnectedToServer)
			{
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Quick Start";
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.Ready)
			{
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Start";
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.WaitForOtherPlayers)
			{
				((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Cancel";
			}
			break;
		case DataName.MyStatusLabel:
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.ConnectedToServer)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = "Status: In Role Select...";
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.Ready)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = "Status: Ready...";
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mConnnectStatus == CRConnectStatus.WaitForOtherPlayers)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = "Status: Wait For Other Players...";
			}
			else
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = string.Empty;
			}
			break;
		case DataName.PlayerList:
		{
			for (int m = 0; m < CRMultiplayerManager.mInstance.otherPlayersInfoList.Length; m++)
			{
				CRConnectStatus mConnnectStatus3 = CRMultiplayerManager.mInstance.otherPlayersInfoList[m].mConnnectStatus;
				string text = CRMultiplayerManager.mInstance.otherPlayersInfoList[m].mTeam.ToString();
				switch (mConnnectStatus3)
				{
				case CRConnectStatus.Nil:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": NA";
					break;
				case CRConnectStatus.ConnectedToServer:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Connected";
					break;
				case CRConnectStatus.Ready:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Select-" + text;
					break;
				case CRConnectStatus.WaitForOtherPlayers:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Ready-" + text;
					break;
				case CRConnectStatus.InGame:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": InGame-" + text;
					break;
				case CRConnectStatus.EndGame:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": EndGame";
					break;
				case CRConnectStatus.DisconnectedToServer:
					((Behaviour)mPlayersStatus[m]).enabled = true;
					mPlayersStatus[m].text = "Player_" + (m + 1) + ": Disconnected";
					break;
				}
			}
			break;
		}
		case DataName.GameRoundTimeRest:
			((Component)this).gameObject.GetComponent<UILabel>().text = "Time - " + (int)CRMultiplayerManager.mInstance.mGameRoundTimeRest / 60 + " : " + (int)CRMultiplayerManager.mInstance.mGameRoundTimeRest % 60;
			break;
		case DataName.PlayerListInGame:
		{
			int num3 = 0;
			int num4 = 10;
			for (int k = 0; k < mPlayersStatus.Length; k++)
			{
				mPlayersStatus[k].text = string.Empty;
			}
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mTeam == CRTeamType.Cop)
			{
				mPlayersStatus[num3].text = CRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num3++;
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mTeam == CRTeamType.Robber)
			{
				mPlayersStatus[num4].text = CRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num4++;
			}
			for (int l = 0; l < CRMultiplayerManager.mInstance.otherPlayersInfoList.Length; l++)
			{
				CRConnectStatus mConnnectStatus2 = CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mConnnectStatus;
				CRTeamType mTeam2 = CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mTeam;
				if (mConnnectStatus2 != CRConnectStatus.Nil && mConnnectStatus2 == CRConnectStatus.InGame)
				{
					switch (mTeam2)
					{
					case CRTeamType.Cop:
						mPlayersStatus[num3].text = CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mNickName + " : Kill-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mDeadNum;
						num3++;
						break;
					case CRTeamType.Robber:
						mPlayersStatus[num4].text = CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mNickName + " : Kill-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[l].mDeadNum;
						num4++;
						break;
					}
				}
			}
			break;
		}
		case DataName.WWServerConnectedNum:
			if (PhotonNetwork.room != null)
			{
				((Component)this).gameObject.GetComponent<UILabel>().text = PhotonNetwork.room.name + " (" + PhotonNetwork.room.playerCount.ToString() + "/" + PhotonNetwork.room.maxPlayers + ")";
			}
			break;
		case DataName.WWStartButton:
			((Component)this).gameObject.GetComponentInChildren<UILabel>().text = "Go";
			break;
		case DataName.WWPlayerList:
		{
			int num = 0;
			int num2 = 10;
			for (int i = 0; i < mPlayersStatus.Length; i++)
			{
				mPlayersStatus[i].text = string.Empty;
			}
			if (CRMultiplayerManager.mInstance.myPlayerInfo.mTeam == CRTeamType.Cop)
			{
				mPlayersStatus[num].text = CRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num++;
			}
			else if (CRMultiplayerManager.mInstance.myPlayerInfo.mTeam == CRTeamType.Robber)
			{
				mPlayersStatus[num2].text = CRMultiplayerManager.mInstance.myPlayerInfo.mNickName + " : Kill-" + CRMultiplayerManager.mInstance.myPlayerInfo.mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.myPlayerInfo.mDeadNum;
				num2++;
			}
			for (int j = 0; j < CRMultiplayerManager.mInstance.otherPlayersInfoList.Length; j++)
			{
				CRConnectStatus mConnnectStatus = CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mConnnectStatus;
				CRTeamType mTeam = CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mTeam;
				if (mConnnectStatus != CRConnectStatus.Nil && mConnnectStatus == CRConnectStatus.InGame)
				{
					switch (mTeam)
					{
					case CRTeamType.Cop:
						mPlayersStatus[num].text = CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mNickName + " : Kill-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mDeadNum;
						num++;
						break;
					case CRTeamType.Robber:
						mPlayersStatus[num2].text = CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mNickName + " : Kill-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mKillNum + " | Dead-" + CRMultiplayerManager.mInstance.otherPlayersInfoList[j].mDeadNum;
						num2++;
						break;
					}
				}
			}
			break;
		}
		case DataName.IsServer:
			((Component)this).gameObject.GetComponent<UILabel>().text = CRMultiplayerManager.mInstance.myPlayerInfo.mServerOrClient.ToString();
			break;
		}
	}
}
public enum CRMultiMode
{
	LocalWiFi,
	PhotonCloudOnline
}
public class CRMultiplayerManager : MonoBehaviour
{
	private const int CR_TIME_OUT_COUNT = 300;

	public static CRMultiplayerManager mInstance;

	public string mVersion = "1.0";

	public static int CR_MAX_PLAYER_NUM = 20;

	public CRPlayerInfo myPlayerInfo = new CRPlayerInfo();

	public CRPlayerInfo[] otherPlayersInfoList = new CRPlayerInfo[CR_MAX_PLAYER_NUM];

	public GameObject copPrefab;

	public GameObject robberPrefab;

	private GameObject[] otherPlayerObject = (GameObject[])(object)new GameObject[CR_MAX_PLAYER_NUM];

	private float mGameRoundTimeStart;

	public float mGameRoundTimeRest = CR_MAX_GAME_ROUND_TIME;

	public static float CR_MAX_GAME_ROUND_TIME = 900f;

	private int[] otherPlayerTimeOutCount = new int[CR_MAX_PLAYER_NUM];

	private bool keepSendingFlag;

	public GameObject mLobbyPanel;

	public List<string> mMessageList = new List<string>();

	public GameObject myPlayerObj;

	public CRGameInfo myGameInfo;

	public string serverPeerId = "null";

	public CRMultiMode multiplayerMode;

	public List<long> mExistPlayerList = new List<long>();

	private Vector3 mInstructionRoomPosition = Vector3.zero;

	private Vector3 mInitCopPosition = Vector3.zero;

	private List<string> tmpPlayerList = new List<string>();

	public bool mAutoSelectServer = true;

	public int mWinOrLose = 255;

	public int mEDoorOpenOrClose = 255;

	public bool isRestartNewRound;

	public void Awake()
	{
		mInstance = this;
		Init();
	}

	private void Init()
	{
		//IL_0050: Unknown result type (might be due to invalid IL or missing references)
		//IL_0055: Unknown result type (might be due to invalid IL or missing references)
		//IL_006a: Unknown result type (might be due to invalid IL or missing references)
		//IL_006f: Unknown result type (might be due to invalid IL or missing references)
		serverPeerId = "null";
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			otherPlayersInfoList[i] = new CRPlayerInfo();
			otherPlayerObject[i] = null;
			otherPlayerTimeOutCount[i] = 0;
		}
		mInstructionRoomPosition = GameObject.Find("SpawnPosition/InstructionRoomPosition").transform.position;
		mInitCopPosition = GameObject.Find("SpawnPosition/PositionCop").transform.position;
		mAutoSelectServer = true;
		mEDoorOpenOrClose = 255;
		mWinOrLose = 255;
	}

	public void Start()
	{
		GameKitManager.peerConnected += onPeerConnected;
		GameKitManager.peerDisconnected += onPeerDisconnect;
		GameKitManager.peerPickerCancelled += onPeerPickerCanceled;
		GameKitManager.peerBecameAvailable += peerBecameAvailable;
		GameKitManager.peerBecameUnavailable += peerBecameUnavailable;
		GameKitManager.receivedConnectionRequestFromPeer += receivedConnectionRequestFromPeer;
		GameKitManager.peerConnectedForVoiceChat += onPeerConnectedForVoiceChat;
		GameKitManager.peerDisconnectedFromVoiceChat += onPeerDisconnectedFromVoiceChat;
		Refresh();
		CRSynEvent.OnValveEnable += OnValveEnableProcess;
		CRSynEvent.OnValveKnock += OnValveKnockProcess;
		CRSynEvent.OnLadderEnable += OnLadderEnableProcess;
		CRSynEvent.OnPropBoxOpen += OnPropBoxOpenProcess;
		CRSynEvent.OnPropCreate += OnPropCreateProcess;
		CRSynEvent.OnPropDestroy += OnPropDestroyRequest;
	}

	public void OnDisable()
	{
		GameKitManager.peerConnected -= onPeerConnected;
		GameKitManager.peerDisconnected -= onPeerDisconnect;
		GameKitManager.peerPickerCancelled -= onPeerPickerCanceled;
		GameKitManager.peerBecameAvailable -= peerBecameAvailable;
		GameKitManager.peerBecameUnavailable -= peerBecameUnavailable;
		GameKitManager.receivedConnectionRequestFromPeer -= receivedConnectionRequestFromPeer;
		GameKitManager.peerConnectedForVoiceChat -= onPeerConnectedForVoiceChat;
		GameKitManager.peerDisconnectedFromVoiceChat -= onPeerDisconnectedFromVoiceChat;
		mInstance = null;
		if (multiplayerMode == CRMultiMode.LocalWiFi && GameKitManager.isConnected() && !isRestartNewRound)
		{
			GameKitBinding.invalidateSession();
		}
		((MonoBehaviour)this).StopAllCoroutines();
		CRSynEvent.OnValveEnable -= OnValveEnableProcess;
		CRSynEvent.OnValveKnock -= OnValveKnockProcess;
		CRSynEvent.OnLadderEnable -= OnLadderEnableProcess;
		CRSynEvent.OnPropBoxOpen -= OnPropBoxOpenProcess;
		CRSynEvent.OnPropCreate -= OnPropCreateProcess;
		CRSynEvent.OnPropDestroy -= OnPropDestroyRequest;
	}

	private void OnValveEnableProcess(CRValveID vId)
	{
		if (myPlayerInfo.mServerOrClient == CRServerOrClient.Client)
		{
			string[] peerIds = new string[1] { serverPeerId };
			if (serverPeerId != "null")
			{
				string name = ((Object)((Component)this).gameObject).name;
				int num = (int)vId;
				sendMessageToPeersAdapt(peerIds, name, "OnValveEnableProcessStr", num.ToString() + '@' + myPlayerInfo.mId, reliably: false);
			}
			return;
		}
		foreach (CRValve dynamicValf in myGameInfo.dynamicValves)
		{
			if (dynamicValf.m_ValveID == vId)
			{
				dynamicValf.isVisible = true;
				break;
			}
		}
	}

	private void OnValveEnableProcessStr(string param)
	{
		string[] array = param.Split('@');
		OnValveEnableProcess((CRValveID)int.Parse(array[0]));
	}

	private void OnValveKnockProcess(CRValveID vId)
	{
		if (myPlayerInfo.mServerOrClient == CRServerOrClient.Client)
		{
			Debug.Log((object)"begin OnValveKnockProcess client");
			string[] peerIds = new string[1] { serverPeerId };
			if (serverPeerId != "null")
			{
				Debug.Log((object)("serverPeerId: " + serverPeerId + "myPlayerInfo: " + myPlayerInfo));
				string name = ((Object)((Component)this).gameObject).name;
				int num = (int)vId;
				sendMessageToPeersAdapt(peerIds, name, "OnValveKnockProcessStr", num.ToString() + '@' + myPlayerInfo.mId, reliably: false);
				Debug.Log((object)"end OnValveKnockProcess client");
			}
			return;
		}
		foreach (CRValve staticValf in myGameInfo.staticValves)
		{
			if (staticValf.m_ValveID == vId)
			{
				staticValf.SetDoorValveState();
				return;
			}
		}
		foreach (CRValve dynamicValf in myGameInfo.dynamicValves)
		{
			if (dynamicValf.m_ValveID == vId)
			{
				dynamicValf.SetDoorValveState();
				break;
			}
		}
	}

