	public void onPeerConnected(string peerId)
	{
		Debug.Log((object)("PeerConnected event fired with peerId: " + peerId));
		AddPlayer(peerId);
		if (!keepSendingFlag)
		{
			keepSendingFlag = true;
			((MonoBehaviour)this).StartCoroutine(SendMyPlayerInfoToPeer());
		}
	}

	public void onPeerDisconnect(string peerId)
	{
		Debug.Log((object)("PeerDisconnected event fired with peerId: " + peerId));
		RemovePlayer(peerId);
		if (!GameKitManager.isConnected())
		{
			((MonoBehaviour)this).StopAllCoroutines();
			keepSendingFlag = false;
			ServerDisconnet(peerId);
		}
	}

	public void ServerDisconnet(string peerId)
	{
		Debug.Log((object)"ServerDisconnet begin");
		if (serverPeerId == peerId)
		{
			Debug.Log((object)"ServerDisconnet end");
			if (CRGame.mInstance.m_Gamestate == CRGameState.InGame)
			{
				mInstance.SetRobberWinOrLoseState(bwinorlose: true);
				mInstance.SetCopWinOrLoseState(bwinorlose: false);
			}
		}
