	public IEnumerator SendMyPlayerInfoToPeer()
	{
		while (GameKitManager.isConnected())
		{
			GameKitBinding.sendData("CRMultiplayerManager", "OtherPlayersInfoToLocation", myPlayerInfo.ParsePlayerInfoToString(), reliably: false);
			if (myPlayerInfo.mServerOrClient == CRServerOrClient.Server)
			{
				GameKitBinding.sendData("CRMultiplayerManager", "ServerGameInfoToLocation", myGameInfo.ParseGameInfoToString(), reliably: false);
			}
			yield return (object)new WaitForSeconds(0.01f);
		}
	}

