	public void AddPlayer(string peerId)
	{
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId == "null")
			{
				otherPlayersInfoList[i] = new CRPlayerInfo(peerId);
				mMessageList.Add("New Player(id-" + peerId + ") Connected!");
				break;
			}
		}
	}

	public void RemovePlayer(string peerId)
	{
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId == peerId)
			{
				mMessageList.Add(otherPlayersInfoList[i].mNickName + " Disconnected!");
				mMessageList.Add(otherPlayersInfoList[i].mNickName + " Leave Game!");
				otherPlayersInfoList[i] = new CRPlayerInfo();
				break;
			}
		}
	}

	public void Refresh()
	{
		GameKitBinding.invalidateSession();
		GameKitBinding.setSessionMode(GameKitSessionMode.Peer);
		GameKitBinding.setAutoConnectPeers(shouldAutoConnect: true);
		if (Application.loadedLevelName == "FreeRun3")
		{
			GameKitBinding.initializeSessionForOnlineOnly("13141001003", GameKitBinding.getPeerId());
		}
		else if (Application.loadedLevelName == "FreeRun4")
		{
			GameKitBinding.initializeSessionForOnlineOnly("13141001004", GameKitBinding.getPeerId());
		}
		else
		{
			GameKitBinding.initializeSessionForOnlineOnly("13141001099", GameKitBinding.getPeerId());
		}
		InitMyPlayerInfo();
		keepSendingFlag = false;
	}

