	public void UpdateOtherPlayersObject()
	{
		//IL_0144: Unknown result type (might be due to invalid IL or missing references)
		//IL_0151: Unknown result type (might be due to invalid IL or missing references)
		//IL_018e: Unknown result type (might be due to invalid IL or missing references)
		//IL_019b: Unknown result type (might be due to invalid IL or missing references)
		if (myPlayerInfo.mConnnectStatus != CRConnectStatus.InGame)
		{
			return;
		}
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if ((Object)(object)otherPlayerObject[i] != (Object)null && otherPlayersInfoList[i].mId != "null" && !((Object)otherPlayerObject[i]).name.Contains(otherPlayersInfoList[i].mTeam.ToString()))
			{
				Object.Destroy((Object)(object)otherPlayerObject[i]);
				otherPlayerObject[i] = null;
				break;
			}
			if ((Object)(object)otherPlayerObject[i] != (Object)null && otherPlayersInfoList[i].mId != "null")
			{
				otherPlayerObject[i].GetComponent<CRPlayerInfo>().UpdateMySelf(otherPlayersInfoList[i]);
			}
			if (otherPlayersInfoList[i].mId != "null" && (Object)(object)otherPlayerObject[i] == (Object)null && otherPlayersInfoList[i].mConnnectStatus == CRConnectStatus.InGame)
			{
				if (otherPlayersInfoList[i].mTeam == CRTeamType.Cop)
				{
					ref GameObject reference = ref otherPlayerObject[i];
					Object obj = Object.Instantiate((Object)(object)copPrefab, otherPlayersInfoList[i].mPosition, otherPlayersInfoList[i].mBodyRotation);
					reference = (GameObject)(object)((obj is GameObject) ? obj : null);
				}
				else if (otherPlayersInfoList[i].mTeam == CRTeamType.Robber)
				{
					ref GameObject reference2 = ref otherPlayerObject[i];
					Object obj2 = Object.Instantiate((Object)(object)robberPrefab, otherPlayersInfoList[i].mPosition, otherPlayersInfoList[i].mBodyRotation);
					reference2 = (GameObject)(object)((obj2 is GameObject) ? obj2 : null);
				}
				mMessageList.Add(otherPlayersInfoList[i].mNickName + " Enter Game!");
				otherPlayerObject[i].GetComponent<CRPlayerInfo>().UpdateMySelf(otherPlayersInfoList[i]);
			}
			if (otherPlayersInfoList[i].mId == "null" && (Object)(object)otherPlayerObject[i] != (Object)null)
			{
				Object.Destroy((Object)(object)otherPlayerObject[i]);
				otherPlayerObject[i] = null;
			}
		}
	}

	public void TimeOutCheckLoop()
	{
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId != "null")
			{
				otherPlayerTimeOutCount[i]++;
			}
			if (otherPlayerTimeOutCount[i] >= 300)
			{
				RemovePlayer(otherPlayersInfoList[i].mId);
				otherPlayerTimeOutCount[i] = 0;
			}
		}
	}

