	public void SynGameRoundTimeLocal()
	{
		if (mEDoorOpenOrClose == 1)
		{
			if (myPlayerInfo.mConnnectStatus != CRConnectStatus.InGame)
			{
				myPlayerInfo.mGameRoundTime = 0f;
				mGameRoundTimeStart = Time.time;
			}
			else
			{
				myPlayerInfo.mGameRoundTime = Time.time - mGameRoundTimeStart;
			}
			float num = 0f;
			for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
			{
				num = Mathf.Max(num, otherPlayersInfoList[i].mGameRoundTime);
			}
			num = Mathf.Max(num, myPlayerInfo.mGameRoundTime);
			mGameRoundTimeRest = CR_MAX_GAME_ROUND_TIME - num;
			myPlayerInfo.mGameRoundTime = num;
			if (mGameRoundTimeRest <= 0f)
			{
				mGameRoundTimeRest = 0f;
			}
		}
		else
		{
			mGameRoundTimeStart = Time.time;
		}
	}

