	public List<string> GetTmpPlayerList()
	{
		tmpPlayerList.Clear();
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId != "null")
			{
				tmpPlayerList.Add(otherPlayersInfoList[i].mId);
			}
		}
		if (myPlayerInfo.mId != string.Empty)
		{
			tmpPlayerList.Add(myPlayerInfo.mId);
		}
		return tmpPlayerList;
	}

	public void SetRobberWinOrLoseState(bool bwinorlose)
	{
		tmpPlayerList.Clear();
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId != "null" && otherPlayersInfoList[i].mTeam == CRTeamType.Robber)
			{
				tmpPlayerList.Add(otherPlayersInfoList[i].mId);
			}
		}
		if (myPlayerInfo.mId != string.Empty && myPlayerInfo.mTeam == CRTeamType.Robber)
		{
			tmpPlayerList.Add(myPlayerInfo.mId);
		}
		string[] array = new string[tmpPlayerList.Count];
		tmpPlayerList.CopyTo(array);
		if (bwinorlose)
		{
			sendMessageToPeersAdapt(array, ((Object)((Component)this).gameObject).name, "SetRobberWinOrLose", "win", reliably: false);
		}
		else
		{
			sendMessageToPeersAdapt(array, ((Object)((Component)this).gameObject).name, "SetRobberWinOrLose", "lose", reliably: false);
		}
	}

	public void SetCopWinOrLoseState(bool bwinorlose)
	{
		string text = string.Empty;
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId != "null" && otherPlayersInfoList[i].mTeam == CRTeamType.Cop)
			{
				text = otherPlayersInfoList[i].mId;
				break;
			}
		}
		if (myPlayerInfo.mId != string.Empty && myPlayerInfo.mTeam == CRTeamType.Cop)
		{
			text = myPlayerInfo.mId;
		}
		string[] peerIds = new string[1] { text };
		if (bwinorlose)
		{
			sendMessageToPeersAdapt(peerIds, ((Object)((Component)this).gameObject).name, "SetCopWinOrLose", "win", reliably: false);
		}
		else
		{
			sendMessageToPeersAdapt(peerIds, ((Object)((Component)this).gameObject).name, "SetCopWinOrLose", "lose", reliably: false);
		}
	}

	public void ServerPlayerAutoSelect()
	{
		if (!mAutoSelectServer || myPlayerInfo.mConnnectStatus != CRConnectStatus.InGame)
		{
			return;
		}
		long num = long.MaxValue;
		if (!(myPlayerInfo.mId != "null") || !(myPlayerInfo.mId != string.Empty))
		{
			return;
		}
		num = long.Parse(myPlayerInfo.mId);
		tmpPlayerList.Clear();
		for (int i = 0; i < CR_MAX_PLAYER_NUM; i++)
		{
			if (otherPlayersInfoList[i].mId != "null")
			{
				num = Math.Min(num, long.Parse(otherPlayersInfoList[i].mId));
				tmpPlayerList.Add(otherPlayersInfoList[i].mId);
				if (otherPlayersInfoList[i].mServerOrClient == CRServerOrClient.Server)
				{
					myPlayerInfo.mServerOrClient = CRServerOrClient.Client;
					myPlayerInfo.mTeam = CRTeamType.Robber;
					CRPlayer.mInstance.m_Playertype = CRPlayerType.PlayerRobber;
					CRPlayer.mInstance.InitProp();
					mEDoorOpenOrClose = 0;
					mAutoSelectServer = false;
					serverPeerId = otherPlayersInfoList[i].mId;
					return;
				}
			}
		}
		Debug.Log((object)("tmpPlayerList.Count: " + tmpPlayerList.Count));
		if (tmpPlayerList.Count < 1)
		{
			Debug.Log((object)"<3, not seclect server!");
			return;
		}
		Debug.Log((object)"yyyyyyyyyyyyyyyyy");
		if (!(myPlayerInfo.mId != string.Empty))
		{
			return;
		}
		tmpPlayerList.Add(myPlayerInfo.mId);
		if (num == long.Parse(myPlayerInfo.mId))
		{
			int index = Random.Range(0, tmpPlayerList.Count);
			string text = tmpPlayerList[index];
			if (text == myPlayerInfo.mId)
			{
				Debug.Log((object)"____________________Set Server success!");
				myPlayerInfo.mServerOrClient = CRServerOrClient.Server;
				string[] array = new string[tmpPlayerList.Count];
				tmpPlayerList.CopyTo(array);
				sendMessageToPeersAdapt(array, ((Object)((Component)this).gameObject).name, "SetServerPlayer", text, reliably: true);
				myPlayerInfo.mTeam = CRTeamType.Cop;
				CRPlayer.mInstance.m_Playertype = CRPlayerType.PlayerCop;
				CRPlayer.mInstance.InitProp();
				mEDoorOpenOrClose = 0;
			}
			else
			{
				Debug.Log((object)"____________________Set Client success!");
				myPlayerInfo.mServerOrClient = CRServerOrClient.Client;
				string[] array2 = new string[tmpPlayerList.Count];
				tmpPlayerList.CopyTo(array2);
				sendMessageToPeersAdapt(array2, ((Object)((Component)this).gameObject).name, "SetServerPlayer", text, reliably: true);
				myPlayerInfo.mTeam = CRTeamType.Robber;
				CRPlayer.mInstance.m_Playertype = CRPlayerType.PlayerRobber;
				CRPlayer.mInstance.InitProp();
				mEDoorOpenOrClose = 0;
			}
			serverPeerId = text;
			mAutoSelectServer = false;
			return;
		}
		for (int j = 0; j < CR_MAX_PLAYER_NUM; j++)
		{
			if (otherPlayersInfoList[j].mId != "null" && otherPlayersInfoList[j].mServerOrClient == CRServerOrClient.Server)
			{
				Debug.Log((object)"1111");
				mAutoSelectServer = false;
				myPlayerInfo.mServerOrClient = CRServerOrClient.Client;
				CRPlayer.mInstance.m_Playertype = CRPlayerType.PlayerRobber;
				CRPlayer.mInstance.InitProp();
				mEDoorOpenOrClose = 0;
				break;
			}
		}
		if (myPlayerInfo.mServerOrClient == CRServerOrClient.Server)
		{
			Debug.Log((object)"2222");
			myPlayerInfo.mTeam = CRTeamType.Cop;
			CRPlayer.mInstance.m_Playertype = CRPlayerType.PlayerCop;
			CRPlayer.mInstance.InitProp();
			mAutoSelectServer = false;
			mEDoorOpenOrClose = 0;
			serverPeerId = myPlayerInfo.mId;
		}
	}

	public void sendMessageToPeersAdapt(string[] peerIds, string gameObjectStr, string method, string param, bool reliably)
	{
		if (multiplayerMode == CRMultiMode.LocalWiFi)
		{
			GameKitBinding.sendMessageToPeers(peerIds, gameObjectStr, method, param, reliably);
			return;
		}
		base.photonView.RPC("TransOnlineMessageToObject", PhotonTargets.Others, peerIds, gameObjectStr, method, param, reliably);
	}

	[RPC]
	public void TransOnlineMessageToObject(string[] peerIds, string gameObjectStr, string method, string param, bool reliably)
	{
		if (peerIds[0] == myPlayerInfo.mId)
		{
			GameObject.Find(gameObjectStr).SendMessage(method, (object)param, (SendMessageOptions)1);
		}
	}

	public void StopSynAction()
	{
		((MonoBehaviour)this).StopAllCoroutines();
		keepSendingFlag = false;
	}

	private void Update()
	{
		TimeOutCheckLoop();
		if (myPlayerInfo.mConnnectStatus == CRConnectStatus.WaitForOtherPlayers)
		{
			myPlayerInfo.mConnnectStatus = CRConnectStatus.InGame;
			mLobbyPanel.SetActive(false);
		}
		ServerPlayerAutoSelect();
		SynGameRoundTimeLocal();
		UpdateOtherPlayersObject();
	}
}
