public class Stronghold : MonoBehaviour
{
	public int Id;

	public StrongholdHoldState holdState1;

	public StrongholdUseState useState1;

	public StrongholdHoldState holdState2;

	public StrongholdUseState useState2;

	private int timeLimit;

	private bool showSchedule1;

	private bool showSchedule2;

	private UISprite ScheduleSprite;

	public Material[] strongholdMaterials;

	private GameObject biaozhi;

	private GameObject qizi;

	private TeamType curType;

	private void Start()
	{
		curType = CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam;
		ScheduleSprite = GameObject.Find("schedule").GetComponent<UISprite>();
		biaozhi = ((Component)((Component)this).transform.Find("BZ/bz_1")).gameObject;
		qizi = ((Component)((Component)this).transform.Find("BZ/q/qizi")).gameObject;
		ChangeStrongholdColor();
	}

	private void OnDisable()
	{
	}

	private void Update()
	{
		if (CNRMultiplayerManager.mInstance.myPlayerInfo.mStatus == PlayerStatus.dead)
		{
			showSchedule1 = false;
			showSchedule2 = false;
			ScheduleSprite.fillAmount = 0f;
		}
		if (curType != CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam)
		{
			curType = CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam;
			showSchedule1 = false;
			showSchedule2 = false;
			ScheduleSprite.fillAmount = 0f;
		}
		if (showSchedule1)
		{
			ScheduleSprite.fillAmount += Time.deltaTime * 0.33f;
			if (ScheduleSprite.fillAmount >= 1f)
			{
				showSchedule1 = false;
				ScheduleSprite.fillAmount = 0f;
				CNRMultiplayerManager.mInstance.SendStrongholdGetMessage(1);
				timeLimit = 30;
			}
		}
		if (showSchedule2)
		{
			ScheduleSprite.fillAmount += Time.deltaTime * 0.33f;
			if (ScheduleSprite.fillAmount >= 1f)
			{
				showSchedule2 = false;
				ScheduleSprite.fillAmount = 0f;
				CNRMultiplayerManager.mInstance.SendStrongholdGetMessage(2);
				timeLimit = 30;
			}
		}
		if (timeLimit > 0)
		{
			timeLimit--;
		}
		ChangeStrongholdColor();
	}

	private void OnTriggerEnter(Collider other)
	{
		if (Id == 1)
		{
			if (timeLimit == 0 && ((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop && holdState1 == StrongholdHoldState.robberHold)
			{
				showSchedule1 = true;
			}
			if (timeLimit == 0 && ((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber && holdState1 == StrongholdHoldState.copHold)
			{
				showSchedule1 = true;
			}
		}
		else if (Id == 2)
		{
			if (timeLimit == 0 && ((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop && holdState2 == StrongholdHoldState.robberHold)
			{
				showSchedule2 = true;
			}
			if (timeLimit == 0 && ((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber && holdState2 == StrongholdHoldState.copHold)
			{
				showSchedule2 = true;
			}
		}
	}

	private void OnTriggerExit(Collider other)
	{
		if (Id == 1)
		{
			if (((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop && holdState1 == StrongholdHoldState.robberHold)
			{
				ScheduleSprite.fillAmount = 0f;
				showSchedule1 = false;
			}
			if (((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber && holdState1 == StrongholdHoldState.copHold)
			{
				ScheduleSprite.fillAmount = 0f;
				showSchedule1 = false;
			}
		}
		else if (Id == 2)
		{
			if (((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Cop && holdState2 == StrongholdHoldState.robberHold)
			{
				ScheduleSprite.fillAmount = 0f;
				showSchedule2 = false;
			}
			if (((Component)other).gameObject.tag == "Player" && CNRMultiplayerManager.mInstance.myPlayerInfo.mTeam == TeamType.Robber && holdState2 == StrongholdHoldState.copHold)
			{
				ScheduleSprite.fillAmount = 0f;
				showSchedule2 = false;
			}
		}
	}

	private void ChangeStrongholdColor()
	{
		if (Id == 1)
		{
