	private IEnumerator FireForOneSecond(float delayTime)
	{
		isAttackState = true;
		((Component)this).BroadcastMessage("FireInSingleMode", (SendMessageOptions)1);
		yield return (object)new WaitForSeconds(delayTime);
		((Component)this).BroadcastMessage("StopFireInSingleMode", (SendMessageOptions)1);
		switch (enemyType)
		{
		case EnemyType.knifeEnemy:
			tempAttackTransform.position = ((Component)this).transform.position + new Vector3(Random.Range(-2f, 2f), 0f, Random.Range(-2f, 2f));
			break;
		case EnemyType.gunEnemy:
			tempAttackTransform.position = ((Component)this).transform.position + new Vector3(Random.Range(-6f, 6f), 0f, Random.Range(-6f, 6f));
			break;
		case EnemyType.sniperEnemy:
			tempAttackTransform.position = ((Component)this).transform.position;
			break;
		case EnemyType.granadeEnemy:
			tempAttackTransform.position = ((Component)this).transform.position + new Vector3(Random.Range(-15f, 15f), 0f, Random.Range(-15f, 15f));
			break;
		}
		if (enemyAction == EnemyAction.attack && enemyType != EnemyType.sniperEnemy)
		{
			singleEnemyAI.target = tempAttackTransform;
		}
		if (enemyType != EnemyType.sniperEnemy)
		{
			singleEnemyAI.canSearch = true;
		}
		isAttackState = false;
	}

