	{
		mInstance = this;
	}

	private void OnDestroy()
	{
		mInstance = null;
	}

	private void OnDisable()
	{
		UISingleGameSceneDirector.OnYesToRespawn -= OnYesToRespawn;
		UISingleGameSceneDirector.OnNoToRespawn -= OnNoToRespawn;
	}

	private void Start()
	{
		mInstance = this;
		goDied = GameObject.Find("IsDied");
		int[] respawnPrice = new int[5] { 10, 15, 20, 25, 30 };
		RespawnPrice = respawnPrice;
		UISingleGameSceneDirector.OnYesToRespawn += OnYesToRespawn;
		UISingleGameSceneDirector.OnNoToRespawn += OnNoToRespawn;
	}

	private void Update()
	{
	}

	private void OnYesToRespawn()
	{
		if (PlayerPrefs.GetInt("GameGems", 0) > RespawnPrice[5 - PlayerPrefs.GetInt("SingleModeRespawnLimit", 5)])
		{
			PlayerPrefs.SetInt("GameGems", PlayerPrefs.GetInt("GameGems", 0) - RespawnPrice[5 - PlayerPrefs.GetInt("SingleModeRespawnLimit", 5)]);
			PlayerPrefs.SetInt("SingleModeRespawnLimit", PlayerPrefs.GetInt("SingleModeRespawnLimit", 5) - 1);
			((Component)this).gameObject.BroadcastMessage("EnableFallDamage", (SendMessageOptions)1);
			((MonoBehaviour)this).StartCoroutine(GeneratePlayerInSingleMode(0.2f));
		}
	}

	private void OnNoToRespawn()
	{
		singleModePointGet = PlayerPrefs.GetInt("SingleModeChapterOneCurrentPoint", 0);
		singleModeCoinGet = (int)((float)singleModePointGet * 0.5f);
		singleModeExpGet = (int)((float)singleModePointGet * 0.25f);
		singleModeScoreGet = (int)((float)singleModePointGet * 5f);
		PlayerPrefs.SetInt("SingleModeChapterOneHighScore", Mathf.Max(PlayerPrefs.GetInt("SingleModeChapterOneHighScore", 0), singleModeScoreGet));
	}

	private IEnumerator GeneratePlayerInSingleMode(float delay)
	{
		yield return (object)new WaitForSeconds(delay);
		((Component)this).transform.position = GameObject.Find("Spawn_1").transform.position;
		((Collider)GameObject.FindWithTag("Player").GetComponent<CharacterController>()).enabled = true;
		PlayerLogic.mInstance.bDied = false;
		PlayerLogic.mInstance.blood = 100;
		goDied.renderer.enabled = false;
	}
}
