	private void Awake()
	{
	}

	private void Start()
	{
		if (Resources.Load("unibillInventory.json") == (Object)null)
		{
			Debug.LogError((object)"You must define your purchasable inventory within the inventory editor!");
			((Component)this).gameObject.SetActive(false);
			return;
		}
		Unibiller.onBillerReady += onBillerReady;
		Unibiller.onTransactionsRestored += onTransactionsRestored;
		Unibiller.onPurchaseCancelled += onCancelled;
		Unibiller.onPurchaseFailed += onFailed;
		Unibiller.onPurchaseCompleteEvent += onPurchased;
		Unibiller.onDownloadProgressedEvent += delegate
		{
		};
		Unibiller.onDownloadFailedEvent += delegate(string arg1, string arg2)
		{
			Debug.LogError((object)arg2);
		};
		Unibiller.onDownloadCompletedEvent += delegate(string obj, DirectoryInfo dir)
		{
			FileInfo[] files = dir.GetFiles();
			foreach (FileInfo fileInfo in files)
			{
				Debug.Log((object)fileInfo.Name);
				if (fileInfo.Name.EndsWith("txt") && fileInfo.Length < 10000)
				{
					Debug.Log((object)File.ReadAllText(fileInfo.FullName));
				}
			}
		};
		Unibiller.Initialise((List<ProductDefinition>)null);
	}

	private void OnDestroy()
	{
		Unibiller.onBillerReady -= onBillerReady;
		Unibiller.onTransactionsRestored -= onTransactionsRestored;
		Unibiller.onPurchaseCancelled -= onCancelled;
		Unibiller.onPurchaseFailed -= onFailed;
		Unibiller.onPurchaseCompleteEvent -= onPurchased;
	}

